	stuff.disconnect = con.Disconnect
	pcall(stuff.disconnect, con)

	stuff.rawrbxset = function(obj, key, value)
		obj[key] = value
	end

	stuff.rawrbxget = function(obj, key)
		return obj[key]
	end


