		Name='button',
		Size=UDim2.new(0,56,0,CB_H-6),
		Position=UDim2.new(1,-60,0,3),
		BackgroundColor3=ACCENT,
		BorderSizePixel=0,
		Text='run',
		Font=Enum.Font.GothamBold,
		TextSize=12,
		TextColor3=Color3.fromRGB(255,255,255),
		Visible=false,
	},mc)
	corner(6, button)

	-- ── CMDLIST ─────────────────────────────────────────────────────────────
	local cmdlist = mk('ScreenGui',{Name='goosesploit_cmdlist',ResetOnSpawn=false,DisplayOrder=997,ZIndexBehavior=Enum.ZIndexBehavior.Sibling},root)

	local CL_W = IS_MOB and 340 or 340
	local CL_H_SCALE = IS_MOB and 0.65 or 0.60
	local cl_mc = mk('Frame',{
		Name='main_container',
		Size=UDim2.new(0,CL_W,CL_H_SCALE,0),
		Position=UDim2.new(0.5,-CL_W/2,0.5,-200),
		BackgroundColor3=BG,
		BorderSizePixel=0,
	},cmdlist)
	corner(10, cl_mc)
	stroke(ACCENT, 1.5, cl_mc)

	local hdr = mk('Frame',{Name='header',Size=UDim2.new(1,0,0,38),BackgroundColor3=PANEL,BorderSizePixel=0},cl_mc)
	corner(10, hdr)
	mk('TextLabel',{
		Size=UDim2.new(1,-80,1,0),Position=UDim2.new(0,12,0,0),
		BackgroundTransparency=1,Text='⌨  command list',
		Font=Enum.Font.GothamBold,TextSize=IS_MOB and 15 or 14,
		TextColor3=TEXT,TextXAlignment=Enum.TextXAlignment.Left,
	},hdr)

	local close_btn = mk('TextButton',{
