	-- animated loading dots
	task.spawn(function()
		local steps = {
			{t='Loading command library…',  p=0.15},
			{t='Parsing player selectors…',  p=0.30},
			{t='Setting up hook library…',   p=0.48},
			{t='Building UI components…',    p=0.65},
			{t='Applying config settings…',  p=0.80},
			{t='Wiring event listeners…',    p=0.92},
			{t='All systems go 🪿',          p=1.00},
		}

		for _, step in steps do
			task.wait(0.38)
			pcall(function()
				step_label.Text = step.t
				fact_label.Text = fun_facts[math.random(#fun_facts)]
				services.tween_service:Create(prog_fill, TweenInfo.new(0.35, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {
					Size = UDim2.new(step.p, 0, 1, 0)
				}):Play()
			end)
		end

		task.wait(0.5)
		local fade = services.tween_service:Create(loader_bg, TweenInfo.new(0.5, Enum.EasingStyle.Sine, Enum.EasingDirection.In), {
			BackgroundTransparency = 1
		})
		services.tween_service:Create(loader_card, TweenInfo.new(0.5, Enum.EasingStyle.Sine, Enum.EasingDirection.In), {
			BackgroundTransparency = 1,
			Position = loader_card.Position + UDim2.new(0, 0, 0, -20)
		}):Play()
		for _, child in loader_card:GetDescendants() do
			if child:IsA('TextLabel') or child:IsA('Frame') then
				pcall(function()
					services.tween_service:Create(child, TweenInfo.new(0.4, Enum.EasingStyle.Sine), {BackgroundTransparency=1, TextTransparency=1}):Play()
				end)
			end
		end
		fade:Play()
		fade.Completed:Connect(function()
			pcall(function() loader_gui:Destroy() end)
		end)
	end)

