		TextColor3=TEXT,
		AutoButtonColor=false,
	},toggle_gui)
	corner(12, toggle_btn)
	stroke(ACCENT, 1.5, toggle_btn)

	-- glow pulse
	task.spawn(function()
		while toggle_btn and toggle_btn.Parent do
			services.tween_service:Create(toggle_btn, TweenInfo.new(1.2, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {
				BackgroundColor3=Color3.fromRGB(28,28,38)
			}):Play()
			task.wait(1.2)
			services.tween_service:Create(toggle_btn, TweenInfo.new(1.2, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {
				BackgroundColor3=BG
			}):Play()
			task.wait(1.2)
		end
	end)

	-- make toggle button draggable
	do
		local dragging, drag_start, start_pos = false, nil, nil
		toggle_btn.InputBegan:Connect(function(inp)
			if inp.UserInputType == Enum.UserInputType.MouseButton1 or inp.UserInputType == Enum.UserInputType.Touch then
				dragging  = true
				drag_start = inp.Position
				start_pos  = toggle_btn.Position
			end
		end)
		services.user_input_service.InputChanged:Connect(function(inp)
			if dragging and (inp.UserInputType == Enum.UserInputType.MouseMovement or inp.UserInputType == Enum.UserInputType.Touch) then
				local delta = inp.Position - drag_start
				toggle_btn.Position = UDim2.new(
					start_pos.X.Scale, start_pos.X.Offset + delta.X,
					start_pos.Y.Scale, start_pos.Y.Offset + delta.Y
				)
			end
		end)
		services.user_input_service.InputEnded:Connect(function(inp)
			if inp.UserInputType == Enum.UserInputType.MouseButton1 or inp.UserInputType == Enum.UserInputType.Touch then
				dragging = false
			end
		end)
	end

