		btn.MouseEnter:Connect(function()
			services.tween_service:Create(btn, TweenInfo.new(0.12), {BackgroundColor3=ACCENT}):Play()
		end)
		btn.MouseLeave:Connect(function()
			services.tween_service:Create(btn, TweenInfo.new(0.12), {BackgroundColor3=PANEL}):Play()
		end)
		btn.Activated:Connect(function()
			-- execute using the existing cmd system; we'll fire it via the execute fn set up later
			-- store it in a shared binding table read at wire-up time
			if cmd_library and cmd_library.execute then
				local parts = {}
				for p in sc.cmd:gmatch('%S+') do table.insert(parts, p) end
				local cname = table.remove(parts, 1)
				cmd_library.execute(cname, unpack(parts))
			end
		end)
