	local function switch_tab(idx)
		active_tab = idx
		for i, btn in tab_btns do
			services.tween_service:Create(btn, TweenInfo.new(0.15), {
				BackgroundColor3 = (i==idx) and ACCENT or Color3.fromRGB(35,35,45),
				TextColor3 = (i==idx) and Color3.fromRGB(255,255,255) or MUTED,
			}):Play()
		end
		for i, page in tab_pages do
			page.Visible = (i == idx)
		end
	end

