		corner(5,tb)
		mk('UIPadding',{PaddingLeft=UDim.new(0,12),PaddingRight=UDim.new(0,12)},tb)
		tab_btns[i] = tb
		tb.Activated:Connect(function() switch_tab(i) end)
	end

	-- page container
	local pages_container = mk('Frame',{
		Size=UDim2.new(1,-16,1,-100),
		Position=UDim2.new(0,8,0,94),
		BackgroundTransparency=1,
		BorderSizePixel=0,
	},menu_frame)

	-- PAGE 1: Commands quick-run
	local page_cmds = mk('Frame',{Size=UDim2.new(1,0,1,0),BackgroundTransparency=1,BorderSizePixel=0,Visible=true},pages_container)
	tab_pages[1] = page_cmds

	local quick_input = mk('TextBox',{
		Size=UDim2.new(1,0,0,IS_MOB and 36 or 30),
		BackgroundColor3=PANEL,
		BorderSizePixel=0,
		PlaceholderText='type command and press Enter…',
		Text='',
		Font=Enum.Font.Gotham,
		TextSize=IS_MOB and 13 or 12,
		TextColor3=TEXT,
		PlaceholderColor3=MUTED,
		TextXAlignment=Enum.TextXAlignment.Left,
		ClearTextOnFocus=false,
	},page_cmds)
	corner(6,quick_input)
	mk('UIPadding',{PaddingLeft=UDim.new(0,10)},quick_input)

	local quick_list_frame = mk('ScrollingFrame',{
		Size=UDim2.new(1,0,1,-(IS_MOB and 46 or 40)),
		Position=UDim2.new(0,0,0,IS_MOB and 40 or 36),
		BackgroundTransparency=1,
		BorderSizePixel=0,
		ScrollBarThickness=3,
		ScrollBarImageColor3=ACCENT,
		CanvasSize=UDim2.new(0,0,0,0),
		AutomaticCanvasSize=Enum.AutomaticSize.Y,
	},page_cmds)
	mk('UIListLayout',{Padding=UDim.new(0,2),SortOrder=Enum.SortOrder.LayoutOrder},quick_list_frame)

	-- Populate command list in the menu (added after cmd_library is populated)
	-- We defer population until after all commands are added by storing a reference
	local _menu_cmd_list_frame = quick_list_frame
	local _menu_cmd_input      = quick_input

	-- PAGE 2: Settings
	local page_settings = mk('Frame',{Size=UDim2.new(1,0,1,0),BackgroundTransparency=1,BorderSizePixel=0,Visible=false},pages_container)
	tab_pages[2] = page_settings

	local settings_items = {
		{label='Sidebar',    key='sidebar'},
		{label='CMD History',key='cmdhistory'},
		{label='Notifications',key='notifs'},
	}

	local settings_sf = mk('ScrollingFrame',{
		Size=UDim2.new(1,0,1,0),BackgroundTransparency=1,BorderSizePixel=0,
		ScrollBarThickness=3,ScrollBarImageColor3=ACCENT,
		CanvasSize=UDim2.new(0,0,0,0),AutomaticCanvasSize=Enum.AutomaticSize.Y,
	},page_settings)
	mk('UIListLayout',{Padding=UDim.new(0,6),SortOrder=Enum.SortOrder.LayoutOrder},settings_sf)

	local toggle_states = {}
	for _, item in settings_items do
		local row = mk('Frame',{
			Size=UDim2.new(1,-4,0,IS_MOB and 38 or 32),
			BackgroundColor3=PANEL,BorderSizePixel=0,
		},settings_sf)
		corner(8,row)

		mk('TextLabel',{
			Size=UDim2.new(1,-60,1,0),Position=UDim2.new(0,12,0,0),
			BackgroundTransparency=1,Text=item.label,
			Font=Enum.Font.Gotham,TextSize=12,
			TextColor3=TEXT,TextXAlignment=Enum.TextXAlignment.Left,
		},row)

		toggle_states[item.key] = true
		local tog = mk('TextButton',{
			Size=UDim2.new(0,44,0,IS_MOB and 24 or 20),
			Position=UDim2.new(1,-52,0.5,-10),
			BackgroundColor3=ACCENT,BorderSizePixel=0,
			Text='ON',Font=Enum.Font.GothamBold,TextSize=10,
			TextColor3=Color3.fromRGB(255,255,255),AutoButtonColor=false,
		},row)
		corner(10,tog)

		tog.Activated:Connect(function()
			toggle_states[item.key] = not toggle_states[item.key]
			local on = toggle_states[item.key]
			tog.Text = on and 'ON' or 'OFF'
			services.tween_service:Create(tog, TweenInfo.new(0.15), {
				BackgroundColor3 = on and ACCENT or Color3.fromRGB(70,70,80)
			}):Play()
			if item.key == 'sidebar' then
				set_sidebar(on and sb_open or false)
				sidebar.Visible = on
			end
		end)
	end

	-- PAGE 3: Info
	local page_info = mk('Frame',{Size=UDim2.new(1,0,1,0),BackgroundTransparency=1,BorderSizePixel=0,Visible=false},pages_container)
	tab_pages[3] = page_info

	local info_lines = {
		{'Version',   'v1.0.0-gs'},
		{'Executor',  identifyexecutor()},
		{'Username',  services.players.LocalPlayer.Name},
		{'Display',   services.players.LocalPlayer.DisplayName},
		{'Game ID',   tostring(game.PlaceId)},
		{'Job ID',    game.JobId:sub(1,16)..'…'},
	}

	local info_sf = mk('ScrollingFrame',{
		Size=UDim2.new(1,0,1,0),BackgroundTransparency=1,BorderSizePixel=0,
		ScrollBarThickness=3,ScrollBarImageColor3=ACCENT,
		CanvasSize=UDim2.new(0,0,0,0),AutomaticCanvasSize=Enum.AutomaticSize.Y,
	},page_info)
	mk('UIListLayout',{Padding=UDim.new(0,4),SortOrder=Enum.SortOrder.LayoutOrder},info_sf)

	for _, pair in info_lines do
		local row = mk('Frame',{
			Size=UDim2.new(1,-4,0,IS_MOB and 34 or 28),
			BackgroundColor3=PANEL,BorderSizePixel=0,
		},info_sf)
		corner(6,row)
		mk('TextLabel',{
			Size=UDim2.new(0.42,0,1,0),Position=UDim2.new(0,10,0,0),
			BackgroundTransparency=1,Text=pair[1],
			Font=Enum.Font.GothamBold,TextSize=11,
			TextColor3=MUTED,TextXAlignment=Enum.TextXAlignment.Left,
		},row)
		mk('TextLabel',{
			Size=UDim2.new(0.56,0,1,0),Position=UDim2.new(0.44,0,0,0),
			BackgroundTransparency=1,Text=pair[2],
			Font=Enum.Font.Gotham,TextSize=11,
			TextColor3=TEXT,TextXAlignment=Enum.TextXAlignment.Left,
		},row)
	end

	-- menu open/close animation
	local function set_menu(open)
		menu_open = open
		if open then
			menu_frame.Visible = true
			services.tween_service:Create(menu_frame, TweenInfo.new(0.3, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {
				Position = UDim2.new(0.5,-MENU_W/2, 0.5,-MENU_H/2)
			}):Play()
		else
			local t = services.tween_service:Create(menu_frame, TweenInfo.new(0.22, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {
				Position = UDim2.new(0.5,-MENU_W/2, 1, 20)
			})
			t:Play()
			t.Completed:Connect(function() menu_frame.Visible = false end)
		end
	end

	menu_close.Activated:Connect(function() set_menu(false) end)

	-- ════════════════════════════════════════════════════════════════════════
	-- ── ENHANCED CMD BOX  ─────────────────────────────────────────────────
	-- ════════════════════════════════════════════════════════════════════════
	-- History tracking for up/down arrow navigation
	local cmd_history    = {}
	local history_index  = 0

	-- command suggestion label (shown below inputbox)
	local suggestion_gui = mk('ScreenGui',{
		Name='goosesploit_suggestion',
		ResetOnSpawn=false,
		DisplayOrder=998,
		ZIndexBehavior=Enum.ZIndexBehavior.Sibling,
	},root)

	local sugg_frame = mk('Frame',{
		Name='suggestion',
		Size=UDim2.new(0,300,0,0),
		Position=UDim2.new(0.5,-150,0,IS_MOB and 0 or 44),
		BackgroundColor3=BG,
		BackgroundTransparency=0.05,
		BorderSizePixel=0,
		AutomaticSize=Enum.AutomaticSize.Y,
		Visible=false,
	},suggestion_gui)
	corner(8,sugg_frame)
	stroke(ACCENT,1,sugg_frame)

	local sugg_list_layout = mk('UIListLayout',{Padding=UDim.new(0,1),SortOrder=Enum.SortOrder.LayoutOrder},sugg_frame)
	mk('UIPadding',{PaddingLeft=UDim.new(0,4),PaddingRight=UDim.new(0,4),PaddingTop=UDim.new(0,4),PaddingBottom=UDim.new(0,4)},sugg_frame)

	local function clear_suggestions()
		for _, c in sugg_frame:GetChildren() do
			if c:IsA('TextButton') then c:Destroy() end
		end
		sugg_frame.Visible = false
	end

	local function show_suggestions(query)
		clear_suggestions()
		if query == '' then return end

		local matches = {}
		for name, _ in cmd_library._command_map do
			if name:sub(1,#query) == query:lower() and #matches < 6 then
				table.insert(matches, name)
			end
		end
		table.sort(matches)

		if #matches == 0 then return end

		sugg_frame.Visible = true
		for _, match in matches do
			local sb = mk('TextButton',{
				Size=UDim2.new(1,0,0,IS_MOB and 28 or 22),
				BackgroundColor3=PANEL,
				BackgroundTransparency=0.3,
				BorderSizePixel=0,
				Text=match,
				Font=Enum.Font.Gotham,
				TextSize=IS_MOB and 13 or 12,
				TextColor3=TEXT,
				TextXAlignment=Enum.TextXAlignment.Left,
				AutoButtonColor=false,
			},sugg_frame)
			corner(4,sb)
			mk('UIPadding',{PaddingLeft=UDim.new(0,8)},sb)

			sb.MouseEnter:Connect(function()
				services.tween_service:Create(sb,TweenInfo.new(0.1),{BackgroundTransparency=0,BackgroundColor3=ACCENT}):Play()
			end)
			sb.MouseLeave:Connect(function()
				services.tween_service:Create(sb,TweenInfo.new(0.1),{BackgroundTransparency=0.3,BackgroundColor3=PANEL}):Play()
			end)
			sb.Activated:Connect(function()
				inputbox.Text = match..' '
				inputbox:CaptureFocus()
				clear_suggestions()
			end)
		end
	end

	-- wire suggestion box to inputbox
	inputbox:GetPropertyChangedSignal('Text'):Connect(function()
		local txt = inputbox.Text
		-- show run button when text is non-empty
		button.Visible = #txt > 0
		-- autocomplete first word only
		local first = txt:match('^(%S+)') or ''
		if #txt > 0 and not txt:find(' ') then
			show_suggestions(first)
		else
			clear_suggestions()
		end
	end)

	-- run on Enter
	inputbox.FocusLost:Connect(function(enterPressed)
		local txt = inputbox.Text:match('^%s*(.-)%s*$')
		clear_suggestions()
		if enterPressed and txt ~= '' then
			table.insert(cmd_history, 1, txt)
			history_index = 0
			if #cmd_history > 50 then table.remove(cmd_history) end

			for _, parsed in cmd_library.parse_command(txt) do
				cmd_library.execute(parsed.cmd, unpack(parsed.args))
			end
			inputbox.Text = ''
		end
	end)

	-- run button
	button.Activated:Connect(function()
		local txt = inputbox.Text:match('^%s*(.-)%s*$')
		if txt ~= '' then
			table.insert(cmd_history, 1, txt)
			history_index = 0
			for _, parsed in cmd_library.parse_command(txt) do
				cmd_library.execute(parsed.cmd, unpack(parsed.args))
			end
			inputbox.Text = ''
			button.Visible = false
		end
	end)

	-- quick-run from menu input
	_menu_cmd_input.FocusLost:Connect(function(enterPressed)
		local txt = _menu_cmd_input.Text:match('^%s*(.-)%s*$')
		if enterPressed and txt ~= '' then
			for _, parsed in cmd_library.parse_command(txt) do
				cmd_library.execute(parsed.cmd, unpack(parsed.args))
			end
			_menu_cmd_input.Text = ''
		end
	end)

	-- keyboard shortcuts: arrow history + menu toggle
	services.user_input_service.InputBegan:Connect(function(input, processed)
		if processed then return end

		-- ']' or RightBracket → open cmd bar focus
		if input.KeyCode == Enum.KeyCode.RightBracket then
			inputbox:CaptureFocus()
			return
		end

		-- Backquote → toggle menu
		if input.KeyCode == Enum.KeyCode.BackQuote then
			set_menu(not menu_open)
			return
		end

		-- Tab → toggle sidebar
		if input.KeyCode == Enum.KeyCode.Tab then
			set_sidebar(not sb_open)
			return
		end

		-- Arrow history navigation while inputbox focused
		if services.user_input_service:GetFocusedTextBox() == inputbox then
			if input.KeyCode == Enum.KeyCode.Up then
				if history_index < #cmd_history then
					history_index = history_index + 1
					inputbox.Text = cmd_history[history_index] or ''
				end
			elseif input.KeyCode == Enum.KeyCode.Down then
				if history_index > 1 then
					history_index = history_index - 1
					inputbox.Text = cmd_history[history_index] or ''
				elseif history_index == 1 then
					history_index = 0
					inputbox.Text = ''
				end
			end
		end
	end)

	-- Toggle button click logic
	local gs_ui_visible = true
	toggle_btn.Activated:Connect(function()
		gs_ui_visible = not gs_ui_visible
		-- toggle cmdbox and cmdlist visibility
		local cmdbox_sg = root:FindFirstChild('goosesploit_cmdbox')
		if cmdbox_sg then cmdbox_sg.Enabled = gs_ui_visible end
		local cmdlist_sg = root:FindFirstChild('goosesploit_cmdlist')
		if cmdlist_sg then cmdlist_sg.Enabled = gs_ui_visible end
		sidebar_gui.Enabled  = gs_ui_visible
		menu_gui.Enabled     = gs_ui_visible

		-- pulse feedback
		services.tween_service:Create(toggle_btn, TweenInfo.new(0.1), {
			BackgroundColor3 = gs_ui_visible and ACCENT or RED
		}):Play()
		task.delay(0.25, function()
			services.tween_service:Create(toggle_btn, TweenInfo.new(0.2), {BackgroundColor3=BG}):Play()
		end)
	end)

	-- Deferred: populate menu command list once cmd_library is ready
	task.defer(function()
		task.wait(4)  -- wait for all commands to be registered (they register after load_ui returns)
		local all_cmds = cmd_library._commands or {}
		for _, cmd in all_cmds do
			local nm = cmd.names[1]
			local lb = mk('TextButton',{
				Size=UDim2.new(1,-4,0,IS_MOB and 28 or 22),
				BackgroundColor3=PANEL,BackgroundTransparency=0.3,
				BorderSizePixel=0,
				Text=nm,
				Font=Enum.Font.Gotham,TextSize=IS_MOB and 12 or 11,
				TextColor3=TEXT,TextXAlignment=Enum.TextXAlignment.Left,
				AutoButtonColor=false,
			},_menu_cmd_list_frame)
			corner(4,lb)
			mk('UIPadding',{PaddingLeft=UDim.new(0,8)},lb)

			lb.MouseEnter:Connect(function()
				services.tween_service:Create(lb,TweenInfo.new(0.1),{BackgroundTransparency=0,BackgroundColor3=ACCENT}):Play()
			end)
			lb.MouseLeave:Connect(function()
				services.tween_service:Create(lb,TweenInfo.new(0.1),{BackgroundTransparency=0.3,BackgroundColor3=PANEL}):Play()
			end)
			lb.Activated:Connect(function()
				_menu_cmd_input.Text = nm..' '
				_menu_cmd_input:CaptureFocus()
			end)
		end
	end)

	return root
end

stuff.ui = load_ui()
if not stuff.ui then
	return error('[Goosesploit] ui failed to load')
end

config.load()

local hook_lib = {
	active_hooks = {},
	presets = {}
}

function hook_lib.create_hook(name, hooks)
	if hook_lib.active_hooks[name] then
		hook_lib.destroy_hook(name)
	end

	local hook_data = {
		hooks = {},
		function_hooks = {},
		enabled = true
	}

	if hooks.namecall and hookmetamethod then
		pcall(function()
			hook_data.hooks.old_namecall = hookmetamethod(game, '__namecall', newcclosure(function(self, ...)
				if hook_data.enabled and not checkcaller() then
					local result = hooks.namecall(self, ...)
					if result ~= nil then
						return result
					end
				end
				return hook_data.hooks.old_namecall(self, ...)
			end))
		end)
	end

	if hooks.index and hookmetamethod then
		pcall(function()
			hook_data.hooks.old_index = hookmetamethod(game, '__index', newcclosure(function(self, key)
				if hook_data.enabled and not checkcaller() then
					local result = hooks.index(self, key)
					if result ~= nil then
						return result
					end
				end
				return hook_data.hooks.old_index(self, key)
			end))
		end)
	end

	if hooks.newindex and hookmetamethod then
		pcall(function()
			hook_data.hooks.old_newindex = hookmetamethod(game, '__newindex', newcclosure(function(self, key, value)
				if hook_data.enabled and not checkcaller() then
					local result = hooks.newindex(self, key, value)
					if result == false then
						return
					end
				end
				return hook_data.hooks.old_newindex(self, key, value)
			end))
		end)
	end

	if hooks.functions and hookfunction then
		for original_func, handler in hooks.functions do
			pcall(function()
				local old_func
				old_func = hookfunction(original_func, newcclosure(function(...)
					if hook_data.enabled and not checkcaller() then
						local result = handler(old_func, ...)
						if result ~= nil then
							return result
						end
					end
					return old_func(...)
				end))
				hook_data.function_hooks[original_func] = old_func
			end)
		end
	end

	hook_lib.active_hooks[name] = hook_data
	return hook_data
end

function hook_lib.destroy_hook(name)
	local hook_data = hook_lib.active_hooks[name]
	if hook_data then
		hook_data.enabled = false

		if hookfunction then
			for original_func, old_func in hook_data.function_hooks do
				pcall(function()
					hookfunction(original_func, old_func)
				end)
			end
		end

		hook_lib.active_hooks[name] = nil
	end
end

function hook_lib.toggle_hook(name, enabled)
	local hook_data = hook_lib.active_hooks[name]
	if hook_data then
		hook_data.enabled = enabled
	end
end

hook_lib.presets.antikick = function(player)
	local functions = {}

	pcall(function()
		local teleport = services.teleport_service.Teleport
		if teleport then
			functions[teleport] = function(old, ...)
				notify('antikick', 'blocked direct teleport call', 3)
				return nil
			end
		end
	end)

	pcall(function()
		local teleport_async = services.teleport_service.TeleportAsync
		if teleport_async then
			functions[teleport_async] = function(old, ...)
				notify('antikick', 'blocked direct teleport async call', 3)
				return nil
			end
		end
	end)

	pcall(function()
		local teleport_place = services.teleport_service.TeleportToPlaceInstance
		if teleport_place then
			functions[teleport_place] = function(old, ...)
				notify('antikick', 'blocked direct teleport to place call', 3)
				return nil
			end
		end
	end)

	return {
		namecall = function(self, ...)
			local method = getnamecallmethod()

			if self == player and (method == 'Kick' or method == 'Destroy' or method == 'Remove') then
				notify('antikick', ("blocked " .. tostring(method) .. " attempt"), 3)
				return nil
			end

			if self == services.teleport_service and (method == 'Teleport' or method == 'TeleportAsync' or method == 'TeleportToPlaceInstance') then
				notify('antikick', ("blocked " .. tostring(method) .. " attempt"), 3)
				return nil
			end
		end,

		functions = functions
	}
end

hook_lib.presets.freegamepass = function()
	local functions = {}

	pcall(function()
		local user_owns = services.marketplace_service.UserOwnsGamePassAsync
		if user_owns then
			functions[user_owns] = function(old, ...)
				return true
			end
		end
	end)

	pcall(function()
		local player_owns = services.marketplace_service.PlayerOwnsAsset
		if player_owns then
			functions[player_owns] = function(old, ...)
				return true
			end
		end
	end)

	return {
		namecall = function(self, ...)
			local method = getnamecallmethod()

			if self == services.marketplace_service then
				if method == 'UserOwnsGamePassAsync' or method == 'PlayerOwnsAsset' or method == 'PlayerOwnsBundle' then
					return true
				elseif method == 'GetProductInfo' then
					local success, result = pcall(function(...)
						return self[method](self, ...)
					end, ...)

					if success and result then
						result.IsOwned = true
						result.IsForSale = true
						return result
					end
				end
			end

			if typeof(self) == 'Instance' and self:IsA('Player') then
				if method == 'IsInGroup' then
					return true
				elseif method == 'GetRankInGroup' then
					return 255
				elseif method == 'GetRoleInGroup' then
					return 'Owner'
				end
			end
		end,

		index = function(self, key)
			if typeof(self) == 'Instance' and self:IsA('Player') then
				if key == 'MembershipType' then
					return Enum.MembershipType.Premium
				end
			end
		end,

		functions = functions
	}
end

hook_lib.presets.property_spoof = function(instance, properties)
	local spoofed_values = {}

	for prop, value in properties do
		spoofed_values[prop] = value
	end

	local functions = {}

	pcall(function()
		local item_changed = game.ItemChanged
		if item_changed and item_changed.Connect then
			functions[item_changed.Connect] = function(old, self, callback)
				return old(self, function(item, prop)
					if item == instance and spoofed_values[prop] ~= nil then
						return
					end
					return callback(item, prop)
				end)
			end
		end
	end)

	pcall(function()
		local changed = instance.Changed
		if changed and changed.Connect then
			functions[changed.Connect] = function(old, self, callback)
				if self == changed then
					return old(self, function(prop)
						if spoofed_values[prop] ~= nil then
							return
						end
						return callback(prop)
					end)
				end
				return old(self, callback)
			end
		end
	end)

	pcall(function()
		local changed = instance.Changed
		if changed and changed.Wait then
			functions[changed.Wait] = function(old, self)
				if self == changed then
					while true do
						local prop = old(self)
						if spoofed_values[prop] == nil then
							return prop
						end
					end
				end
				return old(self)
			end
		end
	end)

	return {
		index = function(self, key)
			if self == instance and spoofed_values[key] ~= nil then
				return spoofed_values[key]
			end
		end,

		namecall = function(self, ...)
			local method = getnamecallmethod()

			if self == instance then
				if method == 'GetPropertyChangedSignal' then
					local args = {...}
					if spoofed_values[args[1]] ~= nil then
						local signal = Instance.new('BindableEvent')
						return signal.Event
					end
				end
			end

			if typeof(self) == 'RBXScriptSignal' then
				if self == instance.Changed then
					if method == 'Connect' then
						local args = {...}
						local callback = args[1]
						if callback then
							return self:Connect(function(prop)
								if spoofed_values[prop] ~= nil then
									return
								end
								return callback(prop)
							end)
						end
					elseif method == 'Wait' then
						while true do
							local prop = instance.Changed:Wait()
							if spoofed_values[prop] == nil then
								return prop
							end
						end
					end
				end
			end
		end,

		newindex = function(self, key, value)
			if self == instance and spoofed_values[key] ~= nil then
				spoofed_values[key] = value
				return false
			end
		end,

		functions = functions
	}
end

