cmd_library.add({'droptools', 'dropall'}, 'drops all droppable tools', {}, function(vstorage)
	local backpack = stuff.owner:FindFirstChildOfClass('Backpack')
	if not stuff.owner_char then
		return notify('droptools', 'character not found', 2)
	end

	local tool_queue = {}

	local function collect_tools(container)
		if not container then return end
		for _, item in container:GetChildren() do
			if item:IsA('Tool') and item.CanBeDropped then
				table.insert(tool_queue, item)
			end
		end
	end

	collect_tools(stuff.owner_char)
	collect_tools(backpack)

	if #tool_queue == 0 then
		notify('droptools', 'no droppable tools found', 3)
		return
	end

	local dropped_count = 0
	for _, tool in tool_queue do
		if tool and tool.Parent then
			if tool.Parent == backpack then
				tool.Parent = stuff.owner_char
				task.wait()
			end
			if tool.Parent == stuff.owner_char then
				tool.Parent = workspace
				dropped_count += 1
				task.wait()
			end
		end
	end

	notify('droptools', ("dropped " .. tostring(dropped_count) .. " tool(s)"), 1)
end)

cmd_library.add({'notools', 'removetools', 'deletetools'}, 'removes all your tools', {}, function(vstorage)
	local count = 0
	local backpack = stuff.owner:FindFirstChildOfClass('Backpack')

	if stuff.owner_char then
		for _, item in stuff.owner_char:GetDescendants() do
			if item:IsA('Tool') then
				stuff.destroy(item)
				count += 1
			end
		end
	end

	if backpack then
		for _, item in backpack:GetDescendants() do
			if item:IsA('Tool') then
				stuff.destroy(item)
				count += 1
			end
		end
	end

	notify('notools', ("removed " .. tostring(count) .. " tool(s)"), 1)
end)

cmd_library.add({'usetools', 'activatetools'}, 'equips all tools, activates them, then restores', {}, function(vstorage)
	local backpack = stuff.owner:FindFirstChildOfClass('Backpack')
	if not backpack or not stuff.owner_char then
		notify('usetools', 'missing backpack or character', 2)
		return
	end

	local previously_equipped = {}
	for _, item in stuff.owner_char:GetChildren() do
		if item:IsA('Tool') or item:IsA('HopperBin') or item:IsA('BackpackItem') then
			table.insert(previously_equipped, item)
		end
	end

	for _, item in backpack:GetChildren() do
		if item:IsA('Tool') or item:IsA('HopperBin') or item:IsA('BackpackItem') and not table.find(previously_equipped, item) then
			item.Parent = stuff.owner_char
		end
	end

	for _, item in stuff.owner_char:GetChildren() do
		if item:IsA('Tool') or item:IsA('HopperBin') or item:IsA('BackpackItem') then
			task.spawn(function()
				item:Activate()
			end)
		end
	end

	task.wait(1)

	for _, item in stuff.owner_char:GetChildren() do
		if item:IsA('Tool') or item:IsA('HopperBin') or item:IsA('BackpackItem') and not table.find(previously_equipped, item) then
			item.Parent = backpack
		end
	end

	for _, item in previously_equipped do
		item.Parent = stuff.owner_char
	end

	notify('usetools', 'activated all tools', 1)
end)

cmd_library.add({'loadstring', 'run', 'script', 'execute', 'ls'}, 'run given luau code', {
	{'...', 'string'}
}, function(vars, ...)
	local code = table.concat({...}, ' ')

	vars.script_folder = vars.script_folder or Instance.new('Folder', services.core_gui)
	vars.script_folder.Name = 'goosesploit_scripts'

	local script = Instance.new('LocalScript')
	script.Enabled = false
	script.Source = code
	script.Name = (tostring(#vars.script_folder:GetChildren() + 1) .. ".script")
	script.Parent = vars.script_folder

	local success, ls = pcall(loadstring, code)
	if not success then
		return notify('loadstring', ("error when calling loadstring: " .. tostring(ls)), 2)
	end

	if not ls then
		return notify('loadstring', 'loadstring did not return anything', 2)
	end

	local ls_env = getfenv(ls)
	ls_env.script = script

	local success2, ls_ret = pcall(ls)
	if not success2 then
		return notify('loadstring', ("error when executing script: " .. tostring(ls_ret)), 2)
	end

	if ls_ret then
		notify('loadstring', ("loadstring returned " .. tostring(ls_ret)), 1)
	end
end)

cmd_library.add({'pluginload', 'pload'}, 'load a plugin from url', {
	{'url', 'string'}
}, function(vars, url)
	local success, content = pcall(function()
		return game:HttpGet(url, true)
	end)

	if not success then
		notify('plugin', ("failed to fetch plugin from url: " .. tostring(content)), 2)
		return
	end

	local success2, plugin_module = pcall(loadstring, content)
	if not success2 then
		notify('plugin', ("failed to load plugin script: " .. tostring(plugin_module)), 2)
		local saved_plugins = config.get('saved_plugins') or {}
		for name, plugin_url in saved_plugins do
			if plugin_url == url then
				saved_plugins[name] = nil
				config.set('saved_plugins', saved_plugins)
				notify('plugin', "removed saved plugin '" .. tostring(name) .. "' because it's data could not be loaded", 3)
				break
			end
		end

		warn(plugin_module)
		return
	end

	local success3, plugin_data = pcall(plugin_module)
	if not success3 then
		notify('plugin', ("plugin execution error: " .. tostring(plugin_data)), 2)
		warn(plugin_data)
		return
	end

	if type(plugin_data) ~= 'table' then
		notify('plugin', 'plugin must return a table', 2)
		return
	end

	if not plugin_data.name then
		notify('plugin', 'plugin missing name field', 2)
		return
	end

	if not plugin_data.init or type(plugin_data.init) ~= 'function' then
		notify('plugin', 'plugin missing init function', 2)
		return
	end

	local plugin, err = cmd_library.register_plugin(plugin_data.name, {
		version = plugin_data.version,
		author = plugin_data.author,
		description = plugin_data.description,
		data = plugin_data
	})

	if not plugin then
		notify('plugin', ("failed to register plugin: " .. tostring(err)), 2)
		return
	end

	local success4, err2 = pcall(plugin_data.init, {
		add_command = function(names, description, args, fn)
			return cmd_library.add_plugin_command(plugin_data.name, names, description, args, fn)
		end,
		notify = notify,
		get_maid = function() return maid end,
		get_stuff = function() return stuff end,
		get_cmd_library = function() return cmd_library end,
		get_hook_library = function() return hook_lib end,
		config = config
	})

	if not success4 then
		cmd_library.remove_plugin(plugin_data.name)
		notify('plugin', ("plugin initialization failed: " .. tostring(err2)), 2)
		return
	end

	notify('plugin', ("plugin '" .. tostring(plugin_data.name) .. "' loaded successfully"), 1)

	local saved_plugins = config.get('saved_plugins') or {}
	saved_plugins[plugin_data.name] = url
	config.set('saved_plugins', saved_plugins)
end)

cmd_library.add({'pluginunload', 'punload'}, 'unload a plugin', {
	{'plugin_name', 'string'}
}, function(vars, plugin_name)
	local success, err = cmd_library.remove_plugin(plugin_name)
	if success then
		notify('plugin', ("plugin '" .. tostring(plugin_name) .. "' unloaded"), 1)

		local saved_plugins = config.get('saved_plugins') or {}
		saved_plugins[plugin_name] = nil
		config.set('saved_plugins', saved_plugins)
	else
		notify('plugin', ("failed to unload plugin: " .. tostring(err)), 2)
	end
end)

cmd_library.add({'pluginreload', 'preload'}, 'reload a plugin', {
	{'plugin_name', 'string'},
	{'refetch', 'boolean'}
}, function(vars, plugin_name, refetch)
	if not plugin_name then
		return notify('plugin', ("plugin '" .. tostring(plugin_name) .. "' not found"), 2)
	end

	local plugin = cmd_library._plugins[plugin_name:lower()]
	if not plugin then
		notify('plugin', ("plugin '" .. tostring(plugin_name) .. "' not found"), 2)
		return
	end

	local saved_plugins = config.get('saved_plugins') or {}
	local url = saved_plugins[plugin_name]

	if not url then
		notify('plugin', 'no url saved for plugin \'' .. tostring(plugin_name) .. '\'. use pluginload instead.', 3)
		return
	end

	if refetch then
		cmd_library.remove_plugin(plugin_name)
		cmd_library.execute('pluginload', url)
		notify('plugin', ("plugin '" .. tostring(plugin_name) .. "' refetched and reloaded"), 1)
	else
		local plugin_data = plugin.data
		if not plugin_data or not plugin_data.init then
			notify('plugin', ("plugin '" .. tostring(plugin_name) .. "' has no cached data, use refetch"), 2)
			return
		end

		for i = #cmd_library._commands, 1, -1 do
			local cmd = cmd_library._commands[i]
			if cmd.plugin and cmd.plugin:lower() == plugin_name:lower() then
				for _, name in cmd.names do
					cmd_library._command_map[name:lower()] = nil
				end
				table.remove(cmd_library._commands, i)
			end
		end

		plugin.commands = {}

		local success, err = pcall(plugin_data.init, {
			add_command = function(names, description, args, fn)
				return cmd_library.add_plugin_command(plugin_name, names, description, args, fn)
			end,
			notify = notify,
			get_maid = function() return maid end,
			get_stuff = function() return stuff end,
			get_cmd_library = function() return cmd_library end,
			get_hook_library = function() return hook_lib end,
			config = config
		})

		if not success then
			cmd_library.remove_plugin(plugin_name)
			notify('plugin', ("plugin reinitialization failed: " .. tostring(err)), 2)
			return
		end

		notify('plugin', ("plugin '" .. tostring(plugin_name) .. "' reloaded"), 1)
	end
end)

