cmd_library.add({'logmodules', 'getmodules', 'modules'}, 'logs all loaded modules and their information', {}, function(vstorage)
	notify('logmodules', 'scanning for loaded modules...', 1)

	if not getloadedmodules then
		return notify('logmodules', 'getloadedmodules not supported by your executor', 2)
	end

	local marketplace = game:GetService('MarketplaceService')
	local modules = getloadedmodules()

	if not modules or #modules == 0 then
		return notify('logmodules', 'no modules found', 2)
	end

	notify('logmodules', ("found " .. tostring(#modules) .. " loaded modules, analyzing..."), 1)

	local output = ("=== found " .. tostring(#modules) .. " loaded modules ===\n")
	output ..= ("game: " .. tostring(game.Name) .. " (placeid: " .. tostring(game.PlaceId) .. ")\n\n")

	local asset_ids = {}
	local module_count = 0

	for i, module in ipairs(modules) do
		module_count += 1
		local module_name = stuff.rawrbxget(module, 'Name')
		local module_path = module:GetFullName()

		local entry = (tostring(i) .. ". '" .. tostring(module_name) .. "'\n")
		entry ..= ("   path: " .. tostring(module_path) .. "\n")

		local source_ids = {}
		pcall(function()
			if decompile then
				local source = decompile(module) or ''

				for id in source:gmatch('rbxassetid://(%d+)') do
					if not table.find(source_ids, id) then
						table.insert(source_ids, id)
					end
				end

				for id in source:gmatch('require%((%d+)%)') do
					if not table.find(source_ids, id) then
						table.insert(source_ids, id)
					end
				end
			end
		end)

		if #source_ids > 0 then
			entry ..= ("   referenced assets: " .. tostring(table.concat(source_ids, ', ')) .. "\n")
			for _, id in source_ids do
				if not table.find(asset_ids, id) then
					table.insert(asset_ids, id)
				end
			end
		end

		output ..= entry .. '\n'
	end

	if #asset_ids > 0 then
		output ..= ("\n=== asset information (" .. tostring(#asset_ids) .. " unique assets) ===\n\n")
		notify('logmodules', 'fetching info for ' .. tostring(#asset_ids) .. ' assets...', 1)

		for idx, id in ipairs(asset_ids) do
			local success, asset_info = pcall(function()
				return marketplace:GetProductInfo(tonumber(id), Enum.InfoType.Asset)
			end)

			if success and asset_info then
				local creator_name = 'unknown'
				if asset_info.Creator then
					if asset_info.Creator.Name then
						creator_name = asset_info.Creator.Name
					elseif asset_info.Creator.CreatorTargetId then
						pcall(function()
							local creator_info = marketplace:GetProductInfo(asset_info.Creator.CreatorTargetId, Enum.InfoType.Asset)
							if creator_info and creator_info.Creator then
								creator_name = creator_info.Creator.Name or 'unknown'
							end
						end)
					end
				end

				local asset_entry = (tostring(idx) .. ". asset " .. tostring(id) .. "\n")
				asset_entry ..= ("   name: '" .. tostring(asset_info.Name) .. "'\n")
				asset_entry ..= ("   creator: " .. tostring(creator_name) .. "\n")
				asset_entry ..= ("   type: " .. tostring(asset_info.AssetTypeId or 'unknown') .. "\n")
				asset_entry ..= ("   description: " .. tostring(asset_info.Description and asset_info.Description:sub(1, 100) or 'none') .. "...\n\n")

				output ..= asset_entry
				print(asset_entry)
			else
				local fail_entry = (tostring(idx) .. ". asset " .. tostring(id) .. ": failed to fetch info\n\n")
				output ..= fail_entry
				print(fail_entry)
			end

			if idx % 5 == 0 then
				task.wait(1)
			end
		end
	end

	output ..= "\n=== summary ===\n"
	output ..= ("total modules: " .. tostring(module_count) .. "\n")
	output ..= ("referenced assets: " .. tostring(#asset_ids) .. "\n")

	if setclipboard then
		setclipboard(output)
		notify('logmodules', 'copied info for ' .. tostring(module_count) .. ' modules and ' .. tostring(#asset_ids) .. ' assets to clipboard', 1)
	else
		notify('logmodules', ("logged " .. tostring(module_count) .. " modules to console (setclipboard not available)"), 3)
	end

	print('\n' .. output)
end)

