cmd_library.add({'chatlogs', 'cl'}, 'toggles the chatlogs', {}, function(vstorage)
	local existing_log = vstorage.existing_log

	if existing_log then
		services.text_chat_service.OnIncomingMessage = stuff.empty_function
		pcall(stuff.destroy, existing_log)
		vstorage.existing_log = nil
		vstorage.enabled = false
		notify('chatlogs', 'chatlogs disabled', 1)
		return
	end

	vstorage.enabled = true
	local chatlog = stuff.ui.goosesploit_chatlogs:Clone()
	vstorage.existing_log = chatlog
	pcall(protect_gui, chatlog)
	local ui_chatlog_template = chatlog.main_container.chatlogs.log
	ui_chatlog_template.Parent = nil

	services.text_chat_service.OnIncomingMessage = function(message)
		if message.Status == Enum.TextChatMessageStatus.Success then
			local frame = chatlog:FindFirstChildOfClass('Frame')
			local sframe = frame:FindFirstChildOfClass('ScrollingFrame')
			local label = ui_chatlog_template:Clone()

			stuff.rawrbxset(label, 'Name', tostring(message.Text))
			stuff.rawrbxset(label, 'Visible', true)
			stuff.rawrbxset(label, 'Text', tostring(message.TextSource) .. ': ' .. tostring(message.Text))
			stuff.rawrbxset(label, 'Parent', sframe)
			if #chatlog.main_container.chatlogs:GetChildren() > 3 then
				task.wait()
				stuff.rawrbxset(sframe, 'CanvasPosition', Vector2.new(0, sframe.AbsoluteCanvasSize.Y))
			end
		end
	end

	notify('chatlogs', 'chatlogs enabled', 1)
end)

cmd_library.add({'clearchatlogs', 'clearcl', 'ccl'}, 'clears the chatlogs', {}, function(vstorage)
	local existing_log = cmd_library.get_variable_storage('chatlogs').existing_log

	if existing_log then
		for _, log in existing_log.main_container.chatlogs:GetChildren() do
			if log:IsA('TextLabel') then
				pcall(stuff.destroy, log)
			end
		end
		return notify('chatlogs', 'chatlogs cleared', 1)
	end

	notify('chatlogs', 'chatlogs not enabled', 2)
end)


local gs_cmds_gui = nil -- holds the ScreenGui so it persists

cmd_library.add({'help', 'cmds', 'commands'}, 'opens the goosesploit command browser', {
	{'search', 'string', 'optional'}
}, function(vstorage, initial_search)

	if gs_cmds_gui and gs_cmds_gui.Parent then
		gs_cmds_gui.Enabled = not gs_cmds_gui.Enabled
		return
	end


	local C = {
		bg      = Color3.fromRGB(18, 18, 22),
		panel   = Color3.fromRGB(26, 26, 32),
		header  = Color3.fromRGB(34, 34, 42),
		accent  = Color3.fromRGB(88, 101, 242),
		accent2 = Color3.fromRGB(60, 200, 140),
		text    = Color3.fromRGB(230, 230, 240),
		muted   = Color3.fromRGB(130, 130, 150),
		row_a   = Color3.fromRGB(28, 28, 36),
		row_b   = Color3.fromRGB(32, 32, 40),
		iy_row  = Color3.fromRGB(28, 36, 28),
		border  = Color3.fromRGB(50, 50, 65),
		tag_iy  = Color3.fromRGB(60, 180, 100),
		tag_gs  = Color3.fromRGB(88, 101, 242),
		close   = Color3.fromRGB(200, 60, 60),
	}


	local function mk(cls, props)
		local o = Instance.new(cls)
		for k, v in pairs(props) do o[k] = v end
		return o
	end

	local function corner(parent, radius)
		local c = Instance.new('UICorner')
		c.CornerRadius = UDim.new(0, radius or 6)
		c.Parent = parent
	end

	local function stroke(parent, color, thickness)
		local s = Instance.new('UIStroke')
		s.Color = color or C.border
		s.Thickness = thickness or 1
		s.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
		s.Parent = parent
	end

	local function padding(parent, px)
		local p = Instance.new('UIPadding')
		p.PaddingLeft   = UDim.new(0, px)
		p.PaddingRight  = UDim.new(0, px)
		p.PaddingTop    = UDim.new(0, px)
		p.PaddingBottom = UDim.new(0, px)
		p.Parent = parent
	end


	local function format_command(cmd_info)
		local names_str = table.concat(cmd_info.names, ', ')
		local args_str  = ''
		if cmd_info.args and #cmd_info.args > 0 then
			local parts = {}
			for _, a in ipairs(cmd_info.args) do
				if a[3] ~= 'hidden' then
					if a['...'] then
						table.insert(parts, '...:' .. tostring(a['...']))
					else
						table.insert(parts, tostring(a[1]) .. ': ' .. tostring(a[2]))
					end
				end
			end
			if #parts > 0 then
				args_str = ' [' .. table.concat(parts, ', ') .. ']'
			end
		end
		return names_str .. args_str
	end


	local vp     = workspace.CurrentCamera.ViewportSize
	local IS_MOB = stuff.is_mobile
	local W      = IS_MOB and math.min(vp.X - 20, 420) or 520
	local H      = IS_MOB and math.min(vp.Y - 60, 560) or 560


	local gui = mk('ScreenGui', {
		Name            = 'GoosesploitCMDsBrowser',
		ResetOnSpawn    = false,
		DisplayOrder    = 999,
		ZIndexBehavior  = Enum.ZIndexBehavior.Sibling,
	})
	pcall(function() gui.Parent = services.core_gui end)
	if not gui.Parent then gui.Parent = services.players.LocalPlayer.PlayerGui end
	gs_cmds_gui = gui


	local backdrop = mk('Frame', {
		Name              = 'backdrop',
		Size              = UDim2.new(0, W, 0, H),
		Position          = UDim2.new(0.5, -W/2, 0.5, -H/2),
		BackgroundColor3  = C.bg,
		BorderSizePixel   = 0,
		Parent            = gui,
	})
	corner(backdrop, 10)
	stroke(backdrop, C.border, 1)


	local shadow = mk('Frame', {
		Name             = 'shadow',
		Size             = UDim2.new(1, 20, 1, 20),
		Position         = UDim2.new(0, -10, 0, 8),
		BackgroundColor3 = Color3.fromRGB(0,0,0),
		BackgroundTransparency = 0.55,
		BorderSizePixel  = 0,
		ZIndex           = 0,
		Parent           = backdrop,
	})
	corner(shadow, 14)


	local header = mk('Frame', {
		Name             = 'header',
		Size             = UDim2.new(1, 0, 0, IS_MOB and 48 or 40),
		BackgroundColor3 = C.header,
		BorderSizePixel  = 0,
		Parent           = backdrop,
	})
	corner(header, 10)

	mk('Frame', {
		Size             = UDim2.new(1, 0, 0.5, 0),
		Position         = UDim2.new(0, 0, 0.5, 0),
		BackgroundColor3 = C.header,
		BorderSizePixel  = 0,
		Parent           = header,
	})


	mk('TextLabel', {
		Size             = UDim2.new(1, -80, 1, 0),
		Position         = UDim2.new(0, 12, 0, 0),
		BackgroundTransparency = 1,
		Text             = ' Goosesploit  —  Command Browser',
		Font             = Enum.Font.GothamBold,
		TextSize         = IS_MOB and 15 or 14,
		TextColor3       = C.text,
		TextXAlignment   = Enum.TextXAlignment.Left,
		Parent           = header,
	})


	local count_badge = mk('TextLabel', {
		Name             = 'count',
		Size             = UDim2.new(0, 60, 0, 20),
		Position         = UDim2.new(1, -130, 0.5, -10),
		BackgroundColor3 = C.accent,
		BackgroundTransparency = 0.3,
		Text             = '...',
		Font             = Enum.Font.GothamBold,
		TextSize         = 11,
		TextColor3       = C.text,
		Parent           = header,
	})
	corner(count_badge, 10)


	local close_btn = mk('TextButton', {
		Size             = UDim2.new(0, IS_MOB and 42 or 32, 0, IS_MOB and 42 or 32),
		Position         = UDim2.new(1, IS_MOB and -48 or -38, 0.5, IS_MOB and -21 or -16),
		BackgroundColor3 = C.close,
		Text             = '',
		Font             = Enum.Font.GothamBold,
		TextSize         = IS_MOB and 16 or 13,
		TextColor3       = C.text,
		BorderSizePixel  = 0,
		Parent           = header,
	})
	corner(close_btn, 6)


	local TAB_H = IS_MOB and 36 or 30
	local tab_bar = mk('Frame', {
		Name             = 'tab_bar',
		Size             = UDim2.new(1, 0, 0, TAB_H),
		Position         = UDim2.new(0, 0, 0, IS_MOB and 48 or 40),
		BackgroundColor3 = C.panel,
		BorderSizePixel  = 0,
		Parent           = backdrop,
	})
	local tab_layout = mk('UIListLayout', {
		FillDirection    = Enum.FillDirection.Horizontal,
		Padding          = UDim.new(0, 4),
		VerticalAlignment= Enum.VerticalAlignment.Center,
		Parent           = tab_bar,
	})
	padding(tab_bar, 6)

	local TABS = {
		{label = ' All',      filter = 'all'},
		{label = ' OPAdmin',  filter = 'gs'},
		{label = ' IY Legacy', filter = 'iy'},
	}
	local active_tab = 'all'
	local tab_btns   = {}

	for _, t in ipairs(TABS) do
		local btn = mk('TextButton', {
			Size             = UDim2.new(0, 0, 1, -6),
			AutoButtonColor  = false,
			BackgroundColor3 = active_tab == t.filter and C.accent or C.header,
			Text             = t.label,
			Font             = Enum.Font.GothamBold,
			TextSize         = IS_MOB and 13 or 11,
			TextColor3       = C.text,
			BorderSizePixel  = 0,
			AutomaticSize    = Enum.AutomaticSize.X,
			Parent           = tab_bar,
		})
		corner(btn, 5)
		padding(btn, 8)
		tab_btns[t.filter] = btn
	end


	local SRCH_H = IS_MOB and 40 or 32
	local srch_frame = mk('Frame', {
		Name             = 'srch_frame',
		Size             = UDim2.new(1, 0, 0, SRCH_H + 8),
		Position         = UDim2.new(0, 0, 0, (IS_MOB and 48 or 40) + TAB_H),
		BackgroundColor3 = C.panel,
		BorderSizePixel  = 0,
		Parent           = backdrop,
	})

	local srch_bg = mk('Frame', {
		Size             = UDim2.new(1, -16, 0, SRCH_H),
		Position         = UDim2.new(0, 8, 0, 4),
		BackgroundColor3 = C.header,
		BorderSizePixel  = 0,
		Parent           = srch_frame,
	})
	corner(srch_bg, 6)
	stroke(srch_bg, C.border, 1)

	mk('TextLabel', {
		Size             = UDim2.new(0, 28, 1, 0),
		BackgroundTransparency = 1,
		Text             = '',
		TextSize         = 14,
		Font             = Enum.Font.Gotham,
		TextColor3       = C.muted,
		Parent           = srch_bg,
	})

	local search_box = mk('TextBox', {
		Size             = UDim2.new(1, -32, 1, 0),
		Position         = UDim2.new(0, 28, 0, 0),
		BackgroundTransparency = 1,
		PlaceholderText  = 'search commands...',
		PlaceholderColor3= C.muted,
		Text             = initial_search or '',
		Font             = Enum.Font.Gotham,
		TextSize         = IS_MOB and 14 or 13,
		TextColor3       = C.text,
		ClearTextOnFocus = false,
		Parent           = srch_bg,
	})


	local TOP_OFFSET = (IS_MOB and 48 or 40) + TAB_H + SRCH_H + 8
	local FOOTER_H   = IS_MOB and 44 or 36
	local list_h     = H - TOP_OFFSET - FOOTER_H

	local scroll = mk('ScrollingFrame', {
		Name                  = 'scroll',
		Size                  = UDim2.new(1, 0, 0, list_h),
		Position              = UDim2.new(0, 0, 0, TOP_OFFSET),
		BackgroundColor3      = C.bg,
		BorderSizePixel       = 0,
		ScrollBarThickness    = IS_MOB and 6 or 4,
		ScrollBarImageColor3  = C.accent,
		CanvasSize            = UDim2.new(0, 0, 0, 0),
		AutomaticCanvasSize   = Enum.AutomaticCanvasSize.Y,
		ScrollingDirection    = Enum.ScrollingDirection.Y,
		ElasticBehavior       = Enum.ElasticBehavior.Always,
		Parent                = backdrop,
	})

	local list_layout = mk('UIListLayout', {
		SortOrder  = Enum.SortOrder.LayoutOrder,
		Padding    = UDim.new(0, 1),
		Parent     = scroll,
	})

	padding(scroll, 0)


	local footer = mk('Frame', {
		Size             = UDim2.new(1, 0, 0, FOOTER_H),
		Position         = UDim2.new(0, 0, 1, -FOOTER_H),
		BackgroundColor3 = C.header,
		BorderSizePixel  = 0,
		Parent           = backdrop,
	})
	corner(footer, 10)
	mk('Frame', {
		Size             = UDim2.new(1, 0, 0.5, 0),
		BackgroundColor3 = C.header,
		BorderSizePixel  = 0,
		Parent           = footer,
	})

	local footer_label = mk('TextLabel', {
		Size             = UDim2.new(1, IS_MOB and -104 or -96, 1, 0),
		Position         = UDim2.new(0, 8, 0, 0),
		BackgroundTransparency = 1,
		Text             = 'prefix: ; | click any command to run it',
		Font             = Enum.Font.Gotham,
		TextSize         = 11,
		TextColor3       = C.muted,
		TextXAlignment   = Enum.TextXAlignment.Left,
		Parent           = footer,
	})


	local plugins_shortcut = mk('TextButton', {
		Size             = UDim2.new(0, IS_MOB and 88 or 80, 0, IS_MOB and 28 or 22),
		Position         = UDim2.new(1, IS_MOB and -94 or -86, 0.5, IS_MOB and -14 or -11),
		BackgroundColor3 = Color3.fromRGB(60, 200, 140),
		Text             = ' Plugins',
		Font             = Enum.Font.GothamBold,
		TextSize         = IS_MOB and 12 or 10,
		TextColor3       = Color3.fromRGB(18, 18, 22),
		BorderSizePixel  = 0,
		Parent           = footer,
	})
	do local c=Instance.new('UICorner') c.CornerRadius=UDim.new(0,5) c.Parent=plugins_shortcut end
	plugins_shortcut.MouseButton1Click:Connect(function()
		cmd_library.execute('plugins')
	end)


	local ROW_H = IS_MOB and 54 or 44
	local all_rows = {}
	local visible_count = 0

	local function build_row(cmd_info, index)
		local is_iy = (cmd_info.plugin == 'iy_legacy')
		local row_col = index % 2 == 0
			and (is_iy and Color3.fromRGB(30,38,30) or C.row_a)
			or  (is_iy and Color3.fromRGB(26,34,26) or C.row_b)

		local row = mk('Frame', {
			Name             = 'row_' .. index,
			Size             = UDim2.new(1, 0, 0, ROW_H),
			BackgroundColor3 = row_col,
			BorderSizePixel  = 0,
			LayoutOrder      = index,
			Parent           = scroll,
		})


		mk('Frame', {
			Size             = UDim2.new(0, 3, 1, 0),
			BackgroundColor3 = is_iy and C.tag_iy or C.accent,
			BorderSizePixel  = 0,
			Parent           = row,
		})


		local tag = mk('TextLabel', {
			Size             = UDim2.new(0, 44, 0, 16),
			Position         = UDim2.new(1, -50, 0, 4),
			BackgroundColor3 = is_iy and C.tag_iy or C.tag_gs,
			BackgroundTransparency = 0.4,
			Text             = is_iy and 'IY' or 'GS',
			Font             = Enum.Font.GothamBold,
			TextSize         = 9,
			TextColor3       = C.text,
			Parent           = row,
		})
		corner(tag, 3)


		local name_label = mk('TextLabel', {
			Size             = UDim2.new(1, -58, 0, IS_MOB and 22 or 18),
			Position         = UDim2.new(0, 8, 0, IS_MOB and 6 or 4),
			BackgroundTransparency = 1,
			Text             = format_command(cmd_info),
			Font             = Enum.Font.GothamBold,
			TextSize         = IS_MOB and 13 or 12,
			TextColor3       = C.text,
			TextXAlignment   = Enum.TextXAlignment.Left,
			TextTruncate     = Enum.TextTruncate.AtEnd,
			Parent           = row,
		})


		mk('TextLabel', {
			Size             = UDim2.new(1, -58, 0, IS_MOB and 18 or 16),
			Position         = UDim2.new(0, 8, 0, IS_MOB and 30 or 24),
			BackgroundTransparency = 1,
			Text             = cmd_info.description or '',
			Font             = Enum.Font.Gotham,
			TextSize         = IS_MOB and 11 or 10,
			TextColor3       = C.muted,
			TextXAlignment   = Enum.TextXAlignment.Left,
			TextTruncate     = Enum.TextTruncate.AtEnd,
			Parent           = row,
		})


		local run_btn = mk('TextButton', {
			Size             = UDim2.new(1, 0, 1, 0),
			BackgroundTransparency = 1,
			Text             = '',
			Parent           = row,
		})
		run_btn.MouseButton1Click:Connect(function()
			local primary = cmd_info.names[1]:lower()
			cmd_library.execute(primary)
			notify('cmds', 'ran: ' .. primary, 1)
		end)

		return row
	end


	local function populate()
		for _, r in pairs(all_rows) do
			if r and r.Parent then r:Destroy() end
		end
		all_rows = {}

		local q    = search_box.Text:lower()
		local idx  = 0

		local cmds_list = cmd_library.help()
		for _, cmd_info in ipairs(cmds_list) do

			local is_iy = (cmd_info.plugin == 'iy_legacy')
			if active_tab == 'gs' and is_iy then continue end
			if active_tab == 'iy' and not is_iy then continue end


			if q ~= '' then
				local match = false
				for _, n in ipairs(cmd_info.names) do
					if n:lower():find(q, 1, true) then match = true; break end
				end
				if not match and cmd_info.description then
					if cmd_info.description:lower():find(q, 1, true) then match = true end
				end
				if not match then continue end
			end

			idx = idx + 1
			local row = build_row(cmd_info, idx)
			table.insert(all_rows, row)
		end

		visible_count = idx
		count_badge.Text = tostring(idx) .. ' cmds'
		footer_label.Text = ('prefix: ' .. (stuff.chat_prefix or ';'))
			.. ' | ' .. tostring(idx) .. ' commands shown | click to run'
	end

	populate()


	for filter, btn in pairs(tab_btns) do
		btn.MouseButton1Click:Connect(function()
			active_tab = filter
			for f2, b2 in pairs(tab_btns) do
				b2.BackgroundColor3 = (f2 == filter) and C.accent or C.header
			end
			populate()
		end)
	end


	search_box:GetPropertyChangedSignal('Text'):Connect(function()
		populate()
	end)


	close_btn.MouseButton1Click:Connect(function()
		gui.Enabled = false
	end)


	do
		local dragging, drag_start, start_pos = false, nil, nil

		header.InputBegan:Connect(function(inp)
			if inp.UserInputType == Enum.UserInputType.MouseButton1
				or inp.UserInputType == Enum.UserInputType.Touch then
				dragging   = true
				drag_start = inp.Position
				start_pos  = backdrop.Position
			end
		end)

		services.user_input_service.InputChanged:Connect(function(inp)
			if dragging and (
				inp.UserInputType == Enum.UserInputType.MouseMovement
				or inp.UserInputType == Enum.UserInputType.Touch) then
				local delta = inp.Position - drag_start
				backdrop.Position = UDim2.new(
					start_pos.X.Scale, start_pos.X.Offset + delta.X,
					start_pos.Y.Scale, start_pos.Y.Offset + delta.Y
				)
			end
		end)

		services.user_input_service.InputEnded:Connect(function(inp)
			if inp.UserInputType == Enum.UserInputType.MouseButton1
				or inp.UserInputType == Enum.UserInputType.Touch then
				dragging = false
			end
		end)
	end


	backdrop.Position = UDim2.new(0.5, -W/2, 0.5, -H/2 - 20)
	backdrop.BackgroundTransparency = 1
	services.tween_service:Create(backdrop, TweenInfo.new(0.2, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
		Position = UDim2.new(0.5, -W/2, 0.5, -H/2),
		BackgroundTransparency = 0,
	}):Play()
end)


