local function gs_save_plugins()
	local out = {}
	for _, p in ipairs(gs_plugin_data) do
		table.insert(out, {
			id=p.id, name=p.name, author=p.author, tag=p.tag,
			description=p.description, code=p.code, enabled=p.enabled, source=p.source,
		})
	end
	pcall(writefile, 'goosesploit_plugins.json', services.http:JSONEncode(out))
end

local function gs_load_plugins_from_disk()
	local ok, raw = pcall(readfile, 'goosesploit_plugins.json')
	if ok and raw and raw ~= '' then
		local ok2, data = pcall(function() return services.http:JSONDecode(raw) end)
		if ok2 and type(data) == 'table' then gs_plugin_data = data end
	end
end

local function gs_run_plugin(plugin)
	if not plugin.enabled then return false, 'disabled' end
	if not plugin.code or plugin.code == '' then return false, 'no code' end
	local fn, err = loadstring(plugin.code)
	if not fn then return false, 'syntax: ' .. tostring(err) end
	local ok, err2 = pcall(fn)
	if not ok then return false, 'runtime: ' .. tostring(err2) end
	return true
end

local function gs_gen_id()
	return 'local_' .. tostring(math.floor(tick())) .. '_' .. tostring(math.random(1000, 9999))
end

local function gs_is_installed(store_id)
	for _, p in ipairs(gs_plugin_data) do
		if p.id == store_id then return true end
	end
	return false
end


gs_load_plugins_from_disk()
for _, plugin in ipairs(gs_plugin_data) do
	if plugin.enabled then
		local ok, err = gs_run_plugin(plugin)
		if not ok then
			notify('plugins', ("Plugin \"" .. tostring(tostring(plugin.name)) .. "\" failed on load: " .. tostring(tostring(err))), 3)
		end
	end
end


cmd_library.add({'plugins', 'pluginmanager', 'pm'}, 'open the goosesploit plugin manager', {}, function()

	if gs_plugins_gui and gs_plugins_gui.Parent then
		gs_plugins_gui.Enabled = not gs_plugins_gui.Enabled
		return
	end


	local C = {
		bg      = Color3.fromRGB(18,18,22),
		panel   = Color3.fromRGB(26,26,32),
		header  = Color3.fromRGB(34,34,42),
		accent  = Color3.fromRGB(88,101,242),
		green   = Color3.fromRGB(60,200,140),
		red     = Color3.fromRGB(200,60,60),
		yellow  = Color3.fromRGB(220,170,50),
		text    = Color3.fromRGB(230,230,240),
		muted   = Color3.fromRGB(130,130,150),
		border  = Color3.fromRGB(50,50,65),
		row_a   = Color3.fromRGB(28,28,36),
		row_b   = Color3.fromRGB(32,32,40),
		code_bg = Color3.fromRGB(14,14,18),
	}
	local TAG_COLORS = {
		cmd=Color3.fromRGB(88,101,242), misc=Color3.fromRGB(130,100,200),
		combat=Color3.fromRGB(200,80,80), movement=Color3.fromRGB(80,180,200),
		utility=Color3.fromRGB(80,200,150), fun=Color3.fromRGB(220,160,60),
		esp=Color3.fromRGB(200,100,200), troll=Color3.fromRGB(220,100,50),
	}
	local function tagcol(t) return TAG_COLORS[tostring(t):lower()] or C.accent end

	local IS_MOB = stuff.is_mobile
	local vp = workspace.CurrentCamera.ViewportSize
	local W  = IS_MOB and math.min(vp.X - 16, 440) or 580
	local H  = IS_MOB and math.min(vp.Y - 50, 620) or 600


	local function mk(cls, props)
		local o = Instance.new(cls)
		for k,v in pairs(props) do o[k]=v end
		return o
	end
	local function corner(p,r) local c=Instance.new('UICorner') c.CornerRadius=UDim.new(0,r or 6) c.Parent=p end
	local function stroke(p,col,t) local s=Instance.new('UIStroke') s.Color=col or C.border s.Thickness=t or 1 s.ApplyStrokeMode=Enum.ApplyStrokeMode.Border s.Parent=p end
	local function pad(p,px,py)
		local u=Instance.new('UIPadding')
		u.PaddingLeft=UDim.new(0,px) u.PaddingRight=UDim.new(0,px)
		u.PaddingTop=UDim.new(0,py or px) u.PaddingBottom=UDim.new(0,py or px)
		u.Parent=p
	end
	local function listlay(p,dir,gap,ha,va)
		local l=Instance.new('UIListLayout')
		l.FillDirection=dir or Enum.FillDirection.Vertical
		l.Padding=UDim.new(0,gap or 0)
		if ha then l.HorizontalAlignment=ha end
		if va then l.VerticalAlignment=va end
		l.Parent=p return l
	end
	local function btn_mk(parent,text,bgcolor,textcol,w,h)
		local b=mk('TextButton',{Size=UDim2.new(0,w or 0,0,h or (IS_MOB and 28 or 24)),AutoButtonColor=false,
			AutomaticSize=w and Enum.AutomaticSize.None or Enum.AutomaticSize.X,
			BackgroundColor3=bgcolor,Text=text,Font=Enum.Font.GothamBold,
			TextSize=IS_MOB and 12 or 11,TextColor3=textcol or C.text,BorderSizePixel=0,Parent=parent})
		corner(b,5) pad(b,10,0) return b
	end
	local function tag_badge(parent,tag,xoff,yoff)
		local t=mk('TextLabel',{Size=UDim2.new(0,52,0,16),Position=UDim2.new(0,xoff or 8,0,yoff or 4),
			BackgroundColor3=tagcol(tag),BackgroundTransparency=0.35,
			Text=tostring(tag or 'misc'),Font=Enum.Font.GothamBold,TextSize=9,TextColor3=C.text,Parent=parent})
		corner(t,3) return t
	end


	local gui = mk('ScreenGui',{Name='GoosesploitPlugins',ResetOnSpawn=false,DisplayOrder=1000,ZIndexBehavior=Enum.ZIndexBehavior.Sibling})
	pcall(function() gui.Parent=services.core_gui end)
	if not gui.Parent then gui.Parent=services.players.LocalPlayer.PlayerGui end
	gs_plugins_gui = gui


	local win = mk('Frame',{Name='win',Size=UDim2.new(0,W,0,H),
		Position=UDim2.new(0.5,-W/2,0.5,-H/2),
		BackgroundColor3=C.bg,BorderSizePixel=0,Parent=gui})
	corner(win,10) stroke(win,C.border,1)


	local shdw=mk('Frame',{Size=UDim2.new(1,20,1,20),Position=UDim2.new(0,-10,0,8),
		BackgroundColor3=Color3.new(0,0,0),BackgroundTransparency=0.55,BorderSizePixel=0,ZIndex=0,Parent=win})
	corner(shdw,14)


	local HDR_H = IS_MOB and 48 or 40
	local hdr=mk('Frame',{Size=UDim2.new(1,0,0,HDR_H),BackgroundColor3=C.header,BorderSizePixel=0,Parent=win})
	corner(hdr,10)
	mk('Frame',{Size=UDim2.new(1,0,0.5,0),Position=UDim2.new(0,0,0.5,0),BackgroundColor3=C.header,BorderSizePixel=0,Parent=hdr})
	mk('TextLabel',{Size=UDim2.new(1,-56,1,0),Position=UDim2.new(0,12,0,0),BackgroundTransparency=1,
		Text=' Goosesploit  —  Plugin Manager',Font=Enum.Font.GothamBold,
		TextSize=IS_MOB and 15 or 14,TextColor3=C.text,TextXAlignment=Enum.TextXAlignment.Left,Parent=hdr})
	local hdr_close=mk('TextButton',{Size=UDim2.new(0,IS_MOB and 40 or 30,0,IS_MOB and 40 or 30),
		Position=UDim2.new(1,IS_MOB and -46 or -36,0.5,IS_MOB and -20 or -15),
		BackgroundColor3=C.red,Text='',Font=Enum.Font.GothamBold,TextSize=IS_MOB and 15 or 12,
		TextColor3=C.text,BorderSizePixel=0,Parent=hdr})
	corner(hdr_close,6)
	hdr_close.MouseButton1Click:Connect(function() gui.Enabled=false end)


	do
		local dragging,ds,sp=false,nil,nil
		win.InputBegan:Connect(function(inp)
			if (inp.UserInputType==Enum.UserInputType.MouseButton1 or inp.UserInputType==Enum.UserInputType.Touch)
				and (inp.Position.Y - win.AbsolutePosition.Y) < HDR_H+2 then
				dragging=true ds=inp.Position sp=win.Position
			end
		end)
		services.user_input_service.InputChanged:Connect(function(inp)
			if dragging and (inp.UserInputType==Enum.UserInputType.MouseMovement or inp.UserInputType==Enum.UserInputType.Touch) then
				local d=inp.Position-ds
				win.Position=UDim2.new(sp.X.Scale,sp.X.Offset+d.X,sp.Y.Scale,sp.Y.Offset+d.Y)
			end
		end)
		services.user_input_service.InputEnded:Connect(function(inp)
			if inp.UserInputType==Enum.UserInputType.MouseButton1 or inp.UserInputType==Enum.UserInputType.Touch then dragging=false end
		end)
	end


	local TAB_H = IS_MOB and 38 or 30
	local TABS_DEF = {
		{id='mine',     label='My Plugins'},
		{id='store',    label='Browse Store'},
		{id='create',   label='Create'},
		{id='import',   label='Import'},
		{id='settings', label='Settings'},
	}
	local active_tab = 'mine'
	local tab_btns   = {}

	local tab_bar=mk('Frame',{Size=UDim2.new(1,0,0,TAB_H),Position=UDim2.new(0,0,0,HDR_H),
		BackgroundColor3=C.panel,BorderSizePixel=0,Parent=win})
	listlay(tab_bar,Enum.FillDirection.Horizontal,4,nil,Enum.VerticalAlignment.Center)
	pad(tab_bar,6,4)

	for _,t in ipairs(TABS_DEF) do
		local b=mk('TextButton',{Size=UDim2.new(0,0,1,-6),AutoButtonColor=false,AutomaticSize=Enum.AutomaticSize.X,
			BackgroundColor3=(active_tab==t.id) and C.accent or C.header,
			Text=t.label,Font=Enum.Font.GothamBold,TextSize=IS_MOB and 13 or 11,TextColor3=C.text,BorderSizePixel=0,Parent=tab_bar})
		corner(b,5) pad(b,10,0)
		tab_btns[t.id]=b
	end


	local CONTENT_Y = HDR_H + TAB_H
	local content=mk('Frame',{Size=UDim2.new(1,0,0,H-CONTENT_Y),Position=UDim2.new(0,0,0,CONTENT_Y),
		BackgroundTransparency=1,BorderSizePixel=0,Parent=win})

	local function clear_content()
		for _,c in ipairs(content:GetChildren()) do c:Destroy() end
	end


	local function build_mine_tab()
		clear_content()


		local act_bar=mk('Frame',{Size=UDim2.new(1,0,0,IS_MOB and 46 or 38),BackgroundColor3=C.panel,BorderSizePixel=0,Parent=content})
		mk('TextLabel',{Size=UDim2.new(1,-240,1,0),Position=UDim2.new(0,12,0,0),BackgroundTransparency=1,
			Text='Installed Plugins',Font=Enum.Font.GothamBold,TextSize=IS_MOB and 13 or 12,
			TextColor3=C.text,TextXAlignment=Enum.TextXAlignment.Left,Parent=act_bar})

		local count_badge=mk('TextLabel',{Size=UDim2.new(0,46,0,18),Position=UDim2.new(0,170,0.5,-9),
			BackgroundColor3=C.accent,BackgroundTransparency=0.3,Text='0',
			Font=Enum.Font.GothamBold,TextSize=10,TextColor3=C.text,Parent=act_bar})
		corner(count_badge,9)

		local ACT_H = IS_MOB and 46 or 38

		local scroll=mk('ScrollingFrame',{
			Size=UDim2.new(1,0,0,H-CONTENT_Y-ACT_H),Position=UDim2.new(0,0,0,ACT_H),
			BackgroundColor3=C.bg,BorderSizePixel=0,
			ScrollBarThickness=IS_MOB and 6 or 4,ScrollBarImageColor3=C.accent,
			CanvasSize=UDim2.new(0,0,0,0),AutomaticCanvasSize=Enum.AutomaticCanvasSize.Y,Parent=content})
		listlay(scroll,nil,2)


		local _editing_ref = nil
		local switch_tab_fn = nil

		local function refresh()
			for _,c in ipairs(scroll:GetChildren()) do if c:IsA('Frame') then c:Destroy() end end
			count_badge.Text = tostring(#gs_plugin_data)

			if #gs_plugin_data == 0 then
				mk('TextLabel',{Size=UDim2.new(1,0,0,100),BackgroundTransparency=1,
					Text='No plugins installed yet.\nBrowse the store or create your own!',
					Font=Enum.Font.Gotham,TextSize=13,TextColor3=C.muted,Parent=scroll})
				return
			end

			for i,plugin in ipairs(gs_plugin_data) do
				local ROW_H = IS_MOB and 68 or 58
				local row=mk('Frame',{Size=UDim2.new(1,0,0,ROW_H),LayoutOrder=i,
					BackgroundColor3=i%2==0 and C.row_a or C.row_b,BorderSizePixel=0,Parent=scroll})

				mk('Frame',{Size=UDim2.new(0,3,1,0),BackgroundColor3=tagcol(plugin.tag),BorderSizePixel=0,Parent=row})
				tag_badge(row, plugin.tag, 8, IS_MOB and 6 or 4)


				mk('TextLabel',{Size=UDim2.new(1,-230,0,IS_MOB and 19 or 16),Position=UDim2.new(0,68,0,IS_MOB and 4 or 3),
					BackgroundTransparency=1,Text=tostring(plugin.name or 'Unnamed'),
					Font=Enum.Font.GothamBold,TextSize=IS_MOB and 13 or 12,TextColor3=C.text,
					TextXAlignment=Enum.TextXAlignment.Left,TextTruncate=Enum.TextTruncate.AtEnd,Parent=row})

				mk('TextLabel',{Size=UDim2.new(1,-230,0,IS_MOB and 14 or 12),Position=UDim2.new(0,68,0,IS_MOB and 25 or 21),
					BackgroundTransparency=1,Text=tostring(plugin.description or ''),
					Font=Enum.Font.Gotham,TextSize=IS_MOB and 11 or 10,TextColor3=C.muted,
					TextXAlignment=Enum.TextXAlignment.Left,TextTruncate=Enum.TextTruncate.AtEnd,Parent=row})

				local on_col = plugin.enabled and C.green or C.muted
				mk('TextLabel',{Size=UDim2.new(0,50,0,12),Position=UDim2.new(0,68,0,IS_MOB and 46 or 38),
					BackgroundTransparency=1,Text=plugin.enabled and '● enabled' or '○ disabled',
					Font=Enum.Font.GothamBold,TextSize=9,TextColor3=on_col,TextXAlignment=Enum.TextXAlignment.Left,Parent=row})

				local src_col = plugin.source=='store' and Color3.fromRGB(80,200,150) or C.muted
				mk('TextLabel',{Size=UDim2.new(0,40,0,12),Position=UDim2.new(0,122,0,IS_MOB and 46 or 38),
					BackgroundTransparency=1,Text=tostring(plugin.source or 'local'),
					Font=Enum.Font.Gotham,TextSize=9,TextColor3=src_col,TextXAlignment=Enum.TextXAlignment.Left,Parent=row})


				local BH = IS_MOB and 26 or 22
				local BY = (ROW_H - BH) / 2
				local function action_btn(text, bgcolor, xoff)
					local b=mk('TextButton',{Size=UDim2.new(0,IS_MOB and 56 or 48,0,BH),
						Position=UDim2.new(1,-xoff,0,BY),
						BackgroundColor3=bgcolor,Text=text,Font=Enum.Font.GothamBold,
						TextSize=IS_MOB and 10 or 9,TextColor3=C.text,BorderSizePixel=0,Parent=row})
					corner(b,4) return b
				end

				local btn_tog  = action_btn(plugin.enabled and 'Disable' or 'Enable', plugin.enabled and C.yellow or C.green, IS_MOB and 218 or 188)
				local btn_edit = action_btn('Edit',   C.accent,                                                                   IS_MOB and 156 or 134)
				local btn_del  = action_btn('Delete', C.red,                                                                      IS_MOB and  94 or  80)
				local btn_shr  = action_btn('Share',  C.header,                                                                   IS_MOB and  30 or  24)

				local p_ref = plugin
				btn_tog.MouseButton1Click:Connect(function()
					p_ref.enabled = not p_ref.enabled
					if p_ref.enabled then
						local ok,err=gs_run_plugin(p_ref)
						if not ok then p_ref.enabled=false; notify('plugins','Error enabling: '..tostring(err),3)
						else notify('plugins',("\"" .. tostring(p_ref.name) .. "\" enabled"),1) end
					else notify('plugins',("\"" .. tostring(p_ref.name) .. "\" disabled"),1) end
					gs_save_plugins() refresh()
				end)

				btn_edit.MouseButton1Click:Connect(function()
					_editing_ref = p_ref
					if switch_tab_fn then switch_tab_fn('create') end
				end)

				btn_del.MouseButton1Click:Connect(function()
					for j,pp in ipairs(gs_plugin_data) do
						if pp==p_ref then table.remove(gs_plugin_data,j) break end
					end
					gs_save_plugins()
					notify('plugins',("\"" .. tostring(p_ref.name) .. "\" deleted"),1)
					refresh()
				end)

				btn_shr.MouseButton1Click:Connect(function()
					local ex = {name=p_ref.name,author=p_ref.author or services.players.LocalPlayer.Name,
						tag=p_ref.tag,description=p_ref.description,version='1.0',code=p_ref.code}
					pcall(setclipboard, services.http:JSONEncode(ex))
					notify('plugins','Plugin JSON copied! Share via discord.gg/StHSWMjcnk',2)
				end)
			end
		end


		local orig_refresh = refresh
		refresh()


		return function() orig_refresh() end, function() return _editing_ref end, function(v) _editing_ref=v end, function(fn) switch_tab_fn=fn end
	end


	local function build_store_tab()
		clear_content()
		local store_data = {}


		local srch_frame=mk('Frame',{Size=UDim2.new(1,0,0,IS_MOB and 42 or 34),BackgroundColor3=C.panel,BorderSizePixel=0,Parent=content})
		local srch_bg=mk('Frame',{Size=UDim2.new(1,-16,0,IS_MOB and 30 or 24),Position=UDim2.new(0,8,0,IS_MOB and 6 or 5),BackgroundColor3=C.header,BorderSizePixel=0,Parent=srch_frame})
		corner(srch_bg,5) stroke(srch_bg,C.border,1)
		mk('TextLabel',{Size=UDim2.new(0,26,1,0),BackgroundTransparency=1,Text='',TextSize=13,Font=Enum.Font.Gotham,TextColor3=C.muted,Parent=srch_bg})
		local srch_box=mk('TextBox',{Size=UDim2.new(1,-28,1,0),Position=UDim2.new(0,26,0,0),BackgroundTransparency=1,
			PlaceholderText='search plugins...',PlaceholderColor3=C.muted,Text='',Font=Enum.Font.Gotham,
			TextSize=IS_MOB and 13 or 12,TextColor3=C.text,ClearTextOnFocus=false,Parent=srch_bg})


		local TAG_H = IS_MOB and 32 or 26
		local tag_bar=mk('Frame',{Size=UDim2.new(1,0,0,TAG_H),Position=UDim2.new(0,0,0,IS_MOB and 42 or 34),
			BackgroundColor3=C.bg,BorderSizePixel=0,Parent=content})
		listlay(tag_bar,Enum.FillDirection.Horizontal,3,nil,Enum.VerticalAlignment.Center)
		pad(tag_bar,6,3)
		local active_tfilter = 'all'
		local tfilter_btns = {}
		for _,tg in ipairs({'all','cmd','misc','combat','movement','utility','fun','esp','troll'}) do
			local b=mk('TextButton',{Size=UDim2.new(0,0,1,0),AutoButtonColor=false,AutomaticSize=Enum.AutomaticSize.X,
				BackgroundColor3=(tg=='all') and C.accent or C.header,Text=tg,Font=Enum.Font.GothamBold,
				TextSize=IS_MOB and 10 or 9,TextColor3=C.text,BorderSizePixel=0,Parent=tag_bar})
			corner(b,4) pad(b,6,0)
			tfilter_btns[tg]=b
		end

		local LIST_TOP = (IS_MOB and 42 or 34) + TAG_H
		local status_lbl=mk('TextLabel',{Size=UDim2.new(1,0,0,IS_MOB and 28 or 22),Position=UDim2.new(0,0,0,LIST_TOP),
			BackgroundTransparency=1,Text='⏳ Loading store...',Font=Enum.Font.Gotham,TextSize=11,TextColor3=C.muted,Parent=content})
		local SCROLL_TOP = LIST_TOP + (IS_MOB and 28 or 22)
		local scroll=mk('ScrollingFrame',{
			Size=UDim2.new(1,0,0,H-CONTENT_Y-SCROLL_TOP),Position=UDim2.new(0,0,0,SCROLL_TOP),
			BackgroundColor3=C.bg,BorderSizePixel=0,
			ScrollBarThickness=IS_MOB and 6 or 4,ScrollBarImageColor3=C.accent,
			CanvasSize=UDim2.new(0,0,0,0),AutomaticCanvasSize=Enum.AutomaticCanvasSize.Y,Parent=content})
		listlay(scroll,nil,2)

		local function render_store()
			for _,c in ipairs(scroll:GetChildren()) do if c:IsA('Frame') then c:Destroy() end end
			local q = srch_box.Text:lower()
			local idx = 0
			for _,sp in ipairs(store_data) do
				if active_tfilter~='all' and tostring(sp.tag):lower()~=active_tfilter then continue end
				if q~='' then
					local hit = tostring(sp.name or ''):lower():find(q,1,true)
						or tostring(sp.description or ''):lower():find(q,1,true)
						or tostring(sp.author or ''):lower():find(q,1,true)
						or tostring(sp.tag or ''):lower():find(q,1,true)
					if not hit then continue end
				end
				idx=idx+1
				local ROW_H = IS_MOB and 72 or 60
				local row=mk('Frame',{Size=UDim2.new(1,0,0,ROW_H),LayoutOrder=idx,
					BackgroundColor3=idx%2==0 and C.row_a or C.row_b,BorderSizePixel=0,Parent=scroll})
				mk('Frame',{Size=UDim2.new(0,3,1,0),BackgroundColor3=tagcol(sp.tag),BorderSizePixel=0,Parent=row})
				tag_badge(row, sp.tag, 8, IS_MOB and 6 or 4)
				mk('TextLabel',{Size=UDim2.new(1,-180,0,IS_MOB and 19 or 16),Position=UDim2.new(0,68,0,IS_MOB and 4 or 3),
					BackgroundTransparency=1,Text=tostring(sp.name or '?'),Font=Enum.Font.GothamBold,
					TextSize=IS_MOB and 13 or 12,TextColor3=C.text,TextXAlignment=Enum.TextXAlignment.Left,
					TextTruncate=Enum.TextTruncate.AtEnd,Parent=row})
				mk('TextLabel',{Size=UDim2.new(1,-180,0,IS_MOB and 14 or 12),Position=UDim2.new(0,68,0,IS_MOB and 25 or 21),
					BackgroundTransparency=1,Text=tostring(sp.description or ''),Font=Enum.Font.Gotham,
					TextSize=IS_MOB and 11 or 10,TextColor3=C.muted,TextXAlignment=Enum.TextXAlignment.Left,
					TextTruncate=Enum.TextTruncate.AtEnd,Parent=row})
				mk('TextLabel',{Size=UDim2.new(1,-180,0,12),Position=UDim2.new(0,68,0,IS_MOB and 46 or 36),
					BackgroundTransparency=1,Text='by ' .. tostring(sp.author or 'unknown') .. ' •  v' .. tostring(sp.version or '1.0'),
					Font=Enum.Font.Gotham,TextSize=10,TextColor3=C.muted,TextXAlignment=Enum.TextXAlignment.Left,Parent=row})

				local already = gs_is_installed(sp.id)
				local inst_btn=mk('TextButton',{Size=UDim2.new(0,IS_MOB and 76 or 68,0,IS_MOB and 30 or 26),
					Position=UDim2.new(1,-(IS_MOB and 84 or 76),0,(ROW_H-(IS_MOB and 30 or 26))/2),
					BackgroundColor3=already and C.muted or C.green,
					Text=already and ' Added' or '+ Add',Font=Enum.Font.GothamBold,
					TextSize=IS_MOB and 12 or 11,TextColor3=already and C.text or C.bg,BorderSizePixel=0,Parent=row})
				corner(inst_btn,5)
				if not already then
					local sp_ref=sp
					inst_btn.MouseButton1Click:Connect(function()
						local new_p={id=sp_ref.id,name=sp_ref.name,author=sp_ref.author,tag=sp_ref.tag,
							description=sp_ref.description,code=sp_ref.code,enabled=true,source='store'}
						table.insert(gs_plugin_data,new_p)
						gs_save_plugins()
						local ok,err=gs_run_plugin(new_p)
						if ok then notify('plugins',("Installed \"" .. tostring(sp_ref.name) .. "\"!"),1)
						else notify('plugins',("Installed but error: " .. tostring(err)),3) end
						inst_btn.Text=' Added'
						inst_btn.BackgroundColor3=C.muted
						inst_btn.TextColor3=C.text
					end)
				end
			end
			status_lbl.Text = tostring(idx) .. ' plugin' .. (idx~=1 and 's' or '')
				.. (q~='' and (' matching "' .. q .. '"') or '')
				.. (active_tfilter~='all' and (' [' .. active_tfilter .. ']') or '')
		end

		for tg,b in pairs(tfilter_btns) do
			b.MouseButton1Click:Connect(function()
				active_tfilter=tg
				for t2,b2 in pairs(tfilter_btns) do b2.BackgroundColor3=(t2==tg) and (tg=='all' and C.accent or tagcol(tg)) or C.header end
				render_store()
			end)
		end
		srch_box:GetPropertyChangedSignal('Text'):Connect(render_store)


		task.spawn(function()
			local ok,raw = pcall(function() return services.http:GetAsync(GS_STORE_URL,true) end)
			if ok and raw and #raw > 10 then
				local ok2,data=pcall(function() return services.http:JSONDecode(raw) end)
				if ok2 and type(data)=='table' then
					store_data=data
					status_lbl.Text='Store loaded — ' .. #store_data .. ' plugins'
					render_store() return
				end
			end
			store_data = GS_BUNDLED
			status_lbl.Text='Bundled plugins (store unreachable)'
			render_store()
		end)
	end


	local _get_editing = nil
	local _set_editing = nil

	local function build_create_tab()
		clear_content()

		local editing = _get_editing and _get_editing() or nil
		if _set_editing then _set_editing(nil) end

		local TAGS_SEL = {'cmd','misc','utility','fun','combat','movement','esp','troll'}
		local sel_tag  = (editing and editing.tag) or 'cmd'
		local tag_sel_btns = {}


		local FORM_H = IS_MOB and 150 or 126
		local form=mk('Frame',{Size=UDim2.new(1,0,0,FORM_H),BackgroundColor3=C.panel,BorderSizePixel=0,Parent=content})


		mk('TextLabel',{Size=UDim2.new(0,40,0,14),Position=UDim2.new(0,10,0,8),BackgroundTransparency=1,
			Text='Name',Font=Enum.Font.GothamBold,TextSize=10,TextColor3=C.muted,TextXAlignment=Enum.TextXAlignment.Left,Parent=form})
		local name_bg=mk('Frame',{Size=UDim2.new(0.55,-14,0,IS_MOB and 28 or 24),Position=UDim2.new(0,8,0,24),BackgroundColor3=C.header,BorderSizePixel=0,Parent=form})
		corner(name_bg,5) stroke(name_bg,C.border,1)
		local name_box=mk('TextBox',{Size=UDim2.new(1,-8,1,0),Position=UDim2.new(0,4,0,0),BackgroundTransparency=1,
			PlaceholderText='Plugin name...',PlaceholderColor3=C.muted,Text=editing and (editing.name or '') or '',
			Font=Enum.Font.Gotham,TextSize=IS_MOB and 13 or 12,TextColor3=C.text,ClearTextOnFocus=false,Parent=name_bg})


		mk('TextLabel',{Size=UDim2.new(0,68,0,14),Position=UDim2.new(0,10,0,IS_MOB and 62 or 56),BackgroundTransparency=1,
			Text='Description',Font=Enum.Font.GothamBold,TextSize=10,TextColor3=C.muted,TextXAlignment=Enum.TextXAlignment.Left,Parent=form})
		local desc_bg=mk('Frame',{Size=UDim2.new(1,-16,0,IS_MOB and 28 or 24),Position=UDim2.new(0,8,0,IS_MOB and 78 or 72),BackgroundColor3=C.header,BorderSizePixel=0,Parent=form})
		corner(desc_bg,5) stroke(desc_bg,C.border,1)
		local desc_box=mk('TextBox',{Size=UDim2.new(1,-8,1,0),Position=UDim2.new(0,4,0,0),BackgroundTransparency=1,
			PlaceholderText='Brief description...',PlaceholderColor3=C.muted,Text=editing and (editing.description or '') or '',
			Font=Enum.Font.Gotham,TextSize=IS_MOB and 13 or 12,TextColor3=C.text,ClearTextOnFocus=false,Parent=desc_bg})


		mk('TextLabel',{Size=UDim2.new(0,30,0,14),Position=UDim2.new(0.56,0,0,8),BackgroundTransparency=1,
			Text='Tag',Font=Enum.Font.GothamBold,TextSize=10,TextColor3=C.muted,TextXAlignment=Enum.TextXAlignment.Left,Parent=form})
		local tag_sel_frame=mk('Frame',{Size=UDim2.new(0.44,-8,0,IS_MOB and 52 or 42),Position=UDim2.new(0.56,0,0,24),BackgroundTransparency=1,BorderSizePixel=0,Parent=form})
		do
			local tsl=Instance.new('UIListLayout')
			tsl.FillDirection=Enum.FillDirection.Horizontal tsl.Padding=UDim.new(0,3)
			tsl.Wraps=true tsl.VerticalAlignment=Enum.VerticalAlignment.Top
			tsl.Parent=tag_sel_frame
		end
		for _,tg in ipairs(TAGS_SEL) do
			local b=mk('TextButton',{Size=UDim2.new(0,0,0,IS_MOB and 22 or 18),AutoButtonColor=false,AutomaticSize=Enum.AutomaticSize.X,
				BackgroundColor3=(sel_tag==tg) and tagcol(tg) or C.header,Text=tg,
				Font=Enum.Font.GothamBold,TextSize=9,TextColor3=C.text,BorderSizePixel=0,Parent=tag_sel_frame})
			corner(b,3) pad(b,5,0)
			tag_sel_btns[tg]=b
			b.MouseButton1Click:Connect(function()
				sel_tag=tg
				for t2,b2 in pairs(tag_sel_btns) do b2.BackgroundColor3=(t2==tg) and tagcol(tg) or C.header end
				if name_box.Text=='' then
					if GS_TEMPLATES[tg] and (code_box.Text==GS_TEMPLATES['cmd'] or code_box.Text==GS_TEMPLATES['misc']) then
						code_box.Text=GS_TEMPLATES[tg]
					end
				end
			end)
		end


		local CODE_HDR_H = IS_MOB and 30 or 26
		local code_hdr=mk('Frame',{Size=UDim2.new(1,0,0,CODE_HDR_H),Position=UDim2.new(0,0,0,FORM_H),
			BackgroundColor3=C.header,BorderSizePixel=0,Parent=content})
		mk('TextLabel',{Size=UDim2.new(0.5,0,1,0),Position=UDim2.new(0,10,0,0),BackgroundTransparency=1,
			Text=' Code Editor',Font=Enum.Font.GothamBold,TextSize=IS_MOB and 12 or 11,TextColor3=C.text,
			TextXAlignment=Enum.TextXAlignment.Left,Parent=code_hdr})

		local tmpl_row=mk('Frame',{Size=UDim2.new(0.5,0,1,-4),Position=UDim2.new(0.5,0,0,2),BackgroundTransparency=1,BorderSizePixel=0,Parent=code_hdr})
		listlay(tmpl_row,Enum.FillDirection.Horizontal,4,Enum.HorizontalAlignment.Right,Enum.VerticalAlignment.Center)
		for _,tt in ipairs({'cmd','misc','esp','hud','loop'}) do
			local key = tt
			local tb=mk('TextButton',{Size=UDim2.new(0,0,1,0),AutoButtonColor=false,AutomaticSize=Enum.AutomaticSize.X,
				BackgroundColor3=C.panel,Text=tt,Font=Enum.Font.GothamBold,TextSize=9,TextColor3=C.muted,BorderSizePixel=0,Parent=tmpl_row})
			corner(tb,3) pad(tb,6,0)
			tb.MouseButton1Click:Connect(function()
				code_box.Text = GS_TEMPLATES[key] or ''
				if GS_TEMPLATES[key] and (key=='cmd' or key=='esp' or key=='hud') then
					sel_tag = 'cmd'
					for t2,b2 in pairs(tag_sel_btns) do b2.BackgroundColor3=(t2=='cmd') and tagcol('cmd') or C.header end
				elseif key=='misc' or key=='loop' then
					sel_tag = 'misc'
					for t2,b2 in pairs(tag_sel_btns) do b2.BackgroundColor3=(t2=='misc') and tagcol('misc') or C.header end
				end
			end)
		end


		local ACT_ROW_H = IS_MOB and 44 or 36

		local code_h = H - CONTENT_Y - FORM_H - CODE_HDR_H - ACT_ROW_H
		local code_bg=mk('Frame',{Size=UDim2.new(1,0,0,code_h),Position=UDim2.new(0,0,0,FORM_H+CODE_HDR_H),
			BackgroundColor3=C.code_bg,BorderSizePixel=0,Parent=content})
		stroke(code_bg,C.border,1)
		local code_box=mk('TextBox',{Size=UDim2.new(1,-8,1,-8),Position=UDim2.new(0,4,0,4),
			BackgroundTransparency=1,MultiLine=true,ClearTextOnFocus=false,
			Text=editing and (editing.code or '') or GS_TEMPLATES[sel_tag] or GS_TEMPLATES.cmd,
			PlaceholderText='-- write your plugin code here...',PlaceholderColor3=C.muted,
			Font=Enum.Font.Code,TextSize=IS_MOB and 12 or 11,
			TextColor3=Color3.fromRGB(200,220,255),
			TextXAlignment=Enum.TextXAlignment.Left,TextYAlignment=Enum.TextYAlignment.Top,
			TextWrapped=false,Parent=code_bg})


		local act_row=mk('Frame',{Size=UDim2.new(1,0,0,ACT_ROW_H),
			Position=UDim2.new(0,0,1,-ACT_ROW_H),BackgroundColor3=C.panel,BorderSizePixel=0,Parent=content})
		listlay(act_row,Enum.FillDirection.Horizontal,6,Enum.HorizontalAlignment.Right,Enum.VerticalAlignment.Center)
		pad(act_row,8,0)


		if editing then
			mk('TextLabel',{Size=UDim2.new(0.4,0,1,0),BackgroundTransparency=1,
				Text='Editing: ' .. tostring(editing.name),Font=Enum.Font.GothamBold,
				TextSize=10,TextColor3=C.yellow,TextXAlignment=Enum.TextXAlignment.Left,Parent=act_row})
		end

		local btn_test   = btn_mk(act_row,'▶ Test Run',   C.green,  C.bg)
		local btn_save   = btn_mk(act_row,' Save',       C.accent, C.text)
		local btn_upload = btn_mk(act_row,' Upload to Store', C.header, C.muted)

		btn_test.MouseButton1Click:Connect(function()
			local fn,err=loadstring(code_box.Text)
			if not fn then notify('plugins','Syntax error: '..tostring(err),3)
			else
				local ok,err2=pcall(fn)
				if ok then notify('plugins',' Plugin ran OK!',1)
				else notify('plugins','Runtime error: '..tostring(err2),3) end
			end
		end)

		btn_save.MouseButton1Click:Connect(function()
			local nm = name_box.Text
			if nm=='' then notify('plugins','Give your plugin a name!',2) return end
			local new_p={
				id          = editing and editing.id or gs_gen_id(),
				name        = nm,
				author      = services.players.LocalPlayer.Name,
				tag         = sel_tag,
				description = desc_box.Text,
				code        = code_box.Text,
				enabled     = true,
				source      = 'local',
			}
			if editing then
				for j,pp in ipairs(gs_plugin_data) do
					if pp.id==editing.id then gs_plugin_data[j]=new_p break end
				end
			else
				table.insert(gs_plugin_data,new_p)
			end
			gs_save_plugins()
			local ok,err=gs_run_plugin(new_p)
			if ok then notify('plugins',("Plugin \"" .. tostring(nm) .. "\" saved & loaded!"),1)
			else notify('plugins',("Saved but run error: " .. tostring(err)),3) end
		end)

		btn_upload.MouseButton1Click:Connect(function()
			local nm = name_box.Text
			if nm=='' then notify('plugins','Name your plugin first!',2) return end
			local ex={
				id          = 'community_'..nm:lower():gsub('%s+','_')..'_'..tostring(math.floor(tick())),
				name        = nm,
				author      = services.players.LocalPlayer.Name,
				tag         = sel_tag,
				description = desc_box.Text,
				version     = '1.0',
				downloads   = 0,
				code        = code_box.Text,
			}
			pcall(setclipboard, services.http:JSONEncode(ex))
			notify('plugins','Copied to clipboard! Submit via discord.gg/StHSWMjcnk to add to the store.',3)
		end)
	end


	local mine_refresh_fn, get_edit_fn, set_edit_fn, set_switch_fn


	local function build_import_tab()
		clear_content()


		local info=mk('Frame',{Size=UDim2.new(1,0,0,IS_MOB and 54 or 44),BackgroundColor3=C.panel,BorderSizePixel=0,Parent=content})
		mk('TextLabel',{Size=UDim2.new(1,-16,1,0),Position=UDim2.new(0,10,0,0),BackgroundTransparency=1,
			Text='Paste plugin JSON below (from the Share button or discord)',
			Font=Enum.Font.Gotham,TextSize=IS_MOB and 12 or 11,TextColor3=C.muted,
			TextWrapped=true,TextXAlignment=Enum.TextXAlignment.Left,Parent=info})


		local PASTE_H = IS_MOB and 160 or 140
		local paste_bg=mk('Frame',{Size=UDim2.new(1,-16,0,PASTE_H),Position=UDim2.new(0,8,0,IS_MOB and 58 or 48),
			BackgroundColor3=C.code_bg,BorderSizePixel=0,Parent=content})
		corner(paste_bg,6) stroke(paste_bg,C.border,1)
		local paste_box=mk('TextBox',{Size=UDim2.new(1,-8,1,-8),Position=UDim2.new(0,4,0,4),
			BackgroundTransparency=1,MultiLine=true,ClearTextOnFocus=false,
			PlaceholderText='{ "name": "My Plugin", "tag": "cmd", "code": "...", ... }',
			PlaceholderColor3=C.muted,Text='',Font=Enum.Font.Code,
			TextSize=IS_MOB and 11 or 10,TextColor3=Color3.fromRGB(200,220,255),
			TextXAlignment=Enum.TextXAlignment.Left,TextYAlignment=Enum.TextYAlignment.Top,
			TextWrapped=true,Parent=paste_bg})


		local PASTE_BTN_Y = (IS_MOB and 58 or 48) + PASTE_H + 8
		local paste_clip=btn_mk(content,'Paste from Clipboard',C.header,C.muted)
		paste_clip.Size=UDim2.new(0,IS_MOB and 170 or 150,0,IS_MOB and 28 or 24)
		paste_clip.Position=UDim2.new(0,8,0,PASTE_BTN_Y)
		paste_clip.MouseButton1Click:Connect(function()
			local ok,txt=pcall(getclipboard)
			if ok and txt and #txt>4 then paste_box.Text=txt
			else notify('plugins','Clipboard empty or unavailable',2) end
		end)


		local status=mk('TextLabel',{Size=UDim2.new(1,-16,0,IS_MOB and 20 or 16),
			Position=UDim2.new(0,8,0,PASTE_BTN_Y+(IS_MOB and 34 or 30)),
			BackgroundTransparency=1,Text='',Font=Enum.Font.GothamBold,TextSize=11,
			TextColor3=C.green,TextXAlignment=Enum.TextXAlignment.Left,Parent=content})


		local PREVIEW_Y = PASTE_BTN_Y + (IS_MOB and 60 or 52)
		local preview_frame=mk('Frame',{Size=UDim2.new(1,-16,0,H-CONTENT_Y-PREVIEW_Y-50),
			Position=UDim2.new(0,8,0,PREVIEW_Y),BackgroundColor3=C.panel,BorderSizePixel=0,Parent=content})
		corner(preview_frame,6) stroke(preview_frame,C.border,1)
		local preview_inner=mk('Frame',{Size=UDim2.new(1,0,1,0),BackgroundTransparency=1,BorderSizePixel=0,Parent=preview_frame})

		local function field_row(parent, label, value, y)
			mk('TextLabel',{Size=UDim2.new(0.35,0,0,IS_MOB and 20 or 16),Position=UDim2.new(0,8,0,y),BackgroundTransparency=1,
				Text=label,Font=Enum.Font.GothamBold,TextSize=IS_MOB and 11 or 10,TextColor3=C.muted,TextXAlignment=Enum.TextXAlignment.Left,Parent=parent})
			mk('TextLabel',{Size=UDim2.new(0.65,-8,0,IS_MOB and 20 or 16),Position=UDim2.new(0.35,0,0,y),BackgroundTransparency=1,
				Text=tostring(value),Font=Enum.Font.Gotham,TextSize=IS_MOB and 11 or 10,TextColor3=C.text,
				TextXAlignment=Enum.TextXAlignment.Left,TextTruncate=Enum.TextTruncate.AtEnd,Parent=parent})
		end

		local parsed_data = nil
		local lh = IS_MOB and 22 or 18

		local function try_parse()
			for _,c in ipairs(preview_inner:GetChildren()) do c:Destroy() end
			parsed_data = nil
			local txt = paste_box.Text
			if txt=='' then status.Text='' return end
			local ok,data=pcall(function() return services.http:JSONDecode(txt) end)
			if not ok or type(data)~='table' then
				status.Text='Invalid JSON — check formatting'
				status.TextColor3 = C.red
				return
			end
			parsed_data = data
			status.Text='Valid JSON — ready to import'
			status.TextColor3 = C.green
			field_row(preview_inner,'Name',   data.name or '?',    4)
			field_row(preview_inner,'Author', data.author or '?',  4+lh)
			field_row(preview_inner,'Tag',    data.tag or '?',     4+lh*2)
			field_row(preview_inner,'Version',data.version or '?', 4+lh*3)
			field_row(preview_inner,'Desc',   data.description or '', 4+lh*4)
			local code_len = data.code and #data.code or 0
			field_row(preview_inner,'Code',   code_len..' chars', 4+lh*5)
		end

		paste_box:GetPropertyChangedSignal('Text'):Connect(try_parse)


		local import_btn=mk('TextButton',{
			Size=UDim2.new(1,-16,0,IS_MOB and 36 or 30),
			Position=UDim2.new(0,8,1,-(IS_MOB and 44 or 38)),
			BackgroundColor3=C.green,Text='Import Plugin',Font=Enum.Font.GothamBold,
			TextSize=IS_MOB and 14 or 12,TextColor3=C.bg,BorderSizePixel=0,Parent=content})
		corner(import_btn,6)

		import_btn.MouseButton1Click:Connect(function()
			if not parsed_data then notify('plugins','Nothing to import — paste valid JSON first',2) return end
			local d = parsed_data
			if not d.name or d.name=='' then notify('plugins','Plugin has no name',2) return end

			local dup=false
			if d.id then
				for _,p in ipairs(gs_plugin_data) do
					if p.id==d.id then dup=true break end
				end
			end
			if dup then notify('plugins','Plugin already installed',2) return end
			local new_p={
				id          = d.id or gs_gen_id(),
				name        = d.name,
				author      = d.author or 'Unknown',
				tag         = d.tag or 'misc',
				description = d.description or '',
				code        = d.code or '',
				enabled     = true,
				source      = 'import',
			}
			table.insert(gs_plugin_data,new_p)
			gs_save_plugins()
			local ok,err=gs_run_plugin(new_p)
			if ok then notify('plugins','Imported "'..(d.name)..'" successfully!',1)
			else notify('plugins','Imported but error: '..tostring(err),3) end
			paste_box.Text=''
			status.Text='Imported! Go to My Plugins to manage it.'
			status.TextColor3=C.green
		end)
	end


	local gs_settings = {
		store_url  = GS_STORE_URL,
		auto_load  = true,
		notify_err = true,
		theme      = 'dark',
	}
	pcall(function()
		local raw=readfile('goosesploit_pm_settings.json')
		if raw and #raw>2 then
			local ok,d=pcall(function() return services.http:JSONDecode(raw) end)
			if ok and type(d)=='table' then
				for k,v in pairs(d) do gs_settings[k]=v end
			end
		end
	end)
	local function gs_save_settings()
		pcall(writefile,'goosesploit_pm_settings.json',services.http:JSONEncode(gs_settings))
	end

	local function build_settings_tab()
		clear_content()

		local SH = IS_MOB and 28 or 24
		local GAP = IS_MOB and 10 or 8
		local y = 12

		local function section_header(label)
			local lbl=mk('TextLabel',{Size=UDim2.new(1,-16,0,IS_MOB and 18 or 14),Position=UDim2.new(0,10,0,y),
				BackgroundTransparency=1,Text=label,Font=Enum.Font.GothamBold,
				TextSize=IS_MOB and 11 or 10,TextColor3=C.accent,TextXAlignment=Enum.TextXAlignment.Left,Parent=content})
			y = y + (IS_MOB and 22 or 18)

			mk('Frame',{Size=UDim2.new(1,-16,0,1),Position=UDim2.new(0,8,0,y),
				BackgroundColor3=C.border,BorderSizePixel=0,Parent=content})
			y = y + 6
		end

		local function toggle_row(label, desc, key)
			local val = gs_settings[key]
			local row=mk('Frame',{Size=UDim2.new(1,0,0,SH+4),Position=UDim2.new(0,0,0,y),
				BackgroundTransparency=1,BorderSizePixel=0,Parent=content})
			mk('TextLabel',{Size=UDim2.new(0.7,-20,0,SH),Position=UDim2.new(0,12,0,2),BackgroundTransparency=1,
				Text=label,Font=Enum.Font.GothamBold,TextSize=IS_MOB and 12 or 11,TextColor3=C.text,
				TextXAlignment=Enum.TextXAlignment.Left,Parent=row})
			if desc~='' then
				mk('TextLabel',{Size=UDim2.new(0.7,-20,0,12),Position=UDim2.new(0,12,0,SH-2),BackgroundTransparency=1,
					Text=desc,Font=Enum.Font.Gotham,TextSize=9,TextColor3=C.muted,
					TextXAlignment=Enum.TextXAlignment.Left,Parent=row})
			end

			local pill=mk('Frame',{Size=UDim2.new(0,44,0,IS_MOB and 24 or 20),Position=UDim2.new(1,-52,0,(SH-20)/2),
				BackgroundColor3=val and C.green or C.header,BorderSizePixel=0,Parent=row})
			corner(pill,10)
			stroke(pill,C.border,1)
			local knob=mk('Frame',{Size=UDim2.new(0,IS_MOB and 18 or 16,0,IS_MOB and 18 or 16),
				Position=val and UDim2.new(1,-(IS_MOB and 20 or 18),0.5,-(IS_MOB and 9 or 8)) or UDim2.new(0,2,0.5,-(IS_MOB and 9 or 8)),
				BackgroundColor3=Color3.fromRGB(230,230,240),BorderSizePixel=0,Parent=pill})
			corner(knob,9)
			local btn=mk('TextButton',{Size=UDim2.new(1,0,1,0),BackgroundTransparency=1,Text='',Parent=pill})
			btn.MouseButton1Click:Connect(function()
				gs_settings[key] = not gs_settings[key]
				local v2=gs_settings[key]
				services.tween_service:Create(pill,TweenInfo.new(0.15),{BackgroundColor3=v2 and C.green or C.header}):Play()
				services.tween_service:Create(knob,TweenInfo.new(0.15),{
					Position=v2 and UDim2.new(1,-(IS_MOB and 20 or 18),0.5,-(IS_MOB and 9 or 8)) or UDim2.new(0,2,0.5,-(IS_MOB and 9 or 8))
				}):Play()
				gs_save_settings()
			end)
			y = y + SH + GAP + (desc~='' and 10 or 0)
		end

		local function text_row(label, desc, key)
			mk('TextLabel',{Size=UDim2.new(1,-16,0,IS_MOB and 16 or 13),Position=UDim2.new(0,12,0,y),
				BackgroundTransparency=1,Text=label,Font=Enum.Font.GothamBold,
				TextSize=IS_MOB and 12 or 11,TextColor3=C.text,TextXAlignment=Enum.TextXAlignment.Left,Parent=content})
			y = y + (IS_MOB and 18 or 15)
			if desc~='' then
				mk('TextLabel',{Size=UDim2.new(1,-16,0,11),Position=UDim2.new(0,12,0,y),
					BackgroundTransparency=1,Text=desc,Font=Enum.Font.Gotham,TextSize=9,
					TextColor3=C.muted,TextXAlignment=Enum.TextXAlignment.Left,Parent=content})
				y = y + 13
			end
			local bg=mk('Frame',{Size=UDim2.new(1,-16,0,IS_MOB and 30 or 26),Position=UDim2.new(0,8,0,y),
				BackgroundColor3=C.code_bg,BorderSizePixel=0,Parent=content})
			corner(bg,5) stroke(bg,C.border,1)
			local tb=mk('TextBox',{Size=UDim2.new(1,-8,1,0),Position=UDim2.new(0,4,0,0),
				BackgroundTransparency=1,ClearTextOnFocus=false,Text=tostring(gs_settings[key] or ''),
				Font=Enum.Font.Code,TextSize=IS_MOB and 12 or 11,TextColor3=C.text,
				TextXAlignment=Enum.TextXAlignment.Left,Parent=bg})
			tb.FocusLost:Connect(function()
				gs_settings[key]=tb.Text
				gs_save_settings()
				notify('plugins','Setting saved',1)
			end)
			y = y + (IS_MOB and 36 or 32) + GAP
		end

		section_header('Plugin Loader')
		toggle_row('Auto-load on start', 'Run enabled plugins automatically when the script loads', 'auto_load')
		toggle_row('Notify on error',    'Show a notification when a plugin fails to load',         'notify_err')

		section_header('Plugin Store')
		text_row('Store URL', 'URL of the community plugin store JSON file', 'store_url')

		section_header('About')
		mk('TextLabel',{Size=UDim2.new(1,-16,0,IS_MOB and 18 or 14),Position=UDim2.new(0,12,0,y),
			BackgroundTransparency=1,Text='Goosesploit Plugin Manager  v1.0.0',
			Font=Enum.Font.GothamBold,TextSize=IS_MOB and 12 or 11,TextColor3=C.muted,
			TextXAlignment=Enum.TextXAlignment.Left,Parent=content})
		y = y + (IS_MOB and 20 or 16)
		mk('TextLabel',{Size=UDim2.new(1,-16,0,IS_MOB and 14 or 12),Position=UDim2.new(0,12,0,y),
			BackgroundTransparency=1,Text='Submit plugins: discord.gg/StHSWMjcnk',
			Font=Enum.Font.Gotham,TextSize=IS_MOB and 11 or 10,TextColor3=C.muted,
			TextXAlignment=Enum.TextXAlignment.Left,Parent=content})
		y = y + (IS_MOB and 20 or 16)


		y = y + 10
		section_header('Danger Zone')
		local del_btn=mk('TextButton',{Size=UDim2.new(1,-16,0,IS_MOB and 32 or 26),Position=UDim2.new(0,8,0,y),
			BackgroundColor3=C.red,BackgroundTransparency=0.2,Text='Delete All Plugins',
			Font=Enum.Font.GothamBold,TextSize=IS_MOB and 13 or 11,TextColor3=C.text,BorderSizePixel=0,Parent=content})
		corner(del_btn,5)
		del_btn.MouseButton1Click:Connect(function()
			gs_plugin_data = {}
			gs_save_plugins()
			notify('plugins','All plugins deleted',2)
		end)
	end

	local function switch_tab(id)
		active_tab=id
		for tid,b in pairs(tab_btns) do b.BackgroundColor3=(tid==id) and C.accent or C.header end
		if id=='mine' then
			mine_refresh_fn, get_edit_fn, set_edit_fn, set_switch_fn = build_mine_tab()
			if set_switch_fn then set_switch_fn(switch_tab) end
			if _get_editing==nil and get_edit_fn then _get_editing=get_edit_fn end
			if _set_editing==nil and set_edit_fn then _set_editing=set_edit_fn end
		elseif id=='store'    then build_store_tab()
		elseif id=='create'   then build_create_tab()
		elseif id=='import'   then build_import_tab()
		elseif id=='settings' then build_settings_tab()
		end
	end

	for _,t in ipairs(TABS_DEF) do
		tab_btns[t.id].MouseButton1Click:Connect(function() switch_tab(t.id) end)
	end


	switch_tab('mine')


	win.BackgroundTransparency=1
	win.Position=UDim2.new(0.5,-W/2,0.5,-H/2-18)
	services.tween_service:Create(win,TweenInfo.new(0.2,Enum.EasingStyle.Sine,Enum.EasingDirection.Out),{
		Position=UDim2.new(0.5,-W/2,0.5,-H/2), BackgroundTransparency=0
	}):Play()
end)

cmd_library.add({'saveposition', 'savepos'}, 'save a position to load with loadpos', {}, function(vstorage)
	vstorage.pos = stuff.owner_char:GetPivot()
	local pos = vstorage.pos.Position
	notify('savepos', ("saved position: x:" .. tostring(math.floor(pos.X)) .. ", y:" .. tostring(math.floor(pos.Y)) .. ", z:" .. tostring(math.floor(pos.Z))), 1)
end)

cmd_library.add({'loadposition', 'loadpos'}, 'load the position saved with savepos', {
	{'bypass_mode', 'boolean'}
}, function(vstorage, bypass)
	local savepos_vstorage = cmd_library.get_variable_storage('savepos')
	local hrp = stuff.owner_char:FindFirstChild('HumanoidRootPart')
	local hrp_cframe = hrp.CFrame

	if savepos_vstorage.pos then
		if bypass then
			if hrp then
				hook_lib.create_hook('loadpos_bypass', {
					newindex = function(self, key, value)
						if self == hrp and (key == 'CFrame' or key == 'Position') then
							return false
						end
					end,
					index = function(self, key)
						if self == hrp and key == 'CFrame' then
							return hrp_cframe
						elseif self == hrp and key == 'Position' then
							return hrp_cframe.Position
						end
					end
				})

				stuff.owner_char:PivotTo(savepos_vstorage.pos)

				task.wait(0.1)
				hook_lib.destroy_hook('loadpos_bypass')
			end
		else
			stuff.owner_char:PivotTo(savepos_vstorage.pos)
		end

		notify('loadpos', 'loaded position', 1)
	else
		notify('loadpos', 'you haven\'t saved a position using saveposition', 2)
	end
end)

cmd_library.add({"respawnpoint","setrespawn"},'sets your respawn point to your current location',{
	{"lasts_one_respawn","boolean"}
} ,function(vstorage,lasts1respawn)
	if vstorage.enabled ~= true then
		vstorage.enabled = true
		local cframe_set = stuff.owner_char:GetPivot()
		notify("respawnpoint","respawn point has been set",1)
		maid.add('set_respawn_point', services.run_service.Heartbeat, function()
			if stuff.owner_char:FindFirstChildOfClass("Humanoid"):GetState() == Enum.HumanoidStateType.Dead then
				if vstorage.currently_respawning ~= true then
				else
					return
				end
				vstorage.currently_respawning = true
				maid.add("currently_respawning",services.run_service.Heartbeat,function()
					if stuff.owner_char:FindFirstChildOfClass("Humanoid"):GetState() ~= Enum.HumanoidStateType.Dead and stuff.owner_char:FindFirstChild("Head") then
						maid.remove("currently_respawning")
						if lasts1respawn == true then
							maid.remove("set_respawn_point")
							vstorage.enabled = false
						end
						stuff.owner_char:PivotTo(cframe_set)
						maid.add("currently_respawning",services.run_service.Heartbeat, function()
							stuff.owner_char:PivotTo(cframe_set)
						end)
						task.delay(0.15,function()
							maid.remove("currently_respawning")
							vstorage.currently_respawning = false
						end)
					end
				end)
			end
		end)
	else
		pcall(function()
			maid.remove("set_respawn_point")
		end)
		vstorage.enabled = false
		notify("respawnpoint","respawn point has been removed",1)
	end
end)

cmd_library.add({'illusion', 'deathrespawn', 'drespawn', 'dr'}, 'makes you respawn at the position where you died', {
	{'bypass_mode', 'boolean'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, bypass, et)
	if et and vstorage.enabled then
		cmd_library.execute('unillusion')
		return
	end
	if vstorage.enabled then
		return notify('deathrespawn', 'death respawn already enabled', 2)
	end

	vstorage.enabled = true
	vstorage.bypass = bypass
	notify('deathrespawn', ("enabled death respawn" .. tostring(bypass and ' (bypass)' or '')), 1)

	local has_died = false
	local death_pos

	maid.add('death_respawn', services.run_service.Heartbeat, function()
		pcall(function()
			local humanoid = stuff.rawrbxget(stuff.owner_char, 'Humanoid')
			if not humanoid then return end

			local health = stuff.rawrbxget(humanoid, 'Health')

			if not has_died and health <= 0 then
				has_died = true
				death_pos = stuff.owner_char:GetPivot()
			elseif has_died and health > 0 then
				if vstorage.bypass then
					local hrp = stuff.owner_char:FindFirstChild('HumanoidRootPart')
					local hrp_cframe = hrp.CFrame
					if hrp then
						hook_lib.create_hook('deathrespawn_bypass', {
							newindex = function(self, key, value)
								if self == hrp and (key == 'CFrame' or key == 'Position') then
									return false
								end
							end,
							index = function(self, key)
								if self == hrp and key == 'CFrame' then
									return hrp_cframe
								elseif self == hrp and key == 'Position' then
									return hrp_cframe.Position
								end
							end
						})

						stuff.owner_char:PivotTo(death_pos)

						task.wait(0.1)
						hook_lib.destroy_hook('deathrespawn_bypass')
					end
				else
					stuff.owner_char:PivotTo(death_pos)
				end

				if health > 1 then
					has_died = false
				end
			end
		end)
	end)
end)

cmd_library.add({'unillusion', 'undeathrespawn', 'undrespawn', 'undr'}, 'disables death respawn', {}, function(vstorage)
	local vstorage = cmd_library.get_variable_storage('illusion')

	if not vstorage.enabled then
		return notify('deathrespawn', 'death respawn not enabled', 2)
	end

	vstorage.enabled = false
	maid.remove('death_respawn')

	if vstorage.bypass then
		hook_lib.destroy_hook('deathrespawn_bypass')
	end

	notify('deathrespawn', 'death respawn disabled', 1)
end)

cmd_library.add({'fakelag', 'desync'}, 'creates fake lag applied on your character', {{'enable_toggling', 'boolean', 'hidden'}}, function(vstorage, et)
	if et and vstorage.enabled then
		cmd_library.execute('unfakelag')
		return
	end
	if vstorage.enabled then
		return notify('fakelag', 'fakelag is already enabled', 2)
	end

	vstorage.enabled = true
	notify('fakelag', 'enabled fakelag', 1)

	task.spawn(function()
		while vstorage.enabled do
			pcall(function()
				local anchor_part = stuff.owner_char:FindFirstChild('UpperTorso') and stuff.rawrbxget(stuff.owner_char, 'HumanoidRootPart') or stuff.rawrbxget(stuff.owner_char, 'Torso')
				stuff.rawrbxset(anchor_part, 'Anchored', true)

				local humanoid = stuff.rawrbxget(stuff.owner_char, 'Humanoid')
				for _, track in humanoid:GetPlayingAnimationTracks() do
					track:AdjustSpeed(track.Speed * 1.1)
				end

				stuff.rawrbxset(humanoid, 'Jump', true)
			end)

			task.wait(.1)

			pcall(function()
				local anchor_part = stuff.owner_char:FindFirstChild('UpperTorso') and stuff.rawrbxget(stuff.owner_char, 'HumanoidRootPart') or stuff.rawrbxget(stuff.owner_char, 'Torso')
				stuff.rawrbxset(anchor_part, 'Anchored', false)

				local humanoid = stuff.rawrbxget(stuff.owner_char, 'Humanoid')
				for _, track in humanoid:GetPlayingAnimationTracks() do
					track:AdjustSpeed(track.Speed / 1.1)
				end
			end)

			task.wait(.1)
		end
	end)
end)

cmd_library.add({'unfakelag', 'undesync'}, 'disables fake lag', {}, function(vstorage)
	local vstorage = cmd_library.get_variable_storage('fakelag')

	if not vstorage.enabled then
		return notify('fakelag', 'fakelag is already disabled', 2)
	end

	vstorage.enabled = false
	notify('fakelag', 'disabled fakelag', 1)
end)

cmd_library.add({'antifling', 'afling', 'antif'}, 'stops other exploiters from flinging you', {}, function(vstorage)
	vstorage.enabled = not vstorage.enabled

	if vstorage.enabled then
		notify('antifling', 'antifling enabled', 1)

		local hrp = stuff.owner_char:FindFirstChild('HumanoidRootPart')
		if hrp then
			vstorage.last_position = stuff.rawrbxget(hrp, 'CFrame')
		end
		vstorage.velocity_threshold = 100

		maid.add('antifling', services.run_service.Heartbeat, function()
			pcall(function()
				local char = stuff.owner.Character
				if char and char:FindFirstChild('HumanoidRootPart') then
					local hrp = char.HumanoidRootPart
					local velocity = stuff.rawrbxget(hrp, 'AssemblyLinearVelocity').Magnitude

					if velocity > vstorage.velocity_threshold then
						stuff.rawrbxset(hrp, 'CFrame', vstorage.last_position)
						stuff.rawrbxset(hrp, 'AssemblyLinearVelocity', Vector3.zero)
						stuff.rawrbxset(hrp, 'AssemblyAngularVelocity', Vector3.zero)
						notify('antifling', ("fling prevention - " .. tostring(math.round(velocity)) .. " > " .. tostring(vstorage.velocity_threshold)), 4)
					else
						vstorage.last_position = stuff.rawrbxget(hrp, 'CFrame')
					end
				end

				local other_players = services.players:GetPlayers()
				table.remove(other_players, table.find(other_players, stuff.owner))

				for _, v in other_players do
					if v.Character then
						for _, part in v.Character:GetDescendants() do
							if part:IsA('BasePart') then
								stuff.rawrbxset(part, 'AssemblyAngularVelocity', Vector3.zero)

								if char and char:FindFirstChild('HumanoidRootPart') then
									local part_pos = stuff.rawrbxget(part, 'Position')
									local hrp_pos = stuff.rawrbxget(char.HumanoidRootPart, 'Position')
									local part_vel = stuff.rawrbxget(part, 'AssemblyLinearVelocity').Magnitude

									if (part_pos - hrp_pos).Magnitude < 10 and part_vel > 50 then
										stuff.rawrbxset(part, 'CanCollide', false)
									end
								end
							end
						end
					end
				end
			end)
		end)
	else
		notify('antifling', 'antifling disabled', 1)
		maid.remove('antifling')
	end
end)

