cmd_library.add({'autopickup', 'apickup'}, 'automatically picks up tools', {
	{'range', 'number'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, range, et)
	if not firetouchinterest then
		return notify('autopickup', 'firetouchinterest not found', 2)
	end

	if et and vstorage.enabled then
		cmd_library.execute('unautopickup')
		return
	end
	if vstorage.enabled then
		return notify('autopickup', 'auto pickup already enabled', 2)
	end

	range = range or 10

	vstorage.enabled = true
	notify('autopickup', 'auto pickup enabled', 1)

	maid.add('auto_pickup', services.run_service.Heartbeat, function()
		local hrp = stuff.rawrbxget(stuff.owner_char, 'HumanoidRootPart')
		local hrp_pos = stuff.rawrbxget(hrp, 'Position')

		for _, v in workspace:GetDescendants() do
			if v:IsA('Tool') and v:FindFirstChild('Handle') then
				local handle_pos = stuff.rawrbxget(v.Handle, 'Position')
				if (hrp_pos - handle_pos).Magnitude <= range then
					firetouchinterest(v.Handle, hrp, 0)
					firetouchinterest(v.Handle, hrp, 1)
				end
			end
		end
	end)
end)

cmd_library.add({'unautopickup', 'unapickup'}, 'disables auto pickup', {}, function(vstorage)
	local vstorage = cmd_library.get_variable_storage('autopickup')

	if not vstorage.enabled then
		return notify('autopickup', 'auto pickup not enabled', 2)
	end

	vstorage.enabled = false
	notify('autopickup', 'auto pickup disabled', 1)
	maid.remove('auto_pickup')
end)

cmd_library.add({'loop'}, 'loops a command at specified interval', {
	{'interval', 'number'},
	{'command', 'string'},
	{['...'] = 'string'}
}, function(vstorage, interval, cmd_name, ...)
	if not cmd_name then
		return notify('loop', 'no command specified', 2)
	end

	interval = interval or 0.5
	local args = {...}

	local similar = cmd_library.find_similar(cmd_name:lower())
	local matched = false
	for _, name in similar do
		if name:lower() == cmd_name:lower() then
			matched = true
			break
		end
	end

	if not matched then
		if #similar > 0 then
			return notify('loop', ("command '" .. tostring(cmd_name) .. "' not found. did you mean: " .. tostring(table.concat(similar, ', ')) .. "?"), 2)
		else
			return notify('loop', ("command '" .. tostring(cmd_name) .. "' not found"), 2)
		end
	end

	vstorage.loops = vstorage.loops or {}
	local loop_id = ("loop_" .. tostring(cmd_name:lower()))

	if vstorage.loops[loop_id] then
		maid.remove(loop_id)
		vstorage.loops[loop_id] = nil
	end

	vstorage.loops[loop_id] = {
		command = cmd_name:lower(),
		args = args,
		interval = interval
	}

	notify('loop', ("looping '" .. tostring(cmd_name) .. "' every " .. tostring(interval) .. "s"), 1)

	task.spawn(function()
		while vstorage.loops[loop_id] do
			cmd_library.execute(cmd_name:lower(), unpack(args))
			task.wait(interval)
		end
	end)
end)

cmd_library.add({'unloop'}, 'stops looping a command', {
	{'command', 'string'}
}, function(vstorage, cmd_name)
	local loop_vs = cmd_library.get_variable_storage('loop')

	if not loop_vs or not loop_vs.loops then
		return notify('unloop', 'no active loops', 2)
	end

	if cmd_name then
		local loop_id = ("loop_" .. tostring(cmd_name:lower()))
		if loop_vs.loops[loop_id] then
			loop_vs.loops[loop_id] = nil
			notify('unloop', ("stopped looping '" .. tostring(cmd_name) .. "'"), 1)
		else
			notify('unloop', 'no loop found for \'' .. tostring(cmd_name) .. '\'', 2)
		end
	else
		local count = 0
		for _ in loop_vs.loops do
			count = count + 1
		end
		loop_vs.loops = {}
		notify('unloop', ("stopped " .. tostring(count) .. " loops"), 1)
	end
end)

cmd_library.add({'spam'}, 'spams a command', {
	{'times', 'number'},
	{'delay', 'number'},
	{['...'] = 'string'}
}, function(vstorage, times, delay, ...)
	times = times or 10
	local args = {...}
	local cmd_name = args[1]
	table.remove(args, 1)

	notify('spam', ("spamming command '" .. tostring(cmd_name) .. "' " .. tostring(times) .. " times"), 1)

	for i = 1, times do
		cmd_library.execute(cmd_name, unpack(args))
		if delay > 0 then
			task.wait(delay or 0.1)
		end
	end
end)

cmd_library.add({'reach', 'r'}, 'increases your tool handle size', {
	{'reach', 'number'},
	{'bypass_mode', 'boolean'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, reach, bypass, et)
	if et and vstorage.enabled then
		cmd_library.execute('unreach')
		return
	end

	reach = reach or 15

	local tool = stuff.owner_char:FindFirstChildOfClass('Tool') or stuff.owner.Backpack:FindFirstChildOfClass('Tool')
	if not tool then
		return notify('reach', 'equip a tool first', 2)
	end

	local tool_handle = stuff.rawrbxget(tool, 'Handle')
	if not tool_handle then
		return notify('reach', 'tool has no handle', 2)
	end

	if vstorage.enabled then
		return notify('reach', 'reach already enabled', 2)
	end

	vstorage.enabled = true
	vstorage.tool = tool
	vstorage.original_size = tool_handle.Size
	vstorage.original_transparency = tool_handle.Transparency
	notify('reach', ("enabled reach (" .. tostring(reach) .. " studs)" .. tostring(bypass and ' (bypass)' or '')), 1)

	if bypass then
		hook_lib.create_hook('reach_bypass', hook_lib.presets.property_spoof(tool_handle, {
			Size = tool_handle.Size,
			Transparency = tool_handle.Transparency
		}))
	end

	stuff.rawrbxset(tool_handle, 'Size', Vector3.new(reach, reach, reach))
	stuff.rawrbxset(tool_handle, 'Transparency', 0.8)
end)

cmd_library.add({'unreach', 'unr'}, 'disables reach', {}, function(vstorage)
	local reach_storage = cmd_library.get_variable_storage('reach')
	if not reach_storage or not reach_storage.enabled then
		return notify('reach', 'reach is not enabled', 2)
	end

	local tool_handle = stuff.rawrbxget(reach_storage.tool, 'Handle')
	if tool_handle then
		stuff.rawrbxset(tool_handle, 'Size', reach_storage.original_size)
		stuff.rawrbxset(tool_handle, 'Transparency', reach_storage.original_transparency)
	end

	reach_storage.enabled = false
	hook_lib.destroy_hook('reach_bypass')
	notify('reach', 'disabled reach', 1)
end)

cmd_library.add({'touchreach', 'treach', 'tr'}, 'adds touch-based reach to your tool', {
	{'reach', 'number'},
	{'use_handle','boolean'},
	{'bypass_mode', 'boolean'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, reach, use_handle, bypass, et)
	if not firetouchinterest then
		return notify('touchreach', 'firetouchinterest not found', 2)
	end
	if et and vstorage.enabled then
		cmd_library.execute('untouchreach')
		return
	end

	reach = reach or 15

	local tool = stuff.owner_char:FindFirstChildOfClass('Tool') or stuff.owner.Backpack:FindFirstChildOfClass('Tool')
	if not tool then
		return notify('touchreach', 'equip a tool first', 2)
	end

	local tool_handle = stuff.rawrbxget(tool, 'Handle')
	if not tool_handle then
		return notify('touchreach', 'tool has no handle', 2)
	end

	if vstorage.enabled then
		return notify('touchreach', 'touchreach already enabled', 2)
	end

	vstorage.enabled = true
	vstorage.tool = tool
	notify('touchreach', ("enabled touchreach (" .. tostring(reach) .. " studs)" .. tostring(bypass and ' (bypass)' or '')), 1)

	if bypass then
		hook_lib.create_hook('touchreach_bypass', hook_lib.presets.property_spoof(tool_handle, {
			Size = tool_handle.Size,
			Position = tool_handle.Position,
			CFrame = tool_handle.CFrame
		}))
	end

	maid.add('touchreach_loop', services.run_service.Heartbeat, function()
		pcall(function()
			if not vstorage.enabled then return end
			if use_handle ~= true then
				local handle_pos = stuff.rawrbxget(tool_handle, 'Position')

				for _, v in workspace:GetDescendants() do
					if (v.Name == 'HumanoidRootPart' or v.Name == 'Head' or v.Name == 'Torso' or v.Name == 'UpperTorso') then
						local char = v.Parent
						if char and char ~= stuff.owner_char and char:FindFirstChildOfClass('Humanoid') then
							local humanoid = char:FindFirstChildOfClass('Humanoid')
							if humanoid and humanoid.Health > 0 then
								local v_pos = stuff.rawrbxget(v, 'Position')
								if (handle_pos - v_pos).Magnitude <= reach then
									firetouchinterest(v, tool_handle, 0)
									firetouchinterest(v, tool_handle, 1)
								end
							end
						end
					end
				end
			else
				local handle_pos = stuff.rawrbxget(tool_handle, 'Position')

				for _, v in workspace:GetDescendants() do
					if (v.Name == 'HumanoidRootPart' or v.Name == 'Head' or v.Name == 'Torso' or v.Name == 'UpperTorso') then
						local char = v.Parent
						if char and char ~= stuff.owner_char and char:FindFirstChildOfClass('Humanoid') then
							local humanoid = char:FindFirstChildOfClass('Humanoid')
							if humanoid and humanoid.Health > 0 then
								local v_pos = stuff.rawrbxget(v, 'Position')
								if (handle_pos - v_pos).Magnitude <= reach then
									for _, tool_part in tool:GetChildren() do
										if tool_part:IsA("BasePart") or tool_part:IsA("Part") or tool_part:IsA("MeshPart") or tool_part:IsA("UnionOperation") or tool_part.Name:lower() == "hitbox" then
											firetouchinterest(v, tool_part, 0)
											firetouchinterest(v, tool_part, 1)
											if tool_part.Name:lower() == "hitbox" then
												return
											end
										end
									end
								end
							end
						end
					end
				end
			end
		end)
	end)
end)

cmd_library.add({'untouchreach', 'untreach', 'untr'}, 'disables touch reach', {}, function(vstorage)
	local touchreach_storage = cmd_library.get_variable_storage('touchreach')
	if not touchreach_storage or not touchreach_storage.enabled then
		return notify('touchreach', 'touchreach is not enabled', 2)
	end

	touchreach_storage.enabled = false
	maid.remove('touchreach_loop')
	hook_lib.destroy_hook('touchreach_bypass')
	notify('touchreach', 'disabled touchreach', 1)
end)

stuff.real_char, stuff.fakechars = nil, {}
cmd_library.add({'fakecharacter', 'fakechar', 'fc'}, 'creates a r6 fake character that you can control', {}, function(vstorage)
	notify('fakecharacter', 'creating r6 fake character', 1)

	local desc = services.players:GetHumanoidDescriptionFromUserId(stuff.owner.UserId)
	local new_character = services.players:CreateHumanoidModelFromDescription(desc, Enum.HumanoidRigType.R6)
	stuff.rawrbxset(new_character, 'Name', stuff.owner.Name)

	local humanoid = stuff.rawrbxget(new_character, 'Humanoid')
	stuff.rawrbxset(humanoid, 'DisplayName', stuff.owner.DisplayName)

	if not stuff.real_char then
		stuff.real_char = stuff.owner_char
		stuff.rawrbxset(stuff.real_char, 'Parent', nil)
	else
		table.insert(stuff.fakechars, stuff.owner_char)
	end

	new_character:PivotTo(stuff.owner_char:GetPivot())
	stuff.rawrbxset(stuff.owner, 'Character', new_character)
	stuff.owner_char = new_character
	stuff.rawrbxset(new_character, 'Parent', workspace)
end)

