						notify("deletetool", "you must own this part's networkowner to be able to delete it; maybe try reloadnet or getting closer to it", 3)
					end
				end
			end
		end
	end)
end)

cmd_library.add({'partfling', 'pf', 'partf'}, 'flings someone using parts, far more undetectable and works in collisions off', {
	{'player', 'player'},
	{'velocity', 'number'}
}, function(vstorage, targets, vel)
	local velocity = vel or 2500

	local function part_fling(target)
		if not target then return end

		if target == stuff.owner then
			notify('partfling', 'cannot partfling yourself', 2)
			return
		end

		local part = get_closest_part()

		if part == nil then
			notify('partfling', 'there is nothing to partfling with', 2)
			return
		end

		if part:IsDescendantOf(stuff.owner_char) then
			notify('partfling', 'cannot use your own character parts for partfling', 2)
			return
		end

		local old_cframe_part = stuff.rawrbxget(part, 'CFrame')
		local old_cf = stuff.owner_char:GetPivot()
		local old_pos = stuff.rawrbxget(part, 'Position')
		local old_anchored = stuff.rawrbxget(part, 'Anchored')
		local old_can_collide = stuff.rawrbxget(part, 'CanCollide')
		local start_tick = tick()

		repeat
			stuff.owner_char:PivotTo(stuff.rawrbxget(part, 'CFrame'))
			services.run_service.RenderStepped:Wait()
		until network_check(part) == true or stuff.sim_range_reset == true or tick() - start_tick >= 5

		if network_check(part) == true then
			notify('partfling', ("successfully gained part ownership and used partfling on " .. tostring(target.Name) .. " with velocity " .. tostring(velocity)), 1)
		else
			if stuff.sim_range_reset == false then
				notify('partfling', 'attempt to gain ownership timed out, consider using reloadnetwork', 2)
				stuff.owner_char:PivotTo(old_cf)
				return
			end
		end

		stuff.owner_char:PivotTo(old_cf)
		local humanoid = stuff.rawrbxget(stuff.owner_char, 'Humanoid')
		humanoid:ChangeState(Enum.HumanoidStateType.Running)

		local target_hrp = target.Character and target.Character:FindFirstChild('HumanoidRootPart')
		if not target_hrp then
			notify('partfling', ("target " .. tostring(target.Name) .. " has no HumanoidRootPart"), 2)
			return
		end

		local target_original_pos = stuff.rawrbxget(target_hrp, 'Position')
		local fling_start_tick = tick()

		stuff.rawrbxset(part, 'Anchored', false)
		stuff.rawrbxset(part, 'CanCollide', false)
		stuff.rawrbxset(part, 'AssemblyLinearVelocity', Vector3.new(0, velocity * 2, 0))

		local fling_detected = false
		local max_distance_reached = 0
		local lost_ownership_tick = nil

		local function cleanup_part()
			pcall(function()
				stuff.rawrbxset(part, 'Anchored', old_anchored)
				stuff.rawrbxset(part, 'CanCollide', old_can_collide)
				stuff.rawrbxset(part, 'AssemblyLinearVelocity', Vector3.zero)
				stuff.rawrbxset(part, 'Position', old_pos)
				stuff.rawrbxset(part, 'CFrame', old_cframe_part)
			end)
		end

		pcall(function()
			maid.remove('partfling_connection')
		end)

		maid.add('partfling_connection', services.run_service.Heartbeat, function()
			if not target_hrp or not stuff.rawrbxget(target_hrp, 'Parent') then
				maid.remove('partfling_connection')
				cleanup_part()
				notify('partfling', ("target " .. tostring(target.Name) .. " no longer exists"), 2)
				return
			end

			local time_elapsed = tick() - fling_start_tick
			local current_pos = stuff.rawrbxget(target_hrp, 'Position')
			local distance_from_original = (current_pos - target_original_pos).Magnitude
			max_distance_reached = math.max(max_distance_reached, distance_from_original)

			if distance_from_original >= 100 and time_elapsed <= 1 then
				fling_detected = true
				maid.remove('partfling_connection')
				cleanup_part()
				notify('partfling', ("successfully flung " .. tostring(target.Name) .. " (distance: " .. tostring(math.floor(distance_from_original)) .. " studs in " .. tostring(math.floor(time_elapsed * 100) / 100) .. "s)"), 1)
				return
			end

			if fling_detected then
				maid.remove('partfling_connection')
				cleanup_part()
				return
			end

			if time_elapsed >= 10 then
				maid.remove('partfling_connection')
				cleanup_part()
				if max_distance_reached >= 100 then
					notify('partfling', ("successfully flung " .. tostring(target.Name) .. " (max distance: " .. tostring(math.floor(max_distance_reached)) .. " studs)"), 1)
				else
					notify('partfling', ("partfling on " .. tostring(target.Name) .. " timed out (max distance: " .. tostring(math.floor(max_distance_reached)) .. " studs)"), 2)
				end
				return
			end

			if network_check(part) ~= true then
				if lost_ownership_tick == nil then
					lost_ownership_tick = tick()
					cleanup_part()
				end

				local time_since_lost = tick() - lost_ownership_tick

				if time_since_lost >= 1 then
					maid.remove('partfling_connection')

					if max_distance_reached >= 100 then
						notify('partfling', ("successfully flung " .. tostring(target.Name) .. " (distance: " .. tostring(math.floor(max_distance_reached)) .. " studs, lost ownership)"), 1)
					else
						notify('partfling', 'lost ownership of part while flinging ' .. tostring(target.Name) .. ' (only moved ' .. tostring(math.floor(max_distance_reached)) .. ' studs)', 2)
					end
				end
				return
			end

			stuff.rawrbxset(stuff.owner, 'SimulationRadius', 1000)
			stuff.rawrbxset(part, 'Anchored', false)
			stuff.rawrbxset(part, 'CanCollide', false)
			stuff.rawrbxset(part, 'AssemblyLinearVelocity', Vector3.new(0, velocity, 0))
			local character_of_target = target.Character
			local predicted_cf = predict_position(character_of_target)
			if predicted_cf then
				stuff.rawrbxset(part, 'CFrame', predicted_cf)
			end
		end)
	end

	if not targets or #targets == 0 then
		return notify('partfling', 'player not found', 2)
	end

	for _, target in targets do
		part_fling(target)
		task.wait(0.5)
	end
end)

cmd_library.add({'partbring', 'pb', 'bringpart'}, 'brings the nearest part to you or a specified player', {
	{'player', 'player'}
}, function(vstorage, targets)
	local part = get_closest_part()

	if not part then
		return notify('partbring', 'no usable part found nearby', 2)
	end

	local function bring_part(target)
		local target_hrp = target and target.Character and target.Character:FindFirstChild('HumanoidRootPart')
		if not target_hrp then
			return notify('partbring', (tostring(target and target.Name or 'target') .. " has no HumanoidRootPart"), 2)
		end

		local old_cf = stuff.owner_char:GetPivot()
		local start_tick = tick()

		repeat
			stuff.owner_char:PivotTo(stuff.rawrbxget(part, 'CFrame'))
			services.run_service.RenderStepped:Wait()
		until network_check(part) == true or stuff.sim_range_reset == true or tick() - start_tick >= 5

		stuff.owner_char:PivotTo(old_cf)
		local humanoid = stuff.rawrbxget(stuff.owner_char, 'Humanoid')
		humanoid:ChangeState(Enum.HumanoidStateType.Running)

		if not network_check(part) and stuff.sim_range_reset == false then
			return notify('partbring', 'failed to gain part ownership, try reloadnetwork', 2)
		end

		stuff.rawrbxset(stuff.owner, 'SimulationRadius', 1000)
		stuff.rawrbxset(part, 'Anchored', false)
		stuff.rawrbxset(part, 'CanCollide', true)
		stuff.rawrbxset(part, 'AssemblyLinearVelocity', Vector3.zero)
		stuff.rawrbxset(part, 'CFrame', stuff.rawrbxget(target_hrp, 'CFrame') * CFrame.new(0, 0, -5))

		notify('partbring', ("brought part to " .. tostring(target.Name)), 1)
	end

	if not targets or #targets == 0 then
		bring_part(stuff.owner)
	else
		for _, target in targets do
			bring_part(target)
			task.wait(0.5)
		end
	end
end)

cmd_library.add({'tripwire', 'tw'}, 'sets a tripwire on the nearest part, flings anyone who gets close to it', {
	{'velocity', 'number'},
	{'radius', 'number'}
}, function(vstorage, vel, rad)
	if vstorage.enabled then
		return notify('tripwire', 'already active, use untripwire to stop', 2)
	end

	local part = get_closest_part()
	if not part then return notify('tripwire', 'no usable part found nearby', 2) end

	notify('tripwire', 'gaining ownership of part...', 1)

	local old_cf = stuff.owner_char:GetPivot()
	local start_tick = tick()

	repeat
		stuff.owner_char:PivotTo(stuff.rawrbxget(part, 'CFrame'))
		services.run_service.RenderStepped:Wait()
	until network_check(part) == true or stuff.sim_range_reset == true or tick() - start_tick >= 5

	stuff.owner_char:PivotTo(old_cf)
	local humanoid = stuff.rawrbxget(stuff.owner_char, 'Humanoid')
	humanoid:ChangeState(Enum.HumanoidStateType.Running)

	if not network_check(part) and stuff.sim_range_reset == false then
		return notify('tripwire', 'failed to gain part ownership, try reloadnetwork', 2)
	end

	vstorage.enabled = true
	vstorage.velocity = vel or 2500
	vstorage.radius = rad or 8
	vstorage.on_cooldown = {}
	vstorage.watch_pos = stuff.rawrbxget(part, 'Position')
	vstorage.part = part

	local old_can_collide = stuff.rawrbxget(part, 'CanCollide')
	local old_anchored = stuff.rawrbxget(part, 'Anchored')

	stuff.rawrbxset(part, 'Anchored', false)
	stuff.rawrbxset(part, 'CanCollide', false)
	stuff.rawrbxset(part, 'AssemblyLinearVelocity', Vector3.zero)
	stuff.rawrbxset(part, 'AssemblyAngularVelocity', Vector3.zero)
	stuff.rawrbxset(stuff.owner, 'SimulationRadius', 1000)

	notify('tripwire', ("tripwire armed | radius: " .. tostring(vstorage.radius) .. " | velocity: " .. tostring(vstorage.velocity)), 1)

	maid.add('tripwire', services.run_service.Heartbeat, function()
		if not vstorage.enabled then return end

		stuff.rawrbxset(stuff.owner, 'SimulationRadius', 1000)

		if not network_check(part) then
			local regain_tick = tick()
			local owner_cf2 = stuff.owner_char:GetPivot()
			repeat
				stuff.owner_char:PivotTo(stuff.rawrbxget(part, 'CFrame'))
				services.run_service.RenderStepped:Wait()
			until network_check(part) == true or tick() - regain_tick >= 1
			stuff.owner_char:PivotTo(owner_cf2)
			stuff.rawrbxget(stuff.owner_char, 'Humanoid'):ChangeState(Enum.HumanoidStateType.Running)
		end

		stuff.rawrbxset(part, 'CFrame', CFrame.new(vstorage.watch_pos))
		stuff.rawrbxset(part, 'AssemblyLinearVelocity', Vector3.zero)
		stuff.rawrbxset(part, 'AssemblyAngularVelocity', Vector3.zero)

		for _, plr in services.players:GetPlayers() do
			local char = plr.Character
			if not char then continue end
			local plr_hrp = char:FindFirstChild('HumanoidRootPart')
			if not plr_hrp then continue end
			if (stuff.rawrbxget(plr_hrp, 'Position') - vstorage.watch_pos).Magnitude > vstorage.radius then continue end
			if vstorage.on_cooldown[plr.Name] then continue end

			vstorage.on_cooldown[plr.Name] = true
			local target_original_pos = stuff.rawrbxget(plr_hrp, 'Position')
			local fling_start_tick = tick()
			local fling_detected = false
			local max_distance_reached = 0

			task.spawn(function()
				repeat
					local current_hrp = plr.Character and plr.Character:FindFirstChild('HumanoidRootPart')
					if not current_hrp then break end

					stuff.rawrbxset(stuff.owner, 'SimulationRadius', 1000)
					stuff.rawrbxset(part, 'Anchored', false)
					stuff.rawrbxset(part, 'CanCollide', false)

					local predicted_cf = predict_position(plr.Character)
					if predicted_cf then
						stuff.rawrbxset(part, 'CFrame', predicted_cf)
					else
						stuff.rawrbxset(part, 'CFrame', CFrame.new(stuff.rawrbxget(current_hrp, 'Position')))
					end

					stuff.rawrbxset(part, 'AssemblyLinearVelocity', Vector3.new(0, vstorage.velocity, 0))

					local current_pos = stuff.rawrbxget(current_hrp, 'Position')
					local dist_from_original = (current_pos - target_original_pos).Magnitude
					max_distance_reached = math.max(max_distance_reached, dist_from_original)

					if dist_from_original >= 100 and tick() - fling_start_tick <= 1 then
						fling_detected = true
					end

					services.run_service.RenderStepped:Wait()
				until fling_detected or tick() - fling_start_tick >= 3

				if max_distance_reached >= 100 then
					notify('tripwire', ("triggered on " .. tostring(plr.Name) .. " (" .. tostring(math.floor(max_distance_reached)) .. " studs)"), 1)
				else
					notify('tripwire', ("triggered on " .. tostring(plr.Name) .. " (weak fling, " .. tostring(math.floor(max_distance_reached)) .. " studs)"), 2)
				end

				stuff.rawrbxset(part, 'CFrame', CFrame.new(vstorage.watch_pos))
				stuff.rawrbxset(part, 'AssemblyLinearVelocity', Vector3.zero)

				task.wait(3)
				vstorage.on_cooldown[plr.Name] = nil
			end)
		end
	end)
end)

cmd_library.add({'untripwire', 'untw'}, 'disables tripwire', {}, function()
	local vs = cmd_library.get_variable_storage('tripwire')
	if not vs.enabled then return notify('tripwire', 'tripwire is not active', 2) end
	vs.enabled = false
	vs.on_cooldown = {}
	vs.watch_pos = nil
	vs.part = nil
	maid.remove('tripwire')
	notify('tripwire', 'tripwire disabled', 1)
end)

cmd_library.add({'instantprompt', 'instaprompt'}, 'sets proximity prompt hold duration to 0', {
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, et)

	if et and vstorage.enabled then
		cmd_library.execute('uninstantprompt')
		return
	end

	if vstorage.enabled then
		return notify('instantprompt', 'instant prompt already enabled', 2)
	end

	vstorage.enabled = true
	vstorage.original = {}
	notify('instantprompt', 'instant prompt enabled', 1)

	for _, v in workspace:GetDescendants() do
		if v:IsA('ProximityPrompt') then
			vstorage.original[v] = stuff.rawrbxget(v, 'HoldDuration')
			stuff.rawrbxset(v, 'HoldDuration', 0)
		end
	end

	maid.add('instantprompt', workspace.DescendantAdded, function(v)
		if v:IsA('ProximityPrompt') then
			vstorage.original[v] = stuff.rawrbxget(v, 'HoldDuration')
			stuff.rawrbxset(v, 'HoldDuration', 0)
		end
	end, true)
end)

cmd_library.add({'uninstantprompt', 'uninstaprompt'}, 'disables instant prompt', {}, function(vstorage)
	local vstorage = cmd_library.get_variable_storage('instantprompt')

	if not vstorage.enabled then
		return notify('instantprompt', 'instant prompt not enabled', 2)
	end

	vstorage.enabled = false

	for prompt, original_duration in vstorage.original do
		if prompt and prompt.Parent then
			pcall(function()
				stuff.rawrbxset(prompt, 'HoldDuration', original_duration)
			end)
		end
	end

	vstorage.original = {}
	notify('instantprompt', 'instant prompt disabled', 1)
	maid.remove('instantprompt')
end)

cmd_library.add({'lagswitch', 'lswitch', 'ls'}, 'freezes network like tab glitch', {
	{'duration', 'number'}
}, function(vstorage, duration)
	duration = duration or 1

	if vstorage.active then
		return notify('lagswitch', 'lagswitch already active', 2)
	end

	vstorage.active = true
	notify('lagswitch', 'lagswitching for ' .. tostring(duration) .. 's', 1)

	settings().Network.IncomingReplicationLag = math.huge

	task.delay(duration, function()
		settings().Network.IncomingReplicationLag = 0
		vstorage.active = false
		notify('lagswitch', 'lagswitch ended', 1)
	end)
end)

cmd_library.add({'parttrap', 'ptrap', 'trap'}, 'trap them in a cage like a monkey', {
	{'player', 'player'}
}, function(vstorage, targets)
	if not targets or #targets == 0 then
		return notify('parttrap', 'player not found', 2)
	end

	local function get_closest_part_e(excluded)
		local best_part = nil
		local smallest_magnitude = nil
		local head = stuff.rawrbxget(stuff.owner_char, 'Head')
		local head_pos = stuff.rawrbxget(head, 'Position')

		for _, v in workspace:GetDescendants() do
			if v:IsA('BasePart') then
				local anchored = stuff.rawrbxget(v, 'Anchored')
				if not anchored and not v.Parent:FindFirstChildOfClass('Humanoid') and not v.Parent.Parent:FindFirstChildOfClass('Humanoid') and not v:IsDescendantOf(stuff.owner_char) then
					local v_pos = stuff.rawrbxget(v, 'Position')
					if smallest_magnitude == nil or (head_pos - v_pos).Magnitude < smallest_magnitude then
						if #v:GetConnectedParts() < 2 and not table.find(excluded, v) then
							smallest_magnitude = (head_pos - v_pos).Magnitude
							best_part = v
						end
					end
				end
			end
		end

		return best_part
	end

	local function part_trap(target, number, excluded)
		if not target or not target.Character then return end

		local part = get_closest_part_e(excluded)

		if part == nil then
			if number == 1 then
				notify('parttrap', 'there is nothing to parttrap with', 2)
			end
			return
		end

		local old_cframe_part = stuff.rawrbxget(part, 'CFrame')
		local old_cf = stuff.owner_char:GetPivot()

		local start_tick = tick()
		repeat
			stuff.owner_char:PivotTo(stuff.rawrbxget(part, 'CFrame'))
			services.run_service.RenderStepped:Wait()
		until network_check(part) == true or stuff.sim_range_reset == true or tick() - start_tick >= 5

		if network_check(part) ~= true then
			if stuff.sim_range_reset == false then
				if number == 1 then
					notify('parttrap', 'attempt to gain ownership timed out, consider using reloadnetwork', 2)
				end
				stuff.owner_char:PivotTo(old_cf)
				return
			end
		end

		stuff.owner_char:PivotTo(old_cf)
		local humanoid = stuff.rawrbxget(stuff.owner_char, 'Humanoid')
		humanoid:ChangeState(Enum.HumanoidStateType.Running)

		local weld_part1 = target.Character:FindFirstChild('Head')
		if number >= 2 and number ~= 6 then
			if target.Character:FindFirstChild('Torso') then
				weld_part1 = target.Character.Torso
			else
				weld_part1 = target.Character:FindFirstChild('HumanoidRootPart')
			end
		end

		if not weld_part1 then return end

		local part_test = Instance.new('Part', workspace)
		stuff.rawrbxset(part_test, 'Anchored', true)
		stuff.rawrbxset(part_test, 'Size', stuff.rawrbxget(weld_part1, 'Size'))
		stuff.rawrbxset(part_test, 'CFrame', stuff.rawrbxget(weld_part1, 'CFrame'))
		stuff.rawrbxset(part_test, 'Orientation', Vector3.new(0, 90, 0))
		stuff.rawrbxset(part_test, 'Transparency', 1)
		stuff.rawrbxset(part_test, 'CanCollide', false)

		local allowed = true
		local old_part_cframe = nil
		local recursion_done = false

		maid.add(("part_trap_connection_" .. tostring(number)), services.run_service.Heartbeat, function()
			if not target or not target.Character or not target.Character:IsDescendantOf(game) or not target.Character:FindFirstChild('Humanoid') or stuff.sim_range_reset == true then
				maid.remove('part_trap_follow')
				maid.remove(("part_trap_connection_" .. tostring(number)))
				pcall(stuff.destroy, part_test)

				maid.add(("removing_trap_connection_" .. tostring(number)), services.run_service.Heartbeat, function()
					stuff.rawrbxset(part, 'CanCollide', true)
				end)

				task.delay(1, function()
					maid.remove(("removing_trap_connection_" .. tostring(number)))
				end)
				return
			end

			local target_hum = stuff.rawrbxget(target.Character, 'Humanoid')
			local health = stuff.rawrbxget(target_hum, 'Health')
			if health <= 1 then
				maid.remove('part_trap_follow')
				maid.remove(("part_trap_connection_" .. tostring(number)))
				pcall(stuff.destroy, part_test)
				return
			end

			stuff.rawrbxset(stuff.owner, 'SimulationRadius', 1000)

			local move_dir = stuff.rawrbxget(target_hum, 'MoveDirection')
			local move_magnitude = move_dir.Magnitude

			if move_magnitude > 0.1 and allowed == true then
				local part_test_cf = stuff.rawrbxget(part_test, 'CFrame')

				if number == 1 then
					stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(0, 15, 0))
				elseif number == 2 then
					stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(0, 15, -1.5))
				elseif number == 3 then
					stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(0, 15, 1.5))
				elseif number == 4 then
					stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(-1.5, 15, 0))
				elseif number == 5 then
					stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(1.5, 15, 0))
				elseif number >= 6 then
					stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(0, 15, 0))
				end
			else
				if allowed == true then
					stuff.rawrbxset(part, 'Velocity', Vector3.new(14.46262424, 14.46262424, 14.46262424) + Vector3.new(0, math.cos(tick() * 10) / 100, 0))

					local part_test_cf = stuff.rawrbxget(part_test, 'CFrame')

					if number == 1 then
						stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(0, 2, 0))
						stuff.rawrbxset(part, 'Orientation', Vector3.new(0, 0, 0))
					elseif number == 2 then
						stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(0, 0.75, -1.75))
						stuff.rawrbxset(part, 'Orientation', Vector3.new(90, 90, 0))
					elseif number == 3 then
						stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(0, 0.5, 1.75))
						stuff.rawrbxset(part, 'Orientation', Vector3.new(90, 90, 0))
					elseif number == 4 then
						stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(-2, 0.75, 0))
						stuff.rawrbxset(part, 'Orientation', Vector3.new(90, 0, 0))
					elseif number == 5 then
						stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(1.95, 0.75, 0))
						stuff.rawrbxset(part, 'Orientation', Vector3.new(90, 0, 0))
					elseif number == 6 then
						stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(0, 2, 0))
						stuff.rawrbxset(part, 'Orientation', Vector3.new(0, 90, 0))
					elseif number == 7 then
						stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(0, -2, 0))
						stuff.rawrbxset(part, 'Orientation', Vector3.new(0, 90, 0))
					elseif number == 8 then
						stuff.rawrbxset(part, 'CFrame', part_test_cf * CFrame.new(0, -2, 0))
						stuff.rawrbxset(part, 'Orientation', Vector3.new(0, 0, 0))
					end

					old_part_cframe = stuff.rawrbxget(part, 'CFrame')

					if not recursion_done and number < 8 then
						recursion_done = true
						table.insert(excluded, part)
						part_trap(target, number + 1, excluded)
					end

					allowed = false
				else
					stuff.rawrbxset(part, 'CFrame', old_part_cframe)
					stuff.rawrbxset(part, 'Velocity', Vector3.new(14.46262424, 14.46262424, 14.46262424) + Vector3.new(0, math.cos(tick() * 10) / 100, 0))
					stuff.rawrbxset(part, 'CanCollide', false)
				end
			end

			if part_test and weld_part1 then
				pcall(function()
					stuff.rawrbxset(part_test, 'CFrame', stuff.rawrbxget(weld_part1, 'CFrame'))
				end)
			end
		end)
	end

	for _, target in targets do
		notify('parttrap', ("attempted trap on " .. tostring(target.Name)), 1)
		part_trap(target, 1, {})
		task.wait(0.5)
	end
end)


cmd_library.add({'flingaura', 'faura', 'fa'}, 'fling nearby players with parts', {
	{'radius', 'number'},
	{'torso_mode', 'boolean'}
}, function(vstorage, radius, torso_mode)
	radius = radius or 50

	notify('flingaura', 'fetching all parts, your character will be reset', 1)

	local hrp = stuff.rawrbxget(stuff.owner_char, 'HumanoidRootPart')
	local old_cframe = stuff.rawrbxget(hrp, 'CFrame')
	local cam = stuff.rawrbxget(workspace, 'CurrentCamera')

	local humanoid = stuff.rawrbxget(stuff.owner_char, 'Humanoid')
	humanoid:ChangeState(15)
	stuff.rawrbxset(stuff.owner, 'SimulationRadius', 1000)
	task.wait(services.players.RespawnTime + 0.5)

	stuff.rawrbxset(stuff.owner, 'SimulationRadius', 1000)
	local new_hrp = stuff.rawrbxget(stuff.owner_char, 'HumanoidRootPart')
	stuff.rawrbxset(new_hrp, 'CFrame', old_cframe)
	stuff.rawrbxset(workspace, 'CurrentCamera', cam)
	task.wait(0.2)

	local parts = {}
	local part_index = 1

	local r = false
	maid.add('flingaura_died', stuff.owner_char.Humanoid.Died, function()
		if r then return end
		r = true
		cmd_library.execute('unflingaura')
	end)

	maid.add('flingaura_char_added', stuff.owner.CharacterAdded, function()
		if r then return end
		r = true
		cmd_library.execute('unflingaura')
	end)

	local is_player_part = function(part)
		for _, plr in services.players:GetPlayers() do
			if plr.Character and plr.Character:IsAncestorOf(part) then
				return true
			end
		end
		return false
	end

	local is_part = function(part)
		local anchored = stuff.rawrbxget(part, 'Anchored')
		if anchored or is_player_part(part) or part:IsDescendantOf(stuff.owner_char) then
			return false
		end
		if part.Parent ~= workspace and (part.Parent:FindFirstChildOfClass('Humanoid') or part.Parent.Parent and part.Parent.Parent:FindFirstChildOfClass('Humanoid')) then
			return false
		end
		return #part:GetConnectedParts() < 2
	end

	for _, part in workspace:GetDescendants() do
		if part:IsA('BasePart') and is_part(part) then
			table.insert(parts, part)
		end
	end

	local desc_added_conn = workspace.DescendantAdded:Connect(function(part)
		if part:IsA('BasePart') and is_part(part) then
			table.insert(parts, part)
		end
	end)

	vstorage.fling_aura_conn = desc_added_conn

	task.wait(1)

	maid.add('fling_aura', services.run_service.Heartbeat, function(dt)
		if not stuff.owner_char or not new_hrp:IsDescendantOf(workspace) then
			maid.remove('fling_aura')
			desc_added_conn:Disconnect()
			return
		end

		local owner_pos = stuff.rawrbxget(new_hrp, 'Position')
		local nearby_targets = {}

		for _, player in services.players:GetPlayers() do
			if player ~= stuff.owner and player.Character and player.Character:FindFirstChild('HumanoidRootPart') then
				local target_hrp = player.Character.HumanoidRootPart
				local target_pos = stuff.rawrbxget(target_hrp, 'Position')
				local distance = (target_pos - owner_pos).Magnitude

				if distance <= radius then
					local predicted_cf = predict_position(player)
					table.insert(nearby_targets, {player = player, hrp = target_hrp, predicted_cf = predicted_cf})
				end
			end
		end

		if #nearby_targets == 0 then
			return end

		for i = #parts, 1, -1 do
			local part = parts[i]

			if not part:IsDescendantOf(game) then
				table.remove(parts, i)
				continue
			end

			pcall(function()
				if part.ReceiveAge ~= 0 then
					return end
				local anchored = stuff.rawrbxget(part, 'Anchored')
				if anchored then
					return end

				stuff.rawrbxset(part, 'CanCollide', false)
				stuff.rawrbxset(part, 'Velocity', Vector3.new(0, 500000000000, 0))

				local target = nearby_targets[(part_index % #nearby_targets) + 1]

				if not torso_mode then
					stuff.rawrbxset(part, 'CFrame', target.predicted_cf)
				else
					local humanoid = stuff.rawrbxget(stuff.owner_char, 'Humanoid')
					if humanoid then
						humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, false)
						stuff.rawrbxset(humanoid, 'Sit', true)
					end
					local offset_cframe = target.predicted_cf * CFrame.new(0, 0, -(17 + part.Size.Magnitude))
					stuff.rawrbxset(part, 'CFrame', offset_cframe)
					stuff.owner_char:PivotTo(offset_cframe)
				end

				part_index = part_index + 1
			end)
		end
	end)
end)

cmd_library.add({'unflingaura', 'unfaura', 'unfa'}, 'stop fling aura', {}, function(vstorage)
	maid.remove('fling_aura')
	maid.remove('flingaura_died')
	maid.remove('flingaura_char_added')
	if vstorage.fling_aura_conn then
		vstorage.fling_aura_conn:Disconnect()
		vstorage.fling_aura_conn = nil
	end
	notify('unflingaura', 'fling aura stopped', 1)
end)


cmd_library.add({'waypoint', 'wp'}, 'manage waypoints: add, del, go, list, clear, esp, noesp, save, load', {
	{'action', 'string'},
	{'name', 'string'},
	{'color', 'color3'}
}, function(vstorage, action, name, color)
	vstorage.waypoints = vstorage.waypoints or {}
	vstorage.markers = vstorage.markers or {}
	vstorage.arrows = vstorage.arrows or {}
	vstorage.esp_enabled = vstorage.esp_enabled or false

	local WP_PURPLE = Color3.fromRGB(180, 100, 255)
	local WP_TEXT_DIM = Color3.fromRGB(200, 180, 255)

	action = action and action:lower()

	if not action then
		return notify('waypoint', 'actions: add, del, go, list, clear, esp, noesp, save, load', 3)
	end

	if action == 'add' or action == 'set' then
		if not name or name == '' then
			return notify('waypoint', 'provide a name: wp add <n> [color]', 2)
		end

		local hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
		if not hrp then
			return notify('waypoint', 'no HumanoidRootPart found', 2)
		end

		local pos = stuff.rawrbxget(hrp, 'Position')
		vstorage.waypoints[name] = {
			position = pos,
			color = color or WP_PURPLE
		}

		notify('waypoint', ("added \"" .. tostring(name) .. "\" at " .. tostring(math.floor(pos.X)) .. ", " .. tostring(math.floor(pos.Y)) .. ", " .. tostring(math.floor(pos.Z))), 1)

		if vstorage.esp_enabled then
			cmd_library.execute('waypoint', 'noesp')
			cmd_library.execute('waypoint', 'esp')
		end

	elseif action == 'del' or action == 'delete' or action == 'remove' then
		if not name or name == '' then
			return notify('waypoint', 'provide a name: wp del <n>', 2)
		end

		if not vstorage.waypoints[name] then
			return notify('waypoint', ("waypoint \"" .. tostring(name) .. "\" not found"), 2)
		end

		vstorage.waypoints[name] = nil

		if vstorage.markers[name] then
			pcall(stuff.destroy, vstorage.markers[name])
			vstorage.markers[name] = nil
		end

		if vstorage.arrows[name] then
			pcall(stuff.destroy, vstorage.arrows[name])
			vstorage.arrows[name] = nil
		end

		notify('waypoint', ("deleted \"" .. tostring(name) .. "\""), 1)

	elseif action == 'go' or action == 'tp' or action == 'teleport' then
		if not name or name == '' then
			return notify('waypoint', 'provide a name: wp go <n>', 2)
		end

		local wp = vstorage.waypoints[name]
		if not wp then
			return notify('waypoint', ("waypoint \"" .. tostring(name) .. "\" not found"), 2)
		end

		local hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
		if not hrp then
			return notify('waypoint', 'no HumanoidRootPart found', 2)
		end

		stuff.rawrbxset(hrp, 'CFrame', CFrame.new(wp.position + Vector3.new(0, 3, 0)))
		notify('waypoint', ("teleported to \"" .. tostring(name) .. "\""), 1)

	elseif action == 'list' or action == 'ls' then
		local count = 0
		for _ in vstorage.waypoints do
			count += 1
		end

		if count == 0 then
			return notify('waypoint', 'no waypoints saved', 2)
		end

		notify('waypoint', (tostring(count) .. " waypoint(s):"), 4)

		local hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
		for n, wp in vstorage.waypoints do
			local dist_str = ''
			if hrp then
				local dist = math.floor((stuff.rawrbxget(hrp, 'Position') - wp.position).Magnitude)
				dist_str = (" [" .. tostring(dist) .. "m]")
			end
			local p = wp.position
			notify('waypoint', ("\"" .. tostring(n) .. "\"" .. tostring(dist_str) .. " — " .. tostring(math.floor(p.X)) .. ", " .. tostring(math.floor(p.Y)) .. ", " .. tostring(math.floor(p.Z))), 1)
			task.wait(0.05)
		end

	elseif action == 'clear' then
		local count = 0
		for _ in vstorage.waypoints do
			count += 1
		end

		if count == 0 then
			return notify('waypoint', 'no waypoints to clear', 2)
		end

		if vstorage.esp_enabled then
			cmd_library.execute('waypoint', 'noesp')
		end

		vstorage.waypoints = {}
		notify('waypoint', ("cleared " .. tostring(count) .. " waypoint(s)"), 1)

	elseif action == 'save' then
		if not writefile then
			return notify('waypoint', 'writefile not supported on your executor', 2)
		end

		local serialisable = {}
		for n, wp in vstorage.waypoints do
			serialisable[n] = {
				x = wp.position.X,
				y = wp.position.Y,
				z = wp.position.Z,
				r = wp.color.R,
				g = wp.color.G,
				b = wp.color.B
			}
		end

		local ok, err = pcall(function()
			writefile('goosesploit_waypoints.json', services.http:JSONEncode(serialisable))
		end)

		if ok then
			local count = 0
			for _ in serialisable do count += 1 end
			notify('waypoint', ("saved " .. tostring(count) .. " waypoint(s) to goosesploit_waypoints.json"), 1)
		else
			notify('waypoint', ("save failed: " .. tostring(tostring(err))), 2)
		end

	elseif action == 'load' then
		if not readfile or not isfile then
			return notify('waypoint', 'readfile not supported on your executor', 2)
		end

		if not isfile('goosesploit_waypoints.json') then
			return notify('waypoint', 'no save file found, use wp save first', 2)
		end

		local ok, result = pcall(function()
			return services.http:JSONDecode(readfile('goosesploit_waypoints.json'))
		end)

		if not ok or type(result) ~= 'table' then
			return notify('waypoint', 'failed to parse waypoints file', 2)
		end

		local count = 0
		for n, data in result do
			vstorage.waypoints[n] = {
				position = Vector3.new(data.x, data.y, data.z),
				color = Color3.new(data.r, data.g, data.b)
			}
			count += 1
		end

		notify('waypoint', ("loaded " .. tostring(count) .. " waypoint(s)"), 1)

		if vstorage.esp_enabled then
			cmd_library.execute('waypoint', 'noesp')
			cmd_library.execute('waypoint', 'esp')
		end

	elseif action == 'esp' or action == 'show' then
		if vstorage.esp_enabled then
			return notify('waypoint', 'waypoint esp already on, use wp noesp to stop', 2)
		end

		local count = 0
		for _ in vstorage.waypoints do count += 1 end

		if count == 0 then
			return notify('waypoint', 'no waypoints to display, add one first', 2)
		end

		vstorage.esp_enabled = true

		local gui = Instance.new('ScreenGui')
		stuff.rawrbxset(gui, 'Name', 'goosesploit_wp_esp')
		stuff.rawrbxset(gui, 'ResetOnSpawn', false)
		stuff.rawrbxset(gui, 'IgnoreGuiInset', true)
		stuff.rawrbxset(gui, 'DisplayOrder', 2147483647)
		pcall(protect_gui, gui)
		vstorage.gui = gui

		for n, wp in vstorage.waypoints do
			local wp_color = wp.color

			local marker = Instance.new('Frame')
			stuff.rawrbxset(marker, 'Name', ("wp_marker_" .. tostring(n)))
			stuff.rawrbxset(marker, 'AnchorPoint', Vector2.new(0.5, 0.5))
			stuff.rawrbxset(marker, 'BackgroundTransparency', 1)
			stuff.rawrbxset(marker, 'BorderSizePixel', 0)
			stuff.rawrbxset(marker, 'Size', UDim2.new(0, 120, 0, 40))
			stuff.rawrbxset(marker, 'Visible', false)
			stuff.rawrbxset(marker, 'Parent', gui)

			local dot = Instance.new('Frame')
			stuff.rawrbxset(dot, 'Name', 'dot')
			stuff.rawrbxset(dot, 'AnchorPoint', Vector2.new(0.5, 0.5))
			stuff.rawrbxset(dot, 'Size', UDim2.new(0, 8, 0, 8))
			stuff.rawrbxset(dot, 'Position', UDim2.new(0.5, 0, 0.5, 0))
			stuff.rawrbxset(dot, 'BackgroundColor3', wp_color)
			stuff.rawrbxset(dot, 'BorderSizePixel', 0)
			stuff.rawrbxset(dot, 'ZIndex', 2)
			stuff.rawrbxset(dot, 'Parent', marker)

			local dot_corner = Instance.new('UICorner')
			stuff.rawrbxset(dot_corner, 'CornerRadius', UDim.new(1, 0))
			stuff.rawrbxset(dot_corner, 'Parent', dot)

			local name_label = Instance.new('TextLabel')
			stuff.rawrbxset(name_label, 'Name', 'name_label')
			stuff.rawrbxset(name_label, 'AnchorPoint', Vector2.new(0.5, 1))
			stuff.rawrbxset(name_label, 'Size', UDim2.new(0, 120, 0, 14))
			stuff.rawrbxset(name_label, 'Position', UDim2.new(0.5, 0, 0.5, -8))
			stuff.rawrbxset(name_label, 'BackgroundTransparency', 1)
			stuff.rawrbxset(name_label, 'BorderSizePixel', 0)
			stuff.rawrbxset(name_label, 'Text', n)
			stuff.rawrbxset(name_label, 'TextColor3', wp_color)
			stuff.rawrbxset(name_label, 'TextStrokeColor3', Color3.new(0, 0, 0))
			stuff.rawrbxset(name_label, 'TextStrokeTransparency', 0.4)
			stuff.rawrbxset(name_label, 'Font', Enum.Font.Code)
			stuff.rawrbxset(name_label, 'TextSize', 13)
			stuff.rawrbxset(name_label, 'ZIndex', 2)
			stuff.rawrbxset(name_label, 'Parent', marker)

			local dist_label = Instance.new('TextLabel')
			stuff.rawrbxset(dist_label, 'Name', 'dist_label')
			stuff.rawrbxset(dist_label, 'AnchorPoint', Vector2.new(0.5, 0))
			stuff.rawrbxset(dist_label, 'Size', UDim2.new(0, 80, 0, 12))
			stuff.rawrbxset(dist_label, 'Position', UDim2.new(0.5, 0, 0.5, 8))
			stuff.rawrbxset(dist_label, 'BackgroundTransparency', 1)
			stuff.rawrbxset(dist_label, 'BorderSizePixel', 0)
			stuff.rawrbxset(dist_label, 'Text', '')
			stuff.rawrbxset(dist_label, 'TextColor3', WP_TEXT_DIM)
			stuff.rawrbxset(dist_label, 'TextStrokeColor3', Color3.new(0, 0, 0))
			stuff.rawrbxset(dist_label, 'TextStrokeTransparency', 0.4)
			stuff.rawrbxset(dist_label, 'Font', Enum.Font.Code)
			stuff.rawrbxset(dist_label, 'TextSize', 11)
			stuff.rawrbxset(dist_label, 'ZIndex', 2)
			stuff.rawrbxset(dist_label, 'Parent', marker)

			vstorage.markers[n] = marker

			local arrow = Instance.new('ImageLabel')
			stuff.rawrbxset(arrow, 'Name', ("wp_arrow_" .. tostring(n)))
			stuff.rawrbxset(arrow, 'AnchorPoint', Vector2.new(0.5, 0.5))
			stuff.rawrbxset(arrow, 'BackgroundTransparency', 1)
			stuff.rawrbxset(arrow, 'Size', UDim2.new(0, 18, 0, 18))
			stuff.rawrbxset(arrow, 'ImageColor3', wp_color)
			stuff.rawrbxset(arrow, 'Image', 'rbxassetid://3926305904')
			stuff.rawrbxset(arrow, 'ImageRectOffset', Vector2.new(524, 763))
			stuff.rawrbxset(arrow, 'ImageRectSize', Vector2.new(36, 36))
			stuff.rawrbxset(arrow, 'ResampleMode', Enum.ResamplerMode.Pixelated)
			stuff.rawrbxset(arrow, 'ZIndex', 2)
			stuff.rawrbxset(arrow, 'Visible', false)
			stuff.rawrbxset(arrow, 'Parent', gui)

			local arrow_dist = Instance.new('TextLabel')
			stuff.rawrbxset(arrow_dist, 'Name', 'distance')
			stuff.rawrbxset(arrow_dist, 'AnchorPoint', Vector2.new(0.5, 0))
			stuff.rawrbxset(arrow_dist, 'Size', UDim2.new(0, 60, 0, 11))
			stuff.rawrbxset(arrow_dist, 'Position', UDim2.new(0.5, 0, 1, 2))
			stuff.rawrbxset(arrow_dist, 'BackgroundTransparency', 1)
			stuff.rawrbxset(arrow_dist, 'BorderSizePixel', 0)
			stuff.rawrbxset(arrow_dist, 'Text', '')
			stuff.rawrbxset(arrow_dist, 'TextColor3', wp_color)
			stuff.rawrbxset(arrow_dist, 'TextStrokeColor3', Color3.new(0, 0, 0))
			stuff.rawrbxset(arrow_dist, 'TextStrokeTransparency', 0.4)
			stuff.rawrbxset(arrow_dist, 'Font', Enum.Font.Code)
			stuff.rawrbxset(arrow_dist, 'TextSize', 10)
			stuff.rawrbxset(arrow_dist, 'ZIndex', 2)
			stuff.rawrbxset(arrow_dist, 'Parent', arrow)

			vstorage.arrows[n] = arrow
		end

		maid.add('waypoint_esp', services.run_service.RenderStepped, function()
			if not vstorage.esp_enabled then return end

			local camera = stuff.rawrbxget(workspace, 'CurrentCamera')
			local viewport = camera.ViewportSize
			local cx = viewport.X / 2
			local cy = viewport.Y / 2
			local pad = 28

			local owner_hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
			local owner_pos = owner_hrp and stuff.rawrbxget(owner_hrp, 'Position')

			for n, wp in vstorage.waypoints do
				local marker = vstorage.markers[n]
				local arrow = vstorage.arrows[n]

				if not marker or not arrow then continue end

				local wp_pos = wp.position + Vector3.new(0, 3, 0)
				local screen_pos, on_screen = camera:WorldToViewportPoint(wp_pos)

				local dist_str = owner_pos and (tostring(math.floor((owner_pos - wp.position).Magnitude)) .. "m") or ''

				if on_screen and screen_pos.Z > 0 then
					stuff.rawrbxset(marker, 'Visible', true)
					stuff.rawrbxset(marker, 'Position', UDim2.new(0, screen_pos.X, 0, screen_pos.Y))
					stuff.rawrbxset(arrow, 'Visible', false)

					local dl = marker:FindFirstChild('dist_label')
					if dl then
						stuff.rawrbxset(dl, 'Text', dist_str)
					end
				else
					stuff.rawrbxset(marker, 'Visible', false)
					stuff.rawrbxset(arrow, 'Visible', true)

					local dir = (wp_pos - camera.CFrame.Position).Unit
					local screen_dir = Vector2.new(
						dir:Dot(camera.CFrame.RightVector),
						-dir:Dot(camera.CFrame.UpVector)
					).Unit

					local scale = math.min(
						(cx - pad) / math.max(math.abs(screen_dir.X), 0.0001),
						(cy - pad) / math.max(math.abs(screen_dir.Y), 0.0001)
					)

					local ax = cx + screen_dir.X * scale
					local ay = cy + screen_dir.Y * scale
					local angle = math.deg(math.atan2(screen_dir.Y, screen_dir.X)) + 90

					stuff.rawrbxset(arrow, 'Position', UDim2.new(0, ax, 0, ay))
					stuff.rawrbxset(arrow, 'Rotation', angle)

					local adl = arrow:FindFirstChild('distance')
					if adl then
						stuff.rawrbxset(adl, 'Text', dist_str)
						stuff.rawrbxset(adl, 'Rotation', -angle)
					end
				end
			end
		end)

		notify('waypoint', 'waypoint esp enabled for ' .. tostring(count) .. ' waypoint(s)', 1)

	elseif action == 'noesp' or action == 'hide' then
		if not vstorage.esp_enabled then
			return notify('waypoint', 'waypoint esp is not enabled', 2)
		end

		vstorage.esp_enabled = false
		maid.remove('waypoint_esp')

		for n, marker in vstorage.markers do
			pcall(stuff.destroy, marker)
		end

		for n, arrow in vstorage.arrows do
			pcall(stuff.destroy, arrow)
		end

		vstorage.markers = {}
		vstorage.arrows = {}

		if vstorage.gui then
			pcall(stuff.destroy, vstorage.gui)
			vstorage.gui = nil
		end

		notify('waypoint', 'waypoint esp disabled', 1)

	else
		notify('waypoint', ("unknown action \"" .. tostring(action) .. "\" | actions: add, del, go, list, clear, esp, noesp, save, load"), 2)
	end
end)

cmd_library.add({'partwalkfling', 'pwalkfling', 'partwalkf', 'pwalkf', 'pwf'}, 'partfling on walkfling', {
	{'player', 'player'},
	{'torso_mode', 'boolean'},
	{'orbit_closer', 'boolean'},
}, function(vstorage, targets, torso_mode,orbit_closer)
	if not targets or #targets == 0 then
		targets = {stuff.owner}
	end

	notify('partwalkfling', 'fetching all parts, your character will be reset', 1)

	for _, target in targets do
		local hrp = stuff.rawrbxget(stuff.owner_char, 'HumanoidRootPart')
		local old_cframe = stuff.rawrbxget(hrp, 'CFrame')
		local cam = stuff.rawrbxget(workspace, 'CurrentCamera')

		local humanoid = stuff.rawrbxget(stuff.owner_char, 'Humanoid')
		humanoid:ChangeState(15)
		stuff.rawrbxset(stuff.owner, 'SimulationRadius', 1000)
		task.wait(services.players.RespawnTime + 0.5)

		if not target.Character or not target.Character:FindFirstChild('HumanoidRootPart') then
			notify('partwalkfling', (tostring(target.Name) .. " has no character"), 2)
			continue
		end

		local target_hrp = stuff.rawrbxget(target.Character, 'HumanoidRootPart')
		stuff.rawrbxset(stuff.owner, 'SimulationRadius', 1000)
		local new_hrp = stuff.rawrbxget(stuff.owner_char, 'HumanoidRootPart')
		stuff.rawrbxset(new_hrp, 'CFrame', old_cframe)
		stuff.rawrbxset(workspace, 'CurrentCamera', cam)
		task.wait(0.2)

		local r = false
		maid.add('partwalkfling_died', target.Character.Humanoid.Died, function()
			if r then return end
			r = true
			cmd_library.execute('unpartwalkfling')
		end)

		maid.add('partwalkfling_char_added', target.CharacterAdded, function()
			if r then return end
			r = true
			cmd_library.execute('unpartwalkfling')
		end)

		local parts = {}
		local cycle_duration = 3
		local distance = 18
		if orbit_closer == true then
			distance = 8
		end
		local cycle_progress = 0

		local is_player_part = function(part)
			for _, plr in services.players:GetPlayers() do
				if plr.Character and plr.Character:IsAncestorOf(part) then
					return true
				end
			end
			return false
		end

		local is_part = function(part)
			local anchored = stuff.rawrbxget(part, 'Anchored')
			if anchored or is_player_part(part) or part:IsDescendantOf(stuff.owner_char) then
				return false
			end
			if part.Parent ~= workspace and (part.Parent:FindFirstChildOfClass('Humanoid') or part.Parent.Parent and part.Parent.Parent:FindFirstChildOfClass('Humanoid')) then
				return false
			end
			return #part:GetConnectedParts() < 2
		end

		for _, part in workspace:GetDescendants() do
			if part:IsA('BasePart') and is_part(part) then
				table.insert(parts, part)
			end
		end

		local desc_added_conn = workspace.DescendantAdded:Connect(function(part)
			if part:IsA('BasePart') and is_part(part) then
				table.insert(parts, part)
			end
		end)

		vstorage.partwalkfling_conn = desc_added_conn

		task.wait(1)

		maid.add('part_walkfling_'..target.Name, services.run_service.Heartbeat, function(dt)
			if not target.Character or not target_hrp:IsDescendantOf(workspace) or not target:IsDescendantOf(game) then
				maid.remove('part_walkfling_'..target.Name)
				desc_added_conn:Disconnect()
				return
			end

			for i = #parts, 1, -1 do
				local part = parts[i]

				if not part:IsDescendantOf(game) then
					table.remove(parts, i)
					continue
				end

				pcall(function()
					if part.ReceiveAge ~= 0 then return end
					local anchored = stuff.rawrbxget(part, 'Anchored')
					if anchored then return end

					stuff.rawrbxset(part, 'CanCollide', false)
					stuff.rawrbxset(part, 'Velocity', Vector3.new(0, 500000000000, 0))

					local target_hrp_pos = stuff.rawrbxget(target_hrp, 'Position')

					if not torso_mode then
						cycle_progress = (cycle_progress + dt / cycle_duration) % 1
						local alpha = 2 * math.pi * cycle_progress
						stuff.rawrbxset(part, 'CFrame', CFrame.Angles(0, alpha, 0) * CFrame.new(0, 0, distance + part.Size.Magnitude) + target_hrp_pos)
					else
						if target == stuff.owner then
							stuff.rawrbxset(part, 'CFrame', stuff.rawrbxget(target_hrp, 'CFrame'))
						else
							local humanoid = stuff.rawrbxget(stuff.owner_char, 'Humanoid')
							if humanoid then
								humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, false)
								stuff.rawrbxset(humanoid, 'Sit', true)
							end
							local target_hrp_cf = stuff.rawrbxget(target_hrp, 'CFrame')
							local offset_cframe = target_hrp_cf * CFrame.new(0, 0, -(17 + part.Size.Magnitude))
							stuff.rawrbxset(part, 'CFrame', offset_cframe)
							stuff.owner_char:PivotTo(offset_cframe)
						end
					end
				end)
			end
		end)
	end
end)

cmd_library.add({'unpartwalkfling', 'unpwalkfling', 'unpartwalkf', 'unpwalkf', 'unpwf'}, 'stop partwalkfling', {}, function(vstorage)
	for _, player in services.players:GetPlayers() do
		maid.remove('part_walkfling_'..player.Name)
	end

	maid.remove('partwalkfling_died')
	maid.remove('partwalkfling_char_added')

	if vstorage.partwalkfling_conn then
		vstorage.partwalkfling_conn:Disconnect()
		vstorage.partwalkfling_conn = nil
	end

	notify('unpartwalkfling', 'partwalkfling stopped', 1)
end)


cmd_library.add({'fullbright', 'fb'}, 'removes darkness', {}, function(vstorage)
	vstorage.enabled = not vstorage.enabled

	if vstorage.enabled then
		notify('fullbright', 'fullbright enabled', 1)

		vstorage.original_ambient = stuff.rawrbxget(services.lighting, 'Ambient')
		vstorage.original_brightness = stuff.rawrbxget(services.lighting, 'Brightness')
		vstorage.original_outdoor_ambient = stuff.rawrbxget(services.lighting, 'OutdoorAmbient')

		stuff.rawrbxset(services.lighting, 'Ambient', Color3.new(1, 1, 1))
		stuff.rawrbxset(services.lighting, 'Brightness', 2)
		stuff.rawrbxset(services.lighting, 'OutdoorAmbient', Color3.new(1, 1, 1))

		maid.add('fullbright', services.lighting.ChildAdded, function(child)
			if vstorage.enabled then
				if child:IsA('BloomEffect') or child:IsA('BlurEffect') or child:IsA('ColorCorrectionEffect') or child:IsA('SunRaysEffect') then
					stuff.rawrbxset(child, 'Enabled', false)
				end
			end
		end)

		for _, effect in services.lighting:GetChildren() do
			if effect:IsA('BloomEffect') or effect:IsA('BlurEffect') or effect:IsA('ColorCorrectionEffect') or effect:IsA('SunRaysEffect') then
				stuff.rawrbxset(effect, 'Enabled', false)
			end
		end
	else
		notify('fullbright', 'fullbright disabled', 1)
		maid.remove('fullbright')

		stuff.rawrbxset(services.lighting, 'Ambient', vstorage.original_ambient)
		stuff.rawrbxset(services.lighting, 'Brightness', vstorage.original_brightness)
		stuff.rawrbxset(services.lighting, 'OutdoorAmbient', vstorage.original_outdoor_ambient)
	end
end)

cmd_library.add({'setuiasset', 'uiasset'}, 'change the ui asset id', {{'asset_id', 'string'}}, function(storage, asset_id)
	if not asset_id then
		notify('config', 'please provide an asset id', 3)
		return
	end

	if tonumber(asset_id) then
		asset_id = 'rbxassetid://' .. asset_id
	elseif not asset_id:match('^rbxassetid://') then
		asset_id = 'rbxassetid://' .. asset_id:gsub('%D', '')
	end

	local success, result = pcall(function()
		return game:GetObjects(asset_id)[1]
	end)

	if success and result then
		config.set('ui_asset', asset_id)
		notify('config', ("ui asset set to " .. tostring(asset_id) .. ". new ui will be applied on the next run"), 1)
	else
		notify('config', 'invalid asset id or failed to load', 2)
	end
end)

cmd_library.add({'resetuiasset', 'defaultui'}, 'reset ui asset to default', {}, function(storage)
	config.reset('ui_asset')
	notify('config', 'ui asset reset to default. new ui will be applied on the next run', 2)
end)

cmd_library.add({'getuiasset', 'currentui'}, 'get the current ui asset id', {}, function(storage)
	local asset = config.get('ui_asset') or config.default_settings.ui_asset
	notify('config', ("current ui asset: " .. tostring(asset)), 1)
end)

cmd_library.add({'btracers', 'bullettracers'}, 'enables bullet tracers when shooting', {
	{'color', 'color'},
	{'thickness', 'number'},
	{'duration', 'number'}
}, function(vstorage, color, thickness, duration)
	if vstorage.enabled then
		return notify('btracers', 'already enabled, use unbtracers to disable', 2)
	end

	vstorage.enabled = true
	vstorage.color = color or Color3.fromRGB(176, 126, 215)
	vstorage.thickness = math.clamp(thickness or 0.05, 0.02, 3)
	vstorage.duration = math.clamp(duration or 1, 0.1, 60)
	vstorage.fade_time = .5

	local muzzle_names = {
		'muzzle', 'flash', 'firepoint', 'fire', 'nozzle',
		'barrel', 'tip', 'gunpoint', 'shootpoint', 'muzzleflash',
		'firemuzzle', 'gunfire', 'shootpart'
	}

	local function find_muzzle(tool)
		for _, descendant in tool:GetDescendants() do
			local name_lower = descendant.Name:lower()
			for _, muzzle_name in muzzle_names do
				if name_lower:find(muzzle_name, 1, true) then
					if descendant:IsA('Attachment') then
						return descendant.WorldPosition
					elseif descendant:IsA('BasePart') then
						return descendant.Position
					end
				end
			end
		end
		return nil
	end

	local function get_tool_front(tool)
		local parts = {}
		for _, descendant in tool:GetDescendants() do
			if descendant:IsA('BasePart') then
				table.insert(parts, descendant)
			end
		end

		if #parts == 0 then return nil end

		local camera = workspace.CurrentCamera
		local look_direction = camera.CFrame.LookVector

		local furthest_part = nil
		local furthest_dot = -math.huge

		for _, part in parts do
			local to_part = (part.Position - camera.CFrame.Position).Unit
			local dot = to_part:Dot(look_direction)
			if dot > furthest_dot then
				furthest_dot = dot
				furthest_part = part
			end
		end

		if furthest_part then
			local cf = furthest_part.CFrame
			local size = furthest_part.Size
			return (cf * CFrame.new(0, 0, -size.Z / 2)).Position
		end

		return nil
	end

	local function get_start_position()
		local character = stuff.owner_char
		if not character then return workspace.CurrentCamera.CFrame.Position end

		local tool = character:FindFirstChildOfClass('Tool')
		if not tool then return workspace.CurrentCamera.CFrame.Position end

		local muzzle_pos = find_muzzle(tool)
		if muzzle_pos then return muzzle_pos end

		local front_pos = get_tool_front(tool)
		if front_pos then return front_pos end

		return workspace.CurrentCamera.CFrame.Position
	end

	local function trace(start_pos, end_pos)
		local distance = (end_pos - start_pos).Magnitude
		if distance < 0.1 then return end

		local cylinder = Instance.new('Part')
		cylinder.Name = 'tracer'
		cylinder.Shape = Enum.PartType.Cylinder
		cylinder.Material = Enum.Material.Neon
		cylinder.Color = vstorage.color
		cylinder.Size = Vector3.new(distance, vstorage.thickness, vstorage.thickness)
		cylinder.Anchored = true
		cylinder.CanCollide = false
		cylinder.CastShadow = false
		cylinder.Transparency = 0

		local midpoint = (start_pos + end_pos) / 2
		cylinder.CFrame = CFrame.lookAt(midpoint, end_pos) * CFrame.Angles(0, math.rad(90), 0)
		cylinder.Parent = workspace.Terrain

		local highlight = Instance.new('Highlight')
		local h, s, v = vstorage.color:ToHSV()
		highlight.FillColor = Color3.fromHSV(h, s, v * 0.5)
		highlight.FillTransparency = 0
		highlight.OutlineTransparency = 1
		highlight.DepthMode = Enum.HighlightDepthMode.Occluded
		highlight.Adornee = cylinder
		highlight.Parent = services.core_gui

		task.delay(vstorage.duration, function()
			local tween_info = TweenInfo.new(vstorage.fade_time, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
			local tween = services.tween_service:Create(cylinder, tween_info, {
				Size = Vector3.new(distance, 0, 0)
			})

			tween:Play()

			tween.Completed:Once(function()
				stuff.destroy(cylinder)
				stuff.destroy(highlight)
			end)
		end)
	end

	local function on_click()
		if not vstorage.enabled then return end

		local character = stuff.owner_char
		if not character then return end

		local camera = workspace.CurrentCamera
		local mouse_location = services.user_input_service:GetMouseLocation()
		local ray = camera:ViewportPointToRay(mouse_location.X, mouse_location.Y)

		local params = RaycastParams.new()
		params.FilterDescendantsInstances = {character}
		params.FilterType = Enum.RaycastFilterType.Exclude
		params.IgnoreWater = true

		local start_pos = get_start_position()
		local result = workspace:Raycast(ray.Origin, ray.Direction * 1000, params)
		local end_pos = result and result.Position or (ray.Origin + ray.Direction * 500)

		task.spawn(trace, start_pos, end_pos)
	end

	maid.add('btracers_click', stuff.owner:GetMouse().Button1Down, on_click)

	notify('btracers', ("enabled | thickness: " .. tostring(vstorage.thickness) .. " | duration: " .. tostring(vstorage.duration) .. "s"), 1)
end)

cmd_library.add({'unbtracers', 'unbullettracers', 'untracers'}, 'disables bullet tracers', {}, function(vstorage)
	if not vstorage.enabled then
		return notify('btracers', 'not enabled', 2)
	end

	vstorage.enabled = false
	maid.remove('btracers_click')

	for _, part in workspace:GetChildren() do
		if part.Name == 'BulletTracer' then
			part:Destroy()
		end
	end

	notify('btracers', 'disabled', 1)
end)

cmd_library.add({'hitsound', 'hitmarker', 'hs'}, 'plays a sound when hitting a player', {
	{'sound_id', 'string'},
	{'volume', 'number'},
	{'pitch', 'number'}
}, function(vstorage, sound_id, volume, pitch)
	if vstorage.enabled then
		return notify('hitsound', 'already enabled, use unhitsound to disable', 2)
	end

	vstorage.enabled = true
	vstorage.sound_id = sound_id or 'rbxassetid://97643101798871'
	vstorage.volume = math.clamp(volume or 3, 0.1, 2)
	vstorage.pitch = math.clamp(pitch or 1, 0.5, 2)

	local function is_player_part(part)
		if not part then return false end

		local character = part:FindFirstAncestorOfClass('Model')
		if not character then return false end

		local humanoid = character:FindFirstChildOfClass('Humanoid')
		if not humanoid then return false end

		local player = services.players:GetPlayerFromCharacter(character)
		if not player then return false end

		if player == stuff.owner then return false end

		return true, player
	end

	local function play_hit_sound()
		local sound = Instance.new('Sound')
		sound.SoundId = vstorage.sound_id
		sound.Volume = vstorage.volume
		sound.PlaybackSpeed = vstorage.pitch * (0.95 + math.random() * 0.1)
		sound.Parent = services.sound_service
		sound.PlayOnRemove = true
		pcall(stuff.destroy, sound)
	end

	local function on_click()
		if not vstorage.enabled then return end

		local character = stuff.owner_char
		if not character then return end

		local camera = workspace.CurrentCamera
		local mouse_location = services.user_input_service:GetMouseLocation()
		local ray = camera:ViewportPointToRay(mouse_location.X, mouse_location.Y)

		local params = RaycastParams.new()
		params.FilterDescendantsInstances = {character}
		params.FilterType = Enum.RaycastFilterType.Exclude
		params.IgnoreWater = true

		local result = workspace:Raycast(ray.Origin, ray.Direction * 1000, params)

		if result and result.Instance then
			local hit, player = is_player_part(result.Instance)
			if hit then
				play_hit_sound()
			end
		end
	end

	maid.add('hitsound_click', stuff.owner:GetMouse().Button1Down, on_click)

	notify('hitsound', ("enabled | sound: " .. tostring(vstorage.sound_id) .. " | volume: " .. tostring(vstorage.volume) .. " | pitch: " .. tostring(vstorage.pitch)), 1)
end)

cmd_library.add({'unhitsound', 'unhitmarker', 'unhs'}, 'disables hit sound', {}, function(vstorage)
	if not vstorage.enabled then
		return notify('hitsound', 'not enabled', 2)
	end

	vstorage.enabled = false
	maid.remove('hitsound_click')

	notify('hitsound', 'disabled', 1)
end)

cmd_library.add({'xray'}, 'makes walls transparent', {
	{'transparency', 'number'}
}, function(vstorage)
	vstorage.enabled = not vstorage.enabled

	if vstorage.enabled then
		vstorage.original_transparency = {}
		notify('xray', 'xray enabled', 1)

		for _, part in workspace:GetDescendants() do
			if part:IsA('BasePart') and not part:IsDescendantOf(stuff.owner.Character) and part.Transparency < 1 then
				vstorage.original_transparency[part] = stuff.rawrbxget(part, 'Transparency')
				stuff.rawrbxset(part, 'Transparency', 0.7)
			end
		end

		maid.add('xray_descendant', workspace.DescendantAdded, function(descendant)
			if vstorage.enabled and descendant:IsA('BasePart') and not descendant:IsDescendantOf(stuff.owner.Character) then
				task.wait()
				if descendant.Transparency < 1 then
					vstorage.original_transparency[descendant] = stuff.rawrbxget(descendant, 'Transparency')
					stuff.rawrbxset(descendant, 'Transparency', 0.7)
				end
			end
		end)
	else
		notify('xray', 'xray disabled', 1)
		maid.remove('xray_descendant')

		for part, original_transparency in vstorage.original_transparency or {} do
			if part and part.Parent then
				stuff.rawrbxset(part, 'Transparency', original_transparency)
			end
		end

		vstorage.original_transparency = {}
	end
end)

cmd_library.add({'crosshair', 'cross', 'xhair'}, 'custom crosshair (styles: cross, dot, circle, crossdot, square, diamond)', {
	{'style', 'string'},
	{'size', 'number'},
	{'thickness', 'number'},
	{'gap', 'number'},
	{'color', 'color'},
	{'outline', 'boolean'}
}, function(vstorage, style, size, thickness, gap, color, outline)
	if vstorage.enabled then
		cmd_library.execute('uncrosshair')
	end

	vstorage.enabled = true
	vstorage.style = (style or 'cross'):lower()
	vstorage.size = math.clamp(size or 10, 1, 100)
	vstorage.thickness = math.clamp(thickness or 2, 1, 10)
	vstorage.gap = math.clamp(gap or 4, 0, 50)
	vstorage.color = color or Color3.fromRGB(176, 126, 215)
	vstorage.outline = outline ~= false
	vstorage.drawings = {}

	local valid_styles = {
		cross = true,
		dot = true,
		circle = true,
		crossdot = true,
		square = true,
		triangle = true,
		diamond = true
	}

	if not valid_styles[vstorage.style] then
		vstorage.enabled = false
		return notify('crosshair', ("invalid style '" .. tostring(vstorage.style) .. "'. valid: cross, dot, circle, crossdot, square, diamond"), 2)
	end

	local function line(from, to, is_outline)
		local line = Drawing.new('Line')
		line.From = from
		line.To = to
		line.Thickness = is_outline and vstorage.thickness + 2 or vstorage.thickness
		line.Color = is_outline and Color3.new(0, 0, 0) or vstorage.color
		line.Transparency = is_outline and 0.5 or 1
		line.Visible = true
		table.insert(vstorage.drawings, line)
		return line
	end

	local function circle(pos, radius, filled, is_outline)
		local circle = Drawing.new('Circle')
		circle.Position = pos
		circle.Radius = is_outline and radius + 1 or radius
		circle.Filled = filled
		circle.Thickness = filled and 0 or (is_outline and vstorage.thickness + 2 or vstorage.thickness)
		circle.Color = is_outline and Color3.new(0, 0, 0) or vstorage.color
		circle.Transparency = is_outline and 0.5 or 1
		circle.NumSides = 32
		circle.Visible = true
		table.insert(vstorage.drawings, circle)
		return circle
	end

	local function square(pos, size, filled, is_outline)
		local square = Drawing.new('Square')
		local half = size / 2
		square.Position = Vector2.new(pos.X - half, pos.Y - half)
		square.Size = Vector2.new(size, size)
		square.Filled = filled
		square.Thickness = filled and 0 or (is_outline and vstorage.thickness + 2 or vstorage.thickness)
		square.Color = is_outline and Color3.new(0, 0, 0) or vstorage.color
		square.Transparency = is_outline and 0.5 or 1
		square.Visible = true
		table.insert(vstorage.drawings, square)
		return square
	end

	local function build_crosshair(center)
		for _, drawing in vstorage.drawings do
			if drawing.Remove then drawing:Remove() end
		end
		table.clear(vstorage.drawings)

		if vstorage.style == 'cross' or vstorage.style == 'crossdot' then
			local lines = {
				{Vector2.new(center.X, center.Y - vstorage.gap - vstorage.size), Vector2.new(center.X, center.Y - vstorage.gap)},
				{Vector2.new(center.X, center.Y + vstorage.gap), Vector2.new(center.X, center.Y + vstorage.gap + vstorage.size)},
				{Vector2.new(center.X - vstorage.gap - vstorage.size, center.Y), Vector2.new(center.X - vstorage.gap, center.Y)},
				{Vector2.new(center.X + vstorage.gap, center.Y), Vector2.new(center.X + vstorage.gap + vstorage.size, center.Y)}
			}

			for _, data in lines do
				if vstorage.outline then
					line(data[1], data[2], true)
				end
				line(data[1], data[2], false)
			end

			if vstorage.style == 'crossdot' then
				if vstorage.outline then
					circle(center, vstorage.thickness, true, true)
				end
				circle(center, vstorage.thickness, true, false)
			end

		elseif vstorage.style == 'dot' then
			if vstorage.outline then
				circle(center, vstorage.size / 2, true, true)
			end
			circle(center, vstorage.size / 2, true, false)

		elseif vstorage.style == 'circle' then
			if vstorage.outline then
				circle(center, vstorage.size, false, true)
			end
			circle(center, vstorage.size, false, false)

		elseif vstorage.style == 'square' then
			if vstorage.outline then
				square(center, vstorage.size, false, true)
			end
			square(center, vstorage.size, false, false)

		elseif vstorage.style == 'diamond' then
			local half = vstorage.size / 2
			local points = {
				{Vector2.new(center.X, center.Y - half), Vector2.new(center.X + half, center.Y)},
				{Vector2.new(center.X + half, center.Y), Vector2.new(center.X, center.Y + half)},
				{Vector2.new(center.X, center.Y + half), Vector2.new(center.X - half, center.Y)},
				{Vector2.new(center.X - half, center.Y), Vector2.new(center.X, center.Y - half)}
			}

			for _, data in points do
				if vstorage.outline then
					line(data[1], data[2], true)
				end
				line(data[1], data[2], false)
			end
		end
	end

	vstorage.build = build_crosshair

	local gui_inset = services.gui_service:GetGuiInset()
	local viewport = workspace.CurrentCamera.ViewportSize
	local center = Vector2.new(viewport.X / 2, (viewport.Y / 2) - gui_inset.Y)

	build_crosshair(center)
	vstorage.last_viewport = viewport

	maid.add('crosshair_update', services.run_service.RenderStepped, function()
		if not vstorage.enabled then return end

		local new_viewport = workspace.CurrentCamera.ViewportSize
		if new_viewport ~= vstorage.last_viewport then
			vstorage.last_viewport = new_viewport
			local new_center = Vector2.new(new_viewport.X / 2, (new_viewport.Y / 2) - gui_inset.Y)
			build_crosshair(new_center)
		end
	end)

	notify('crosshair', ("enabled | style: " .. tostring(vstorage.style) .. " | size: " .. tostring(vstorage.size) .. " | gap: " .. tostring(vstorage.gap)), 1)
end)

cmd_library.add({'uncrosshair', 'uncross', 'unxhair'}, 'disables crosshair', {}, function()
	local vs = cmd_library.get_variable_storage('crosshair')
	if not vs or not vs.enabled then
		return notify('crosshair', 'not enabled', 2)
	end

	vs.enabled = false

	for _, drawing in vs.drawings or {} do
		if drawing.Remove then drawing:Remove() end
	end
	table.clear(vs.drawings)

