cmd_library.add({'clientgodmode', 'cgodmode', 'cgod', 'god'}, 'sets your health to NaN', {
	{'bypass_mode', 'boolean'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, bypass, et)
	if et and vstorage.enabled then
		cmd_library.execute('unclientgodmode')
		return
	end

	if vstorage.enabled then
		return notify('clientgodmode', 'godmode already enabled', 2)
	end

	local humanoid = stuff.owner_char:FindFirstChildOfClass('Humanoid')
	if not humanoid then
		return notify('clientgodmode', 'your character doesnt have a humanoid', 2)
	end

	vstorage.enabled = true
	vstorage.bypass = bypass
	vstorage.humanoid = humanoid

	notify('clientgodmode', ("godmode enabled" .. tostring(bypass and ' (bypass)' or '')), 1)

	if bypass then
		local health, maxhealth = humanoid.Health, humanoid.MaxHealth
		hook_lib.create_hook('godmode_bypass', {
			index = function(self, key)
				if self == vstorage.humanoid or (self:IsA('Humanoid') and self:IsDescendantOf(stuff.owner_char)) then
					if key == 'Health' then
						return health
					elseif key == 'MaxHealth' then
						return maxhealth
					end
				end
			end,

			newindex = function(self, key, value)
				if self == vstorage.humanoid or (self:IsA('Humanoid') and self:IsDescendantOf(stuff.owner_char)) then
					if key == 'Health' or key == 'MaxHealth' then
						return false
					end
				end
			end,

			namecall = function(self, ...)
				local method = getnamecallmethod()
				local args = {...}

				if self == vstorage.humanoid or (self:IsA('Humanoid') and self:IsDescendantOf(stuff.owner_char)) then
					if method == 'TakeDamage' then
						return nil
					elseif method == 'ChangeState' then
						if args[1] == Enum.HumanoidStateType.Dead then
							return nil
						end
					elseif method == 'GetPropertyChangedSignal' then
						if args[1] == 'Health' or args[1] == 'MaxHealth' then
							return Instance.new('BindableEvent').Event
						end
					end
				end
			end
		})
	end

	stuff.rawrbxset(humanoid, 'MaxHealth', 0/0)
	stuff.rawrbxset(humanoid, 'Health', 0/0)

	maid.add('godmode', humanoid:GetPropertyChangedSignal('Health'), function()
		local current_health = stuff.rawrbxget(humanoid, 'Health')
		local current_max = stuff.rawrbxget(humanoid, 'MaxHealth')

		if current_health == current_health or current_max == current_max then
			stuff.rawrbxset(humanoid, 'MaxHealth', 0/0)
			stuff.rawrbxset(humanoid, 'Health', 0/0)
		end
	end)

	maid.add('godmode_hum', humanoid.Died, function()
		local new_char = stuff.owner.CharacterAdded:Wait()
		humanoid = new_char:WaitForChild('Humanoid')
		vstorage.humanoid = humanoid

		if vstorage.enabled then
			stuff.rawrbxset(humanoid, 'MaxHealth', 0/0)
			stuff.rawrbxset(humanoid, 'Health', 0/0)

			maid.remove('godmode')
			maid.add('godmode', humanoid:GetPropertyChangedSignal('Health'), function()
				local current_health = stuff.rawrbxget(humanoid, 'Health')
				local current_max = stuff.rawrbxget(humanoid, 'MaxHealth')

				if current_health == current_health or current_max == current_max then
					stuff.rawrbxset(humanoid, 'MaxHealth', 0/0)
					stuff.rawrbxset(humanoid, 'Health', 0/0)
				end
			end)
		end
	end)
end)
cmd_library.add({'unclientgodmode', 'uncgodmode', 'uncgod', 'ungod'}, 'disables client godmode', {}, function(vstorage)
	local vstorage = cmd_library.get_variable_storage('clientgodmode')

	if not vstorage.enabled then
		return notify('clientgodmode', 'godmode not enabled', 2)
	end

	vstorage.enabled = false
	maid.remove('godmode')
	maid.remove('godmode_hum')

	if vstorage.bypass then
		hook_lib.destroy_hook('godmode_bypass')
	end

	if vstorage.humanoid then
		pcall(function()
			stuff.rawrbxset(vstorage.humanoid, 'MaxHealth', 100)
			stuff.rawrbxset(vstorage.humanoid, 'Health', 100)
		end)
	end

	notify('clientgodmode', 'godmode disabled', 1)
end)

cmd_library.add({'seatbring', 'sbring'}, 'bring a player using a seat tool', {
	{'player', 'player'}
}, function(vstorage, targets)
	if not firetouchinterest then
		return notify('seatbring', 'firetouchinterest not found', 2)
	end

	if not targets or #targets == 0 then
		return notify('seatbring', 'player not found', 2)
	end

	for _, target in targets do
		local tool = stuff.owner_char:FindFirstChildOfClass('Tool')

		if not tool then
			notify('seatbring', 'equip a tool and maybe then we\'ll see', 3)
			repeat task.wait() until stuff.owner_char:FindFirstChildOfClass('Tool')
			tool = stuff.owner_char:FindFirstChildOfClass('Tool')
		end

		local seat = tool:FindFirstChildWhichIsA('Seat', true)
		if not seat then
			return notify('seatbring', 'tool does not have a seat', 2)
		end

		notify('seatbring', ("bringing " .. tostring(target.Name) .. " to you"), 1)

		local old_pos = stuff.owner_char:GetPivot()
		local start_time = tick()
		local target_char = target.Character
		if not target_char then
			notify('seatbring', (tostring(target.Name) .. " has no character"), 2)
			continue
		end

		local target_hrp = stuff.rawrbxget(target_char, 'HumanoidRootPart')
		local target_humanoid = stuff.rawrbxget(target_char, 'Humanoid')
		if not target_hrp or not target_humanoid then
			notify('seatbring', (tostring(target.Name) .. " has no humanoid or rootpart"), 2)
			continue
		end

		repeat
			local predicted_pos = predict_position(target, 9)
			if not predicted_pos then break end

			firetouchinterest(seat, target_hrp, 0)
			firetouchinterest(seat, target_hrp, 1)
			stuff.owner_char:PivotTo(predicted_pos * CFrame.new(-4, 0, 3))
			services.run_service.Heartbeat:Wait()

			firetouchinterest(seat, target_hrp, 0)
			firetouchinterest(seat, target_hrp, 1)
			stuff.owner_char:PivotTo(predicted_pos * CFrame.new(4, 0, 3))
			services.run_service.Heartbeat:Wait()
			services.run_service.Heartbeat:Wait()

			local target_sit = stuff.rawrbxget(target_humanoid, 'Sit')
		until tick() - start_time >= 4 or (seat and seat:FindFirstChild('SeatWeld')) or target_sit

		stuff.owner_char:PivotTo(old_pos)
	end
end)


maid.add('owner_chatted', stuff.owner.Chatted, function(msg)
	if msg:sub(1, #(stuff.chat_prefix)) == stuff.chat_prefix then
		local commands = cmd_library.parse_command(msg:sub(#(stuff.chat_prefix) + 1))

		for _, data in commands do
			cmd_library.execute(data.cmd, unpack(data.args))
		end
	end
end, true)


-- UI elements are now built programmatically – always present
local ui_cmdbox        = stuff.ui:FindFirstChild('goosesploit_cmdbox', true)
local ui_cmdlist       = stuff.ui:FindFirstChild('goosesploit_cmdlist', true)
local ui_notifications = stuff.ui:FindFirstChild('goosesploit_notifications', true)
if not ui_cmdbox or not ui_cmdlist or not ui_notifications then
	error('[Goosesploit] Programmatic UI failed to build – goosesploit_cmdbox/cmdlist/notifications missing.')
end

local ui_cmdbox_main_container = ui_cmdbox.main_container
local ui_cmdbox_inputbox       = ui_cmdbox_main_container.inputbox
local ui_cmdbox_button         = ui_cmdbox_main_container.button

local ui_cmdlist_main_container  = ui_cmdlist.main_container
local ui_cmdlist_search          = ui_cmdlist_main_container:FindFirstChild('search', true)
local ui_cmdlist_close           = ui_cmdlist_main_container:FindFirstChild('close', true)
local ui_cmdlist_commandlist     = ui_cmdlist_main_container:FindFirstChild('commands', true)
local ui_cmdlist_template        = ui_cmdlist_commandlist and ui_cmdlist_commandlist:FindFirstChild('template', true)

local ui_notifications_main_container = ui_notifications.main_container
local ui_notifications_template       = ui_notifications_main_container:FindFirstChild('template')
	or ui_notifications_main_container:WaitForChild('template', 5)

ui_cmdlist_template.Parent    = nil
ui_notifications_template.Parent = nil

local tween_ui = function(element, duration, properties, out)
	services.tween_service:Create(element, TweenInfo.new(duration, Enum.EasingStyle.Sine,
		out and Enum.EasingDirection.Out or Enum.EasingDirection.In), properties):Play()
end

do
	local IS_MOB  = stuff.is_mobile
	local open    = false
	local pos_open   = ui_cmdbox_main_container.Position
	-- hide off top of screen initially
	local pos_closed = IS_MOB
		and UDim2.new(pos_open.X.Scale, pos_open.X.Offset, 1, 60) -- slides off bottom on mobile
		or  UDim2.new(0.5, 0, 0, -50)

	ui_cmdbox_button.Visible = false
	ui_cmdbox_main_container.Position = pos_closed -- start hidden

	-- ── parent the cmdbox ScreenGui ──────────────────────────────────────
	pcall(function() ui_cmdbox.Parent = services.core_gui end)
	if not ui_cmdbox.Parent or ui_cmdbox.Parent == stuff.ui then
		ui_cmdbox.Parent = services.players.LocalPlayer.PlayerGui
	end

	-- ── MOBILE BOTTOM BAR + TOGGLE ───────────────────────────────────────
	-- On mobile: a full-width bottom bar with a toggle button + inline cmd box.
	-- On desktop: a small draggable pill button on the left edge.
	local toggle_gui = Instance.new('ScreenGui')
	toggle_gui.Name           = 'GoosesploitToggle'
	toggle_gui.ResetOnSpawn   = false
	toggle_gui.DisplayOrder   = 998
	toggle_gui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
	pcall(function() toggle_gui.Parent = services.core_gui end)
	if not toggle_gui.Parent or toggle_gui.Parent == stuff.ui then
		toggle_gui.Parent = services.players.LocalPlayer.PlayerGui
	end

	local ACCENT = Color3.fromRGB(88, 101, 242)
	local BG     = Color3.fromRGB(18, 18, 22)
	local TEXT   = Color3.fromRGB(230, 230, 240)
	local MUTED  = Color3.fromRGB(100, 100, 120)

	local toggle_btn  -- forward-declare for set_open closure

	if IS_MOB then
		-- ── Mobile: fixed bottom bar spanning full width ─────────────────
		local BAR_H = 52
		local bar = Instance.new('Frame')
		bar.Name             = 'mobile_bar'
		bar.Size             = UDim2.new(1, 0, 0, BAR_H)
		bar.Position         = UDim2.new(0, 0, 1, -BAR_H)
		bar.BackgroundColor3 = BG
		bar.BorderSizePixel  = 0
		bar.Active           = true
		bar.Parent           = toggle_gui

		local bar_stroke = Instance.new('UIStroke')
		bar_stroke.Color     = ACCENT
		bar_stroke.Thickness = 1
		bar_stroke.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
		bar_stroke.Parent    = bar

		-- Goose icon / label
		local icon = Instance.new('TextLabel')
		icon.Size                = UDim2.new(0, 44, 1, 0)
		icon.Position            = UDim2.new(0, 0, 0, 0)
		icon.BackgroundTransparency = 1
		icon.Text                = '🪿'
		icon.TextSize            = 22
		icon.Font                = Enum.Font.Gotham
		icon.TextColor3          = TEXT
		icon.Parent              = bar

		-- Inline cmd input (shown when open)
		local mob_input = Instance.new('TextBox')
		mob_input.Name                = 'mob_input'
		mob_input.Size                = UDim2.new(1, -120, 1, -10)
		mob_input.Position            = UDim2.new(0, 44, 0, 5)
		mob_input.BackgroundColor3    = Color3.fromRGB(26, 26, 32)
		mob_input.BorderSizePixel     = 0
		mob_input.PlaceholderText     = 'type command + press ↵'
		mob_input.Text                = ''
		mob_input.Font                = Enum.Font.Gotham
		mob_input.TextSize            = 15
		mob_input.TextColor3          = TEXT
		mob_input.PlaceholderColor3   = MUTED
		mob_input.TextXAlignment      = Enum.TextXAlignment.Left
		mob_input.ClearTextOnFocus    = false
		mob_input.Visible             = false
		mob_input.Parent              = bar
		local mob_input_corner = Instance.new('UICorner')
		mob_input_corner.CornerRadius = UDim.new(0, 8)
		mob_input_corner.Parent       = mob_input
		local mob_input_pad = Instance.new('UIPadding')
		mob_input_pad.PaddingLeft     = UDim.new(0, 8)
		mob_input_pad.Parent          = mob_input

		-- Run button (shown when open)
		local mob_run = Instance.new('TextButton')
		mob_run.Name              = 'mob_run'
		mob_run.Size              = UDim2.new(0, 52, 0, BAR_H - 10)
		mob_run.Position          = UDim2.new(1, -56, 0, 5)
		mob_run.BackgroundColor3  = ACCENT
		mob_run.BorderSizePixel   = 0
		mob_run.Text              = '▶'
		mob_run.Font              = Enum.Font.GothamBold
		mob_run.TextSize          = 15
		mob_run.TextColor3        = Color3.fromRGB(255, 255, 255)
		mob_run.Visible           = false
		mob_run.Parent            = bar
		local mob_run_corner = Instance.new('UICorner')
		mob_run_corner.CornerRadius = UDim.new(0, 8)
		mob_run_corner.Parent       = mob_run

		-- Toggle button
		toggle_btn = Instance.new('TextButton')
		toggle_btn.Name              = 'toggle_btn'
		toggle_btn.Size              = UDim2.new(0, 68, 1, -10)
		toggle_btn.Position          = UDim2.new(1, -72, 0, 5)
		toggle_btn.BackgroundColor3  = BG
		toggle_btn.BorderSizePixel   = 0
		toggle_btn.Text              = 'CMD'
		toggle_btn.Font              = Enum.Font.GothamBold
		toggle_btn.TextSize          = 14
		toggle_btn.TextColor3        = TEXT
		toggle_btn.Parent            = bar
		local tb_corner = Instance.new('UICorner')
		tb_corner.CornerRadius = UDim.new(0, 8)
		tb_corner.Parent       = toggle_btn
		local tb_stroke = Instance.new('UIStroke')
		tb_stroke.Color     = ACCENT
		tb_stroke.Thickness = 1.5
		tb_stroke.Parent    = toggle_btn

		local function exec_mob_input()
			local text = mob_input.Text
			if text ~= '' then
				local commands = cmd_library.parse_command(text)
				for _, data in commands do
					cmd_library.execute(data.cmd, unpack(data.args))
				end
				mob_input.Text = ''
			end
		end

		mob_run.MouseButton1Click:Connect(exec_mob_input)
		mob_input.FocusLost:Connect(function(enter)
			if enter then exec_mob_input() end
		end)

		toggle_btn.MouseButton1Click:Connect(function()
			open = not open
			mob_input.Visible  = open
			mob_run.Visible    = open
			toggle_btn.Size    = open
				and UDim2.new(0, 52, 1, -10)
				or  UDim2.new(0, 68, 1, -10)
			toggle_btn.Position = open
				and UDim2.new(1, -56, 0, 5)
				or  UDim2.new(1, -72, 0, 5)
			toggle_btn.Text    = open and '✕' or 'CMD'
			toggle_btn.BackgroundColor3 = open and ACCENT or BG
			if open then
				task.defer(function() mob_input:CaptureFocus() end)
			end
		end)

	else
		-- ── Desktop: small draggable pill on the left edge ────────────────
		local BTN_W, BTN_H = 72, 28

		local toggle_frame = Instance.new('Frame')
		toggle_frame.Name             = 'toggle_frame'
		toggle_frame.Size             = UDim2.new(0, BTN_W, 0, BTN_H)
		toggle_frame.Position         = UDim2.new(0, 8, 0.5, -BTN_H/2)
		toggle_frame.BackgroundColor3 = BG
		toggle_frame.BorderSizePixel  = 0
		toggle_frame.Active           = true
		toggle_frame.Parent           = toggle_gui
		local tf_corner = Instance.new('UICorner')
		tf_corner.CornerRadius = UDim.new(0, 7)
		tf_corner.Parent       = toggle_frame
		local tf_stroke = Instance.new('UIStroke')
		tf_stroke.Color     = ACCENT
		tf_stroke.Thickness = 1.5
		tf_stroke.Parent    = toggle_frame

		local icon_lbl = Instance.new('TextLabel')
		icon_lbl.Size                = UDim2.new(0, BTN_H, 1, 0)
		icon_lbl.BackgroundTransparency = 1
		icon_lbl.Text                = '🪿'
		icon_lbl.TextSize            = 13
		icon_lbl.Font                = Enum.Font.Gotham
		icon_lbl.TextColor3          = TEXT
		icon_lbl.Parent              = toggle_frame

		toggle_btn = Instance.new('TextButton')
		toggle_btn.Name              = 'toggle_btn'
		toggle_btn.Size              = UDim2.new(1, -BTN_H, 1, 0)
		toggle_btn.Position          = UDim2.new(0, BTN_H, 0, 0)
		toggle_btn.BackgroundTransparency = 1
		toggle_btn.Text              = 'open'
		toggle_btn.Font              = Enum.Font.GothamBold
		toggle_btn.TextSize          = 11
		toggle_btn.TextColor3        = TEXT
		toggle_btn.Parent            = toggle_frame

		-- Drag
		do
			local dragging, drag_start, start_pos = false, nil, nil
			toggle_frame.InputBegan:Connect(function(inp)
				if inp.UserInputType == Enum.UserInputType.MouseButton1
					or inp.UserInputType == Enum.UserInputType.Touch then
					dragging = true; drag_start = inp.Position; start_pos = toggle_frame.Position
				end
			end)
			services.user_input_service.InputChanged:Connect(function(inp)
				if dragging and (inp.UserInputType == Enum.UserInputType.MouseMovement
					or inp.UserInputType == Enum.UserInputType.Touch) then
					local d = inp.Position - drag_start
					local vp = workspace.CurrentCamera.ViewportSize
					toggle_frame.Position = UDim2.new(0,
						math.clamp(start_pos.X.Offset + d.X, 0, vp.X - BTN_W), 0,
						math.clamp(start_pos.Y.Offset + d.Y, 0, vp.Y - BTN_H))
				end
			end)
			services.user_input_service.InputEnded:Connect(function(inp)
				if inp.UserInputType == Enum.UserInputType.MouseButton1
					or inp.UserInputType == Enum.UserInputType.Touch then
					dragging = false
				end
			end)
		end

		local function set_open(state)
			open = state
			tween_ui(ui_cmdbox_main_container, 0.15, {Position = open and pos_open or pos_closed}, open)
			toggle_btn.Text               = open and 'close' or 'open'
			toggle_frame.BackgroundColor3 = open and ACCENT or BG
			if open then task.defer(function() ui_cmdbox_inputbox:CaptureFocus() end) end
		end

		toggle_btn.MouseButton1Click:Connect(function() set_open(not open) end)

		stuff.update_keybind = function()
			maid.add('open_cmdbox_key', services.user_input_service.InputBegan, function(input, gp)
				if input.KeyCode == stuff.open_keybind and not gp then
					set_open(not open)
					task.delay(.05, function()
						if open and ui_cmdbox_inputbox.Text ~= '' then
							repeat ui_cmdbox_inputbox.Text = '' hwait()
							until ui_cmdbox_inputbox.Text == ''
						end
					end)
				end
			end, true)
		end
		stuff.update_keybind()

		maid.add('cmdbox_focuslost', ui_cmdbox_inputbox.FocusLost, function(enter)
			tween_ui(ui_cmdbox_main_container, 0.15, {Position = pos_closed}, false)
			open = false
			toggle_btn.Text               = 'open'
			toggle_frame.BackgroundColor3 = BG
			if enter then
				local text = ui_cmdbox_inputbox.Text
				local commands = cmd_library.parse_command(text)
				for _, data in commands do
					cmd_library.execute(data.cmd, unpack(data.args))
				end
			end
			ui_cmdbox_inputbox.Text = ''
		end, true)
	end

	pcall(protect_gui, ui_cmdbox)
	pcall(protect_gui, toggle_gui)
end

do
	maid.add('cmdlist_close', ui_cmdlist_close.MouseButton1Click, function()
		ui_cmdlist.Enabled = false
	end, true)

	maid.add('cmdlist_search', ui_cmdlist_search:GetPropertyChangedSignal('Text'), function()
		local search_text = ui_cmdlist_search.Text:lower()
		ui_cmdlist_commandlist.CanvasPosition = Vector2.zero
		for _, label in ui_cmdlist_commandlist:GetChildren() do
			if label:IsA('TextLabel') and label ~= stuff.ui_cmdlist_template then
				if search_text == '' then
					label.Visible = true
				else
					local text = label.Text:lower()

					local names_part = text:match('^%s*(.-)%s*%[') or text:match('^%s*(.-)%s*%-')

					if names_part then
						local found = false
						for name in names_part:gmatch('[^,]+') do
							local trimmed_name = name:gsub('^%s*(.-)%s*$', '%1')
							if trimmed_name:find(search_text, 1, true) then
								found = true
								break
							end
						end
						label.Visible = found
					else
						label.Visible = false
					end
				end
			end
		end
	end, true)

	maid.add('command_search_focus', ui_cmdlist_search.Focused, function()
		ui_cmdlist_search.PlaceholderText = 'type to search...'
	end, true)

	maid.add('command_search_unfocus', ui_cmdlist_search.FocusLost, function()
		if ui_cmdlist_search.Text == '' then
			ui_cmdlist_search.PlaceholderText = 'search commands'
		end
	end, true)

	ui_cmdlist.Enabled = false
	pcall(protect_gui, ui_cmdlist)
	stuff.ui_cmdlist = ui_cmdlist
	stuff.ui_cmdlist_template = ui_cmdlist_template
	stuff.ui_cmdlist_commandlist = ui_cmdlist_commandlist
end

pcall(protect_gui, ui_notifications)
stuff.ui_notifications_template = ui_notifications_template
stuff.ui_notifications_main_container = ui_notifications_main_container

xpcall(config.apply, function(err)
	warn(debug.traceback(err, 2))
	notify('config', 'an error occured while applying config: ' .. tostring(err) .. ' | check console for full error', 2)
end)

cmd_library.add({'kill', 'slay'}, 'breaks your character joints (client-side)', {
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, et)
	local char = stuff.owner_char
	if not char then return notify('kill', 'no character', 2) end
	local hum = char:FindFirstChildOfClass('Humanoid')
	if hum then
		hum.Health = 0
	else
		char:BreakJoints()
	end
	notify('kill', 'you died', 1)
end)

cmd_library.add({'loopkill', 'lk'}, 'repeatedly kills your character', {
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, et)
	if et and vstorage.enabled then
		cmd_library.execute('unloopkill')
		return
	end
	if vstorage.enabled then return notify('loopkill', 'already looping', 2) end
	vstorage.enabled = true
	notify('loopkill', 'loop kill enabled', 1)
	maid.add('loopkill', services.run_service.Heartbeat, function()
		if not vstorage.enabled then return end
		local char = stuff.owner_char
		if char then
			local hum = char:FindFirstChildOfClass('Humanoid')
			if hum and hum.Health > 0 then hum.Health = 0 end
		end
	end)
end)

cmd_library.add({'unloopkill', 'unlk'}, 'stops loop kill', {}, function()
	local vs = cmd_library.get_variable_storage('loopkill')
	vs.enabled = false
	maid.remove('loopkill')
	notify('loopkill', 'loop kill disabled', 1)
end)

cmd_library.add({'heal', 'hp'}, 'restores your health to full', {}, function()
	local hum = stuff.owner_char and stuff.owner_char:FindFirstChildOfClass('Humanoid')
	if not hum then return notify('heal', 'no humanoid', 2) end
	stuff.rawrbxset(hum, 'Health', hum.MaxHealth)
	notify('heal', 'healed to full HP', 1)
end)

cmd_library.add({'loopheal', 'lheal'}, 'continuously heals you to full health', {
