}, function(vstorage, et)
	if et and vstorage.enabled then cmd_library.execute('unloopheal') return end
	if vstorage.enabled then return notify('loopheal', 'already looping', 2) end
	vstorage.enabled = true
	notify('loopheal', 'loop heal enabled', 1)
	maid.add('loopheal', services.run_service.Heartbeat, function()
		if not vstorage.enabled then return end
		local hum = stuff.owner_char and stuff.owner_char:FindFirstChildOfClass('Humanoid')
		if hum then stuff.rawrbxset(hum, 'Health', hum.MaxHealth) end
