cmd_library.add({'bring', 'tphere'}, 'teleports you to a player (local)', {
	{'player', 'player'}
}, function(vstorage, targets)
	if not targets or #targets == 0 then return notify('bring', 'player not found', 2) end
	local hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
	if not hrp then return notify('bring', 'no rootpart', 2) end
	for _, target in targets do
		local tc = target.Character
		if tc and tc:FindFirstChild('HumanoidRootPart') then
			local tpos = tc.HumanoidRootPart.CFrame
			stuff.owner_char:PivotTo(tpos * CFrame.new(3, 0, 0))
			notify('bring', 'teleported to ' .. target.Name, 1)
		end
	end
end)

cmd_library.add({'loopbring', 'lb'}, 'loops teleporting to a player', {
	{'player', 'player'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, targets, et)
	if et and vstorage.enabled then cmd_library.execute('unloopbring') return end
	if vstorage.enabled then cmd_library.execute('unloopbring') end
	if not targets or #targets == 0 then return notify('loopbring', 'player not found', 2) end
	vstorage.enabled = true
	vstorage.target = targets[1]
	notify('loopbring', 'looping to ' .. targets[1].Name, 1)
	maid.add('loopbring', services.run_service.Heartbeat, function()
		if not vstorage.enabled then return end
		local t = vstorage.target
		if not t or not t.Character then return end
		local tc = t.Character:FindFirstChild('HumanoidRootPart')
		local sc = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
		if tc and sc then
			stuff.owner_char:PivotTo(tc.CFrame * CFrame.new(3, 0, 0))
		end
	end)
end)

cmd_library.add({'unloopbring', 'unlb'}, 'stops loop bring', {}, function()
	local vs = cmd_library.get_variable_storage('loopbring')
	vs.enabled = false
	maid.remove('loopbring')
	notify('loopbring', 'loop bring stopped', 1)
end)

cmd_library.add({'hat', 'addhat'}, 'adds a hat to your character by asset id', {
	{'asset_id', 'number'}
}, function(vstorage, id)
	if not id then return notify('hat', 'provide an asset id', 2) end
	local ok, obj = pcall(function()
		return game:GetObjects('rbxassetid://' .. tostring(math.floor(id)))[1]
	end)
	if not ok or not obj then return notify('hat', 'failed to load asset ' .. tostring(id), 2) end
	local char = stuff.owner_char
	if obj:IsA('Accessory') then
		obj.Parent = char
	elseif obj:FindFirstChildOfClass('Accessory') then
		obj:FindFirstChildOfClass('Accessory').Parent = char
	else
		obj.Parent = char
	end
	notify('hat', 'hat ' .. tostring(id) .. ' added', 1)
end)

cmd_library.add({'removehats', 'clearhats', 'rhats'}, 'removes all accessories from your character', {}, function()
	local char = stuff.owner_char
	if not char then return notify('hat', 'no character', 2) end
	for _, acc in ipairs(char:GetChildren()) do
		if acc:IsA('Accessory') then acc:Destroy() end
	end
	notify('hat', 'accessories removed', 1)
end)

cmd_library.add({'music', 'playsound', 'song'}, 'plays a sound in your character', {
	{'sound_id', 'number'},
	{'volume',   'number'}
}, function(vstorage, id, vol)
	if not id then return notify('music', 'provide a sound id', 2) end
	local char = stuff.owner_char
	if not char then return notify('music', 'no character', 2) end
	if vstorage.sound then pcall(function() vstorage.sound:Destroy() end) end
	local s = Instance.new('Sound')
	s.SoundId = 'rbxassetid://' .. tostring(math.floor(id))
	s.Volume = vol or 1
	s.Looped = true
	s.Parent = char:FindFirstChild('HumanoidRootPart') or char
	s:Play()
	vstorage.sound = s
	notify('music', 'playing ' .. tostring(math.floor(id)), 1)
end)

cmd_library.add({'stopmusic', 'stopsound', 'nosong'}, 'stops character sound', {}, function()
	local vs = cmd_library.get_variable_storage('music')
	if vs.sound then
		pcall(function() vs.sound:Destroy() end)
		vs.sound = nil
		notify('music', 'sound stopped', 1)
	else
		notify('music', 'no sound playing', 2)
	end
end)

cmd_library.add({'volume', 'vol'}, 'sets volume of playing character sound', {
	{'volume', 'number'}
}, function(vstorage, vol)
	local vs = cmd_library.get_variable_storage('music')
	if not vs.sound then return notify('volume', 'no sound playing', 2) end
	vs.sound.Volume = math.clamp(vol or 1, 0, 10)
	notify('volume', 'volume set to ' .. tostring(vs.sound.Volume), 1)
end)

cmd_library.add({'pitch', 'soundpitch'}, 'sets pitch of playing character sound', {
	{'pitch', 'number'}
}, function(vstorage, p)
	local vs = cmd_library.get_variable_storage('music')
	if not vs.sound then return notify('pitch', 'no sound playing', 2) end
	local pe = vs.sound:FindFirstChildOfClass('PitchShiftSoundEffect')
	if not pe then pe = Instance.new('PitchShiftSoundEffect', vs.sound) end
	pe.Octave = math.clamp(p or 1, 0.01, 4)
	notify('pitch', 'pitch set to ' .. tostring(pe.Octave), 1)
end)

cmd_library.add({'nightvision', 'nv'}, 'enables night vision (brightens the game)', {
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, et)
	if et and vstorage.enabled then cmd_library.execute('unnightvision') return end
	if vstorage.enabled then return notify('nightvision', 'already enabled', 2) end
	vstorage.enabled = true
	vstorage.old_brightness = services.lighting.Brightness
	vstorage.old_ambient = services.lighting.Ambient
	vstorage.old_outdoor = services.lighting.OutdoorAmbient
	vstorage.old_shadows = services.lighting.GlobalShadows
	services.lighting.Brightness = 2
	services.lighting.Ambient = Color3.fromRGB(150, 150, 150)
	services.lighting.OutdoorAmbient = Color3.fromRGB(150, 150, 150)
	services.lighting.GlobalShadows = false
	notify('nightvision', 'night vision on', 1)
end)

cmd_library.add({'unnightvision', 'unnv'}, 'disables night vision', {}, function()
	local vs = cmd_library.get_variable_storage('nightvision')
	if not vs.enabled then return notify('nightvision', 'not enabled', 2) end
	vs.enabled = false
	if vs.old_brightness then services.lighting.Brightness = vs.old_brightness end
	if vs.old_ambient then services.lighting.Ambient = vs.old_ambient end
	if vs.old_outdoor then services.lighting.OutdoorAmbient = vs.old_outdoor end
	if vs.old_shadows ~= nil then services.lighting.GlobalShadows = vs.old_shadows end
	notify('nightvision', 'night vision off', 1)
end)

cmd_library.add({'rainbow', 'rainbowcolor'}, 'makes your character cycle rainbow colors', {
	{'speed', 'number'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, speed, et)
	if et and vstorage.enabled then cmd_library.execute('unreinbow') return end
	if vstorage.enabled then return notify('rainbow', 'already enabled', 2) end
	vstorage.enabled = true
	speed = speed or 1
	notify('rainbow', 'rainbow enabled', 1)
	maid.add('rainbow', services.run_service.Heartbeat, function()
		if not vstorage.enabled then return end
		local h = (tick() * speed) % 1
		local col = Color3.fromHSV(h, 1, 1)
		local char = stuff.owner_char
		if not char then return end
		for _, part in char:GetDescendants() do
			if part:IsA('BasePart') and part.Name ~= 'HumanoidRootPart' then
				pcall(function() stuff.rawrbxset(part, 'Color', col) end)
			end
		end
	end)
end)

cmd_library.add({'unreinbow', 'norainbow'}, 'stops rainbow colors', {}, function()
	local vs = cmd_library.get_variable_storage('rainbow')
	vs.enabled = false
	maid.remove('rainbow')
	notify('rainbow', 'rainbow off', 1)
end)

cmd_library.add({'glow', 'neon'}, 'makes your character parts neon material', {
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, et)
	if et and vstorage.enabled then cmd_library.execute('unglow') return end
	if vstorage.enabled then return notify('glow', 'already glowing', 2) end
	vstorage.enabled = true
	vstorage.old_materials = {}
	local char = stuff.owner_char
	for _, part in char:GetDescendants() do
