end)

cmd_library.add({'unglow', 'noneon'}, 'removes neon glow', {}, function()
	local vs = cmd_library.get_variable_storage('glow')
	if not vs.enabled then return notify('glow', 'not glowing', 2) end
	vs.enabled = false
	if vs.old_materials then
		for part, mat in pairs(vs.old_materials) do
			pcall(function() stuff.rawrbxset(part, 'Material', mat) end)
		end
	end
	notify('glow', 'neon glow off', 1)
end)

