cmd_library.add({'clonechar', 'charclone', 'doppelganger'}, 'spawns a non-moving copy of your character', {}, function(vstorage)
	local char = stuff.owner_char
	if not char then return notify('clone', 'no character', 2) end
	local clone = char:Clone()
	for _, script in clone:GetDescendants() do
		if script:IsA('LocalScript') or script:IsA('Script') then script:Destroy() end
	end
	local hum = clone:FindFirstChildOfClass('Humanoid')
	if hum then hum:Destroy() end
	local anim = clone:FindFirstChildOfClass('Animator')
	if anim then anim:Destroy() end
	local hrp = clone:FindFirstChild('HumanoidRootPart')
	if hrp then
		hrp.Anchored = true
		hrp.CanCollide = false
	end
	clone.Name = 'GoosesploitClone'
	clone.Parent = workspace
	if vstorage.last_clone then pcall(function() vstorage.last_clone:Destroy() end) end
	vstorage.last_clone = clone
	notify('clone', 'character clone spawned', 1)
end)

cmd_library.add({'unclonechar', 'removeclone'}, 'removes your character clone', {}, function()
	local vs = cmd_library.get_variable_storage('clonechar')
	if vs.last_clone then
		pcall(function() vs.last_clone:Destroy() end)
		vs.last_clone = nil
		notify('clone', 'clone removed', 1)
	end
	for _, obj in workspace:GetChildren() do
		if obj.Name == 'GoosesploitClone' then pcall(function() obj:Destroy() end) end
	end
end)

