cmd_library.add({'superfly', 'sf'}, 'fly at extreme speed with shift to boost', {
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, et)
	if et and vstorage.enabled then cmd_library.execute('unsuperfly') return end
	if vstorage.enabled then return notify('superfly', 'already active', 2) end
	vstorage.enabled = true
	local char = stuff.owner_char
	local hrp  = char and char:FindFirstChild('HumanoidRootPart')
	if not hrp then return notify('superfly', 'no rootpart', 2) end

	local bv = Instance.new('BodyVelocity')
	bv.Velocity  = Vector3.zero
	bv.MaxForce  = Vector3.new(1e9, 1e9, 1e9)
	bv.Parent    = hrp

	local bg = Instance.new('BodyGyro')
	bg.MaxTorque = Vector3.new(1e9, 1e9, 1e9)
	bg.P         = 1e6
	bg.CFrame    = hrp.CFrame
	bg.Parent    = hrp

	vstorage.bv = bv
	vstorage.bg = bg

	notify('superfly', 'superfly on — WASD to move, hold shift to boost', 1)

	maid.add('superfly', services.run_service.Heartbeat, function()
		if not vstorage.enabled then return end
		local uis   = services.user_input_service
		local cam   = workspace.CurrentCamera
		local speed = uis:IsKeyDown(Enum.KeyCode.LeftShift) and 200 or 60
		local fwd   = cam.CFrame.LookVector
		local right = cam.CFrame.RightVector
		local up    = Vector3.new(0, 1, 0)
		local dir   = Vector3.zero
		if uis:IsKeyDown(Enum.KeyCode.W) then dir = dir + fwd end
		if uis:IsKeyDown(Enum.KeyCode.S) then dir = dir - fwd end
		if uis:IsKeyDown(Enum.KeyCode.A) then dir = dir - right end
		if uis:IsKeyDown(Enum.KeyCode.D) then dir = dir + right end
		if uis:IsKeyDown(Enum.KeyCode.Space) then dir = dir + up end
		if uis:IsKeyDown(Enum.KeyCode.LeftControl) then dir = dir - up end
		local vel = dir == Vector3.zero and Vector3.zero or dir.Unit * speed
		bv.Velocity = vel
		bg.CFrame   = cam.CFrame
		local hum = char:FindFirstChildOfClass('Humanoid')
		if hum then hum:ChangeState(Enum.HumanoidStateType.Physics) end
	end)
end)

cmd_library.add({'unsuperfly', 'unsf'}, 'disables superfly', {}, function()
	local vs = cmd_library.get_variable_storage('superfly')
	vs.enabled = false
	maid.remove('superfly')
