cmd_library.add({'trail', 'chartrail', 'addtrail'}, 'adds a color trail to your character', {
	{'r', 'number'},
	{'g', 'number'},
	{'b', 'number'}
}, function(vstorage, r, g, b)
	local char = stuff.owner_char
	if not char then return notify('trail', 'no character', 2) end
	if vstorage.trail then pcall(function() vstorage.trail:Destroy() end) end
	if vstorage.attach0 then pcall(function() vstorage.attach0:Destroy() end) end
	if vstorage.attach1 then pcall(function() vstorage.attach1:Destroy() end) end
	local hrp = char:FindFirstChild('HumanoidRootPart')
	if not hrp then return notify('trail', 'no rootpart', 2) end
	local a0 = Instance.new('Attachment') a0.Position = Vector3.new(0, 1, 0) a0.Parent = hrp
	local a1 = Instance.new('Attachment') a1.Position = Vector3.new(0, -1, 0) a1.Parent = hrp
	local trail = Instance.new('Trail')
	trail.Attachment0 = a0
	trail.Attachment1 = a1
	trail.Lifetime    = 0.5
	local col = Color3.fromRGB(r or 100, g or 150, b or 255)
	trail.Color = ColorSequence.new(col)
	trail.Transparency = NumberSequence.new(0, 1)
	trail.Parent = hrp
	vstorage.trail   = trail
	vstorage.attach0 = a0
	vstorage.attach1 = a1
	notify('trail', 'trail added', 1)
end)

