cmd_library.add({'highlight', 'hl', 'mark'}, 'adds a highlight to a player', {
	{'player', 'player'},
	{'r',      'number'},
	{'g',      'number'},
	{'b',      'number'}
}, function(vstorage, targets, r, g, b)
	if not targets or #targets == 0 then return notify('highlight', 'player not found', 2) end
	vstorage.highlights = vstorage.highlights or {}
	local col = Color3.fromRGB(r or 255, g or 255, b or 0)
	for _, target in targets do
		if vstorage.highlights[target.UserId] then
			pcall(function() vstorage.highlights[target.UserId]:Destroy() end)
		end
		local char = target.Character
		if not char then notify('highlight', target.Name .. ' has no char', 2); continue end
		local hl = Instance.new('SelectionBox')
		hl.Adornee     = char
		hl.Color3      = col
		hl.LineThickness = 0.05
		hl.SurfaceTransparency = 0.8
		hl.SurfaceColor3 = col
		hl.Parent      = services.core_gui
		vstorage.highlights[target.UserId] = hl
		notify('highlight', 'highlighted ' .. target.Name, 1)
	end
end)

cmd_library.add({'unhighlight', 'unhl', 'unmark'}, 'removes highlight from a player', {
	{'player', 'player'}
}, function(vstorage, targets)
	vstorage.highlights = vstorage.highlights or {}
	if not targets or #targets == 0 then
		for _, hl in pairs(vstorage.highlights) do pcall(function() hl:Destroy() end) end
		vstorage.highlights = {}
		notify('highlight', 'all highlights removed', 1)
		return
	end
	for _, target in targets do
		if vstorage.highlights[target.UserId] then
			pcall(function() vstorage.highlights[target.UserId]:Destroy() end)
			vstorage.highlights[target.UserId] = nil
			notify('highlight', 'removed highlight from ' .. target.Name, 1)
		end
	end
end)

