cmd_library.add({'partinfo', 'inspectpart', 'pinfo2'}, 'logs info about the part your mouse is over', {}, function()
	local mouse = services.players.LocalPlayer:GetMouse()
	notify('partinfo', 'hover over a part and click', 4)
	local conn
	conn = mouse.Button1Down:Connect(function()
		conn:Disconnect()
		local t = mouse.Target
		if not t then notify('partinfo', 'no target', 2) return end
		notify('partinfo', 'Name: ' .. t.Name .. ' | Class: ' .. t.ClassName, 4)
		notify('partinfo', 'Size: ' .. tostring(t.Size) .. ' | Anchored: ' .. tostring(t:IsA('BasePart') and t.Anchored), 4)
		notify('partinfo', 'Parent: ' .. (t.Parent and t.Parent.Name or 'nil'), 4)
		local pos = t:IsA('BasePart') and t.Position or Vector3.zero
		pcall(setclipboard, t.Name .. ' | ' .. t.ClassName .. ' | ' .. tostring(pos))
	end)
end)

cmd_library.add({'decalspam', 'texturedecal'}, 'covers workspace parts with a decal', {
	{'decal_id', 'number'}
}, function(vstorage, id)
	if not id then return notify('decalspam', 'provide a decal id', 2) end
	if vstorage.decals then
		for _, d in ipairs(vstorage.decals) do pcall(function() d:Destroy() end) end
	end
	vstorage.decals = {}
	local count = 0
	for _, part in workspace:GetDescendants() do
		if part:IsA('BasePart') then
			local d = Instance.new('Decal')
			d.Texture = 'rbxassetid://' .. tostring(math.floor(id))
			d.Parent  = part
			table.insert(vstorage.decals, d)
			count = count + 1
			if count >= 200 then break end
		end
	end
	notify('decalspam', 'applied decal ' .. id .. ' to ' .. count .. ' parts', 1)
end)

cmd_library.add({'nodecalspam', 'removedecals'}, 'removes all added decals', {}, function()
	local vs = cmd_library.get_variable_storage('decalspam')
	if vs.decals then
		for _, d in ipairs(vs.decals) do pcall(function() d:Destroy() end) end
		vs.decals = {}
	end
	notify('decalspam', 'decals removed', 1)
end)

cmd_library.add({'boom', 'explodeme', 'selfexplode'}, 'creates a client-side explosion at your position', {
	{'blast_radius', 'number'}
}, function(vstorage, radius)
	local hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
	if not hrp then return notify('boom', 'no rootpart', 2) end
	local explosion = Instance.new('Explosion')
	explosion.Position    = hrp.Position
	explosion.BlastRadius = radius or 30
	explosion.BlastPressure = 0
