cmd_library.add({'tppart', 'teleporttopart'}, 'teleports you to a named part', {
	{'part_name', 'string'}
}, function(vstorage, name)
	if not name then return notify('tppart', 'provide a part name', 2) end
	local part = workspace:FindFirstChild(name, true)
	if not part or not part:IsA('BasePart') then
		return notify('tppart', 'part "' .. name .. '" not found', 2)
	end
	stuff.owner_char:PivotTo(part.CFrame * CFrame.new(0, 3, 0))
	notify('tppart', 'teleported to ' .. name, 1)
end)

cmd_library.add({'listparts', 'findparts'}, 'lists parts matching a name in workspace', {
	{'name', 'string'}
}, function(vstorage, name)
	if not name then return notify('listparts', 'provide a name to search', 2) end
	local found = {}
	for _, obj in workspace:GetDescendants() do
		if obj.Name:lower():find(name:lower(), 1, true) then
			table.insert(found, obj.Name .. ' (' .. obj.ClassName .. ')')
			if #found >= 10 then break end
		end
	end
	if #found == 0 then
		notify('listparts', 'no parts matching "' .. name .. '"', 2)
	else
		notify('listparts', table.concat(found, ', '), 4)
	end
end)

cmd_library.add({'clearws', 'cleanworkspace'}, 'destroys all non-essential workspace children', {}, function()
	local keep = {'Terrain', 'Camera', stuff.owner_char and stuff.owner_char.Name or ''}
	local removed = 0
	for _, child in workspace:GetChildren() do
		local skip = false
		for _, k in ipairs(keep) do if child.Name == k then skip = true break end end
		if not skip then
			pcall(function() child:Destroy() end)
			removed = removed + 1
		end
	end
	notify('clearws', 'removed ' .. removed .. ' workspace objects', 1)
end)

cmd_library.add({'countplayers', 'playercount', 'pc'}, 'shows how many players are in the server', {}, function()
	local plrs = services.players:GetPlayers()
