	for _, p in ipairs(plrs) do table.insert(names, p.Name) end
	notify('players', table.concat(names, ', '), 4)
end)

cmd_library.add({'randomtp', 'rtp', 'tprandom'}, 'teleports you to a random player', {}, function()
	local others = {}
	for _, p in ipairs(services.players:GetPlayers()) do
		if p ~= stuff.owner and p.Character and p.Character:FindFirstChild('HumanoidRootPart') then
			table.insert(others, p)
		end
	end
	if #others == 0 then return notify('randomtp', 'no other players', 2) end
	local target = others[math.random(#others)]
	stuff.owner_char:PivotTo(target.Character.HumanoidRootPart.CFrame * CFrame.new(3, 0, 0))
	notify('randomtp', 'teleported to ' .. target.Name, 1)
end)

