cmd_library.add({'spawnpart', 'mkpart', 'newpart'}, 'spawns a part at your position', {
	{'size',     'number'},
	{'material', 'string'},
	{'anchored', 'boolean'}
}, function(vstorage, size, mat, anch)
	local hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
	local pos = hrp and hrp.Position or Vector3.new(0, 10, 0)
	local p = Instance.new('Part')
	p.Size     = Vector3.one * (size or 4)
	p.CFrame   = CFrame.new(pos + Vector3.new(0, 5, 0))
	p.Anchored = (anch == nil) and true or anch
	if mat then
		local ok, enum_val = pcall(function() return Enum.Material[mat] end)
		if ok and enum_val then p.Material = enum_val end
	end
	p.Parent = workspace
	if not vstorage.parts then vstorage.parts = {} end
	table.insert(vstorage.parts, p)
	notify('spawnpart', 'part spawned', 1)
end)

cmd_library.add({'clearparts', 'removemyparts'}, 'removes parts spawned with spawnpart', {}, function()
	local vs = cmd_library.get_variable_storage('spawnpart')
	if not vs.parts or #vs.parts == 0 then return notify('spawnpart', 'no parts to remove', 2) end
	for _, p in ipairs(vs.parts) do pcall(function() p:Destroy() end) end
	vs.parts = {}
	notify('spawnpart', 'all spawned parts removed', 1)
end)

cmd_library.add({'antitp', 'blocktp'}, 'attempts to block forced teleports', {
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, et)
	if et and vstorage.enabled then cmd_library.execute('unantitp') return end
	if vstorage.enabled then return notify('antitp', 'already active', 2) end
	if not hookmetamethod then return notify('antitp', 'hookmetamethod not available', 2) end
	vstorage.enabled = true
	vstorage.saved_cf = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart') and stuff.owner_char.HumanoidRootPart.CFrame
	local hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
	if not hrp then return notify('antitp', 'no rootpart', 2) end
	maid.add('antitp', services.run_service.Heartbeat, function()
		if not vstorage.enabled then return end
		vstorage.saved_cf = hrp.CFrame
	end)
	hook_lib.create_hook('antitp_hook', {
		newindex = function(self, key, val)
			if (self == hrp) and (key == 'CFrame' or key == 'Position') then
				local dist = vstorage.saved_cf and (vstorage.saved_cf.Position - (key == 'Position' and val or val.Position)).Magnitude or 0
				if dist > 50 then return false end
			end
		end
	})
	notify('antitp', 'anti-teleport enabled (>50 stud jumps blocked)', 1)
end)

cmd_library.add({'unantitp', 'unblocktp'}, 'disables anti-teleport', {}, function()
	local vs = cmd_library.get_variable_storage('antitp')
	vs.enabled = false
	maid.remove('antitp')
	hook_lib.destroy_hook('antitp_hook')
	notify('antitp', 'anti-teleport disabled', 1)
end)

