cmd_library.add({'alias', 'addalias'}, 'creates a short alias for a command', {
	{'name',    'string'},
	{'command', 'string'}
}, function(vstorage, name, command)
	if not name or not command then return notify('alias', 'usage: alias [name] [command]', 2) end
	local existing = cmd_library.find_similar(name:lower())
	for _, n in ipairs(existing) do
		if n == name:lower() then return notify('alias', 'command "' .. name .. '" already exists', 2) end
	end
	cmd_library.add({name:lower()}, 'alias -> ' .. command, {{'args', 'string', 'optional'}}, function(vs2, extra)
		local full = command .. (extra and (' ' .. extra) or '')
		for _, data in cmd_library.parse_command(full) do
			cmd_library.execute(data.cmd, table.unpack(data.args))
		end
	end)
	notify('alias', 'alias "' .. name .. '" -> "' .. command .. '" created', 1)
end)

cmd_library.add({'macro', 'addmacro', 'multiscript'}, 'runs multiple commands in sequence separated by &&', {
	{'commands', 'string', '...'}
}, function(vstorage, ...)
	local raw = table.concat({...}, ' ')
	if raw == '' then return notify('macro', 'provide commands separated by &&', 2) end
	local parts = {}
	for part in raw:gmatch('[^&&]+') do
		table.insert(parts, part:match('^%s*(.-)%s*$'))
	end
	notify('macro', 'running ' .. #parts .. ' commands', 1)
	for _, part in ipairs(parts) do
		for _, data in cmd_library.parse_command(part) do
			cmd_library.execute(data.cmd, table.unpack(data.args))
		end
	end
end)

cmd_library.add({'looptask', 'schedule', 'every'}, 'runs a command every N seconds', {
	{'interval', 'number'},
	{'command',  'string'}
}, function(vstorage, interval, command)
	if not interval or not command then return notify('looptask', 'usage: looptask [seconds] [command]', 2) end
	if vstorage.running then
		vstorage.running = false
		notify('looptask', 'stopped previous loop', 1)
	end
	vstorage.running = true
	notify('looptask', 'running "' .. command .. '" every ' .. interval .. 's', 1)
	task.spawn(function()
		while vstorage.running do
			for _, data in cmd_library.parse_command(command) do
				cmd_library.execute(data.cmd, table.unpack(data.args))
			end
			task.wait(interval)
		end
	end)
end)

cmd_library.add({'stoplooptask', 'unschedule', 'unlooptask'}, 'stops the running looptask', {}, function()
	local vs = cmd_library.get_variable_storage('looptask')
	vs.running = false
