local function gs_load_url(url, label)
	local ok, result = pcall(function()
		return game:HttpGet(url, true)
	end)
	if not ok or not result or result == '' then
		return false, 'http failed: ' .. tostring(result)
	end
	local ok2, fn = pcall(loadstring, result)
	if not ok2 or not fn then
		return false, 'compile failed: ' .. tostring(fn)
	end
	local ok3, err = pcall(fn)
	if not ok3 then
		return false, 'runtime error: ' .. tostring(err)
	end
	return true
end

cmd_library.add({'rspy', 'remotespy2', 'spyremotes'}, 'built-in remote spy — logs all remote calls to console', {
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, et)
	if et and vstorage.enabled then
		cmd_library.execute('unrespy')
		return
	end
	if vstorage.enabled then return notify('rspy', 'remote spy already running', 2) end
	if not hookmetamethod then
		notify('rspy', 'hookmetamethod unavailable — trying ketamine loader', 3)
		local ok, err = gs_load_url('https://raw.githubusercontent.com/InfernusScripts/Ketamine/refs/heads/main/Ketamine.lua', 'ketamine')
		if not ok then notify('rspy', 'ketamine failed: ' .. err, 2) end
		return
	end

	vstorage.enabled  = true
	vstorage.log      = vstorage.log or {}
	vstorage.paused   = false
	vstorage.filter   = nil

	local IGNORED = {
		'RunService', 'UserInputService', 'Players',
		'ReplicatedFirst', 'GuiService', 'CoreGui'
	}
	local function is_ignored(remote)
		local p = remote.Parent
		while p do
			for _, name in ipairs(IGNORED) do
				if p.Name == name then return true end
			end
			p = p.Parent
		end
		return false
	end

	local original_namecall = hookmetamethod(game, '__namecall', newcclosure(function(self, ...)
		local method = getnamecallmethod()
		local result = {original_namecall(self, ...)}

		if not vstorage.enabled or vstorage.paused then return table.unpack(result) end
		if not (self:IsA('RemoteEvent') or self:IsA('RemoteFunction') or self:IsA('BindableEvent') or self:IsA('BindableFunction')) then
			return table.unpack(result)
		end
		if is_ignored(self) then return table.unpack(result) end
		if vstorage.filter and not self.Name:lower():find(vstorage.filter:lower(), 1, true) then
			return table.unpack(result)
		end

		local args = {...}
		local arg_strs = {}
		for _, v in ipairs(args) do
			table.insert(arg_strs, tostring(v))
		end
		local entry = {
			time   = os.date('%H:%M:%S'),
			name   = self.Name,
			path   = self:GetFullName(),
			class  = self.ClassName,
			method = method,
			args   = table.concat(arg_strs, ', '),
		}
		table.insert(vstorage.log, 1, entry)
		if #vstorage.log > 200 then table.remove(vstorage.log) end

		print(('[rspy] [' .. entry.time .. '] ' .. entry.method .. ' -> ' .. entry.path
			.. (entry.args ~= '' and (' | args: ' .. entry.args) or '')))

		return table.unpack(result)
	end))

	vstorage.original_namecall = original_namecall
	notify('rspy', 'remote spy active — check F9 console', 1)
end)

cmd_library.add({'unrespy', 'stoprspy', 'rspyoff'}, 'stops the built-in remote spy', {}, function()
