cmd_library.add({'fireremote', 'fr', 'fremote'}, 'fires a RemoteEvent by name with optional args', {
	{'name',   'string'},
	{'arg1',   'string'},
	{'arg2',   'string'},
	{'arg3',   'string'}
}, function(vstorage, name, a1, a2, a3)
	if not name then return notify('fireremote', 'provide a remote name', 2) end
	local found = {}
	for _, obj in workspace:GetDescendants() do
		if (obj:IsA('RemoteEvent') or obj:IsA('RemoteFunction')) and obj.Name:lower() == name:lower() then
			table.insert(found, obj)
		end
	end
	for _, obj in game.ReplicatedStorage:GetDescendants() do
		if (obj:IsA('RemoteEvent') or obj:IsA('RemoteFunction')) and obj.Name:lower() == name:lower() then
			table.insert(found, obj)
		end
	end
	if #found == 0 then return notify('fireremote', 'remote "' .. name .. '" not found', 2) end
	local args = {}
	for _, v in ipairs({a1, a2, a3}) do if v then table.insert(args, v) end end
	for _, remote in ipairs(found) do
		if remote:IsA('RemoteEvent') then
			pcall(function() remote:FireServer(table.unpack(args)) end)
			notify('fireremote', 'fired: ' .. remote:GetFullName(), 1)
		elseif remote:IsA('RemoteFunction') then
			local ok, res = pcall(function() return remote:InvokeServer(table.unpack(args)) end)
			notify('fireremote', 'invoked: ' .. remote.Name .. ' -> ' .. tostring(res), ok and 1 or 2)
		end
	end
end)

cmd_library.add({'listremotes', 'remotes', 'getremotes'}, 'lists all RemoteEvents and RemoteFunctions in the game', {
	{'filter', 'string'}
}, function(vstorage, filter)
	local found = {}
	for _, obj in game:GetDescendants() do
		if obj:IsA('RemoteEvent') or obj:IsA('RemoteFunction') or obj:IsA('BindableEvent') or obj:IsA('BindableFunction') then
			local path = obj:GetFullName()
			if not filter or path:lower():find(filter:lower(), 1, true) then
				table.insert(found, obj.ClassName:sub(1,2) .. ':' .. path)
			end
		end
	end
	table.sort(found)
	if #found == 0 then return notify('remotes', 'no remotes found', 2) end
	notify('remotes', #found .. ' remotes — printed to F9 console', 4)
	for _, r in ipairs(found) do print('[remotes] ' .. r) end
end)

cmd_library.add({'firetouchinterest', 'fti', 'touchweld'}, 'fires touch interest on the part your mouse is over', {}, function()
	local mouse = services.players.LocalPlayer:GetMouse()
	local hrp   = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
	if not hrp then return notify('fti', 'no rootpart', 2) end
	notify('fti', 'click a part to fire its touch interest', 4)
	local conn
	conn = mouse.Button1Down:Connect(function()
		conn:Disconnect()
		local target = mouse.Target
		if not target then return notify('fti', 'no target', 2) end
