cmd_library.add({'loopfti', 'looptouch', 'lft'}, 'repeatedly fires touch interest on a named part', {
	{'part_name', 'string'},
	{'interval',  'number'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, part_name, interval, et)
	if et and vstorage.enabled then cmd_library.execute('unloopfti') return end
	if vstorage.enabled then cmd_library.execute('unloopfti') end
	if not part_name then return notify('loopfti', 'provide a part name', 2) end
	local part = workspace:FindFirstChild(part_name, true)
	if not part then return notify('loopfti', 'part "' .. part_name .. '" not found', 2) end
	local hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
	if not hrp then return notify('loopfti', 'no rootpart', 2) end
	vstorage.enabled = true
	interval = interval or 0.1
	notify('loopfti', 'looping touch on ' .. part_name, 1)
	task.spawn(function()
		while vstorage.enabled do
			pcall(firetouchinterest, hrp, part, 0)
			pcall(firetouchinterest, hrp, part, 1)
			task.wait(interval)
		end
	end)
end)

cmd_library.add({'unloopfti', 'unlooptouch'}, 'stops loop firetouchinterest', {}, function()
	local vs = cmd_library.get_variable_storage('loopfti')
	vs.enabled = false
	notify('loopfti', 'loop touch stopped', 1)
end)

cmd_library.add({'fireproxprompt', 'fpp', 'instantpp', 'presspp'}, 'fires a proximity prompt by name or clicks nearest one', {
	{'name',   'string'},
	{'player', 'player'}
}, function(vstorage, name, targets)
	local hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
	if not hrp then return notify('fpp', 'no rootpart', 2) end

	local fired = 0
	for _, obj in workspace:GetDescendants() do
		if obj:IsA('ProximityPrompt') then
			local match = (not name) or obj.Name:lower():find(name:lower(), 1, true)
				or (obj.Parent and obj.Parent.Name:lower():find(name:lower(), 1, true))
			if match then
				local ok = pcall(fireproximityprompt, obj)
				if ok then fired = fired + 1 end
				if not name then break end
			end
		end
	end

	if fired > 0 then
		notify('fpp', 'fired ' .. fired .. ' prompt(s)', 1)
	else
		notify('fpp', 'no matching prompts found', 2)
	end
end)

cmd_library.add({'loopfpp', 'loopinstantpp'}, 'repeatedly fires a proximity prompt', {
	{'name',     'string'},
	{'interval', 'number'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, name, interval, et)
	if et and vstorage.enabled then cmd_library.execute('unloopfpp') return end
	if vstorage.enabled then cmd_library.execute('unloopfpp') end
	vstorage.enabled = true
	interval = interval or 0.2
	notify('loopfpp', 'looping prompt fire' .. (name and (' on ' .. name) or ''), 1)
	task.spawn(function()
		while vstorage.enabled do
			for _, obj in workspace:GetDescendants() do
				if obj:IsA('ProximityPrompt') then
					local match = (not name) or obj.Name:lower():find(name:lower(), 1, true)
						or (obj.Parent and obj.Parent.Name:lower():find(name:lower(), 1, true))
					if match then pcall(fireproximityprompt, obj) end
				end
			end
			task.wait(interval)
		end
	end)
end)

cmd_library.add({'unloopfpp', 'stopfpp'}, 'stops loop fire proximity prompt', {}, function()
	local vs = cmd_library.get_variable_storage('loopfpp')
	vs.enabled = false
	notify('loopfpp', 'loop fpp stopped', 1)
end)

cmd_library.add({'listprompts', 'getprompts', 'prompts'}, 'lists all proximity prompts and their locations', {}, function()
	local found = {}
	for _, obj in workspace:GetDescendants() do
		if obj:IsA('ProximityPrompt') then
			local hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
			local dist = '?'
			if hrp and obj.Parent and obj.Parent:IsA('BasePart') then
				dist = tostring(math.floor((obj.Parent.Position - hrp.Position).Magnitude))
			end
			table.insert(found, obj.Name .. ' @ ' .. obj:GetFullName() .. ' (' .. dist .. ' studs)')
		end
	end
	if #found == 0 then return notify('prompts', 'no proximity prompts found', 2) end
	notify('prompts', #found .. ' prompts — printed to F9', 4)
	for _, s in ipairs(found) do print('[prompts] ' .. s) end
end)

cmd_library.add({'clickdetector', 'clickdet', 'cd'}, 'fires the click detector on the part your mouse is over', {
	{'distance', 'number'}
}, function(vstorage, dist)
	local mouse = services.players.LocalPlayer:GetMouse()
	notify('clickdet', 'click a part to fire its ClickDetector', 4)
	local conn
	conn = mouse.Button1Down:Connect(function()
		conn:Disconnect()
		local target = mouse.Target
		if not target then return notify('clickdet', 'no target', 2) end
		local det = target:FindFirstChildOfClass('ClickDetector')
			or target.Parent and target.Parent:FindFirstChildOfClass('ClickDetector')
		if not det then return notify('clickdet', 'no ClickDetector on ' .. target.Name, 2) end
		local old_max = det.MaxActivationDistance
		det.MaxActivationDistance = dist or 1e9
		local ok, err = pcall(function()
			fireclickdetector(det)
		end)
		det.MaxActivationDistance = old_max
		if ok then notify('clickdet', 'clicked: ' .. det.Parent.Name, 1)
		else notify('clickdet', 'failed: ' .. tostring(err), 2) end
	end)
end)

