cmd_library.add({'consolegui', 'console', 'outputgui'}, 'opens a live output console GUI', {}, function(vstorage)
	if vstorage.gui and vstorage.gui.Parent then
		vstorage.gui.Enabled = not vstorage.gui.Enabled
		return
	end

	local IS_MOB = stuff.is_mobile
	local vp = workspace.CurrentCamera.ViewportSize
	local W, H = IS_MOB and math.min(vp.X - 10, 440) or 500, IS_MOB and 320 or 380

	local gui = Instance.new('ScreenGui')
	gui.Name = 'GoosesploitConsole'
	gui.ResetOnSpawn = false
	gui.DisplayOrder = 995
	pcall(function() gui.Parent = services.core_gui end)
	if not gui.Parent then gui.Parent = services.players.LocalPlayer.PlayerGui end
	vstorage.gui = gui

	local win = Instance.new('Frame')
	win.Size = UDim2.new(0, W, 0, H)
	win.Position = UDim2.new(1, -W - 8, 1, -H - 8)
	win.BackgroundColor3 = Color3.fromRGB(14, 14, 18)
	win.BorderSizePixel = 0
	win.Active = true
	win.Parent = gui
	do local c = Instance.new('UICorner') c.CornerRadius = UDim.new(0,8) c.Parent = win end
	do local s = Instance.new('UIStroke') s.Color = Color3.fromRGB(50,50,65) s.Thickness = 1 s.Parent = win end

	local hdr = Instance.new('Frame')
	hdr.Size = UDim2.new(1, 0, 0, IS_MOB and 36 or 28)
	hdr.BackgroundColor3 = Color3.fromRGB(26, 26, 32)
	hdr.BorderSizePixel = 0
	hdr.Parent = win
	do local c = Instance.new('UICorner') c.CornerRadius = UDim.new(0,8) c.Parent = hdr end
	do local f = Instance.new('Frame') f.Size = UDim2.new(1,0,0.5,0) f.Position = UDim2.new(0,0,0.5,0) f.BackgroundColor3 = Color3.fromRGB(26,26,32) f.BorderSizePixel=0 f.Parent=hdr end

	local title = Instance.new('TextLabel')
	title.Size = UDim2.new(1, -80, 1, 0)
	title.Position = UDim2.new(0, 10, 0, 0)
	title.BackgroundTransparency = 1
	title.Text = 'Console Output'
	title.Font = Enum.Font.GothamBold
	title.TextSize = IS_MOB and 13 or 11
	title.TextColor3 = Color3.fromRGB(200, 200, 210)
	title.TextXAlignment = Enum.TextXAlignment.Left
	title.Parent = hdr

	local clr_btn = Instance.new('TextButton')
	clr_btn.Size = UDim2.new(0, IS_MOB and 44 or 36, 0, IS_MOB and 26 or 20)
	clr_btn.Position = UDim2.new(1, IS_MOB and -92 or -78, 0.5, IS_MOB and -13 or -10)
	clr_btn.BackgroundColor3 = Color3.fromRGB(60, 60, 75)
	clr_btn.Text = 'Clear'
	clr_btn.Font = Enum.Font.GothamBold
	clr_btn.TextSize = IS_MOB and 11 or 9
	clr_btn.TextColor3 = Color3.fromRGB(180, 180, 200)
	clr_btn.BorderSizePixel = 0
	clr_btn.Parent = hdr
	do local c = Instance.new('UICorner') c.CornerRadius = UDim.new(0,4) c.Parent = clr_btn end

	local close_btn = Instance.new('TextButton')
	close_btn.Size = UDim2.new(0, IS_MOB and 36 or 28, 0, IS_MOB and 26 or 20)
	close_btn.Position = UDim2.new(1, IS_MOB and -42 or -34, 0.5, IS_MOB and -13 or -10)
	close_btn.BackgroundColor3 = Color3.fromRGB(180, 50, 50)
	close_btn.Text = 'X'
	close_btn.Font = Enum.Font.GothamBold
	close_btn.TextSize = IS_MOB and 12 or 10
	close_btn.TextColor3 = Color3.fromRGB(240, 240, 240)
	close_btn.BorderSizePixel = 0
	close_btn.Parent = hdr
	do local c = Instance.new('UICorner') c.CornerRadius = UDim.new(0,4) c.Parent = close_btn end
	close_btn.MouseButton1Click:Connect(function() gui.Enabled = false end)

	local INPUT_H = IS_MOB and 36 or 28
	local scroll = Instance.new('ScrollingFrame')
	scroll.Size = UDim2.new(1, 0, 0, H - (IS_MOB and 36 or 28) - INPUT_H - 4)
	scroll.Position = UDim2.new(0, 0, 0, IS_MOB and 36 or 28)
	scroll.BackgroundTransparency = 1
	scroll.BorderSizePixel = 0
	scroll.ScrollBarThickness = IS_MOB and 5 or 3
	scroll.ScrollBarImageColor3 = Color3.fromRGB(88, 101, 242)
	scroll.CanvasSize = UDim2.new(0, 0, 0, 0)
	scroll.AutomaticCanvasSize = Enum.AutomaticCanvasSize.Y
	scroll.Parent = win

	local list = Instance.new('UIListLayout')
	list.SortOrder = Enum.SortOrder.LayoutOrder
	list.Padding = UDim.new(0, 1)
	list.Parent = scroll

	local entry_count = 0
	local COLORS = {
		output  = Color3.fromRGB(200, 220, 255),
		warn    = Color3.fromRGB(255, 200, 80),
		error   = Color3.fromRGB(255, 100, 100),
		info    = Color3.fromRGB(120, 200, 140),
	}

	local function add_line(text, kind)
		entry_count = entry_count + 1
		local lbl = Instance.new('TextLabel')
		lbl.Size = UDim2.new(1, -8, 0, 0)
		lbl.AutomaticSize = Enum.AutomaticSize.Y
		lbl.Position = UDim2.new(0, 4, 0, 0)
		lbl.BackgroundTransparency = 1
		lbl.Text = '[' .. os.date('%H:%M:%S') .. '] ' .. tostring(text)
		lbl.Font = Enum.Font.Code
		lbl.TextSize = IS_MOB and 11 or 10
		lbl.TextColor3 = COLORS[kind] or COLORS.output
		lbl.TextXAlignment = Enum.TextXAlignment.Left
		lbl.TextWrapped = true
		lbl.LayoutOrder = entry_count
		lbl.Parent = scroll
		scroll.CanvasPosition = Vector2.new(0, 1e9)
		if entry_count > 300 then
			local children = scroll:GetChildren()
			for _, c in ipairs(children) do
				if c:IsA('TextLabel') and c.LayoutOrder < entry_count - 250 then c:Destroy() end
			end
		end
	end

	add_line('Console ready. Output from ;run will appear here.', 'info')
	add_line('Goosesploit v' .. stuff.ver, 'info')

	vstorage.add_line = add_line

	clr_btn.MouseButton1Click:Connect(function()
		for _, c in scroll:GetChildren() do if c:IsA('TextLabel') then c:Destroy() end end
		entry_count = 0
		add_line('Console cleared.', 'info')
	end)

	local input_bg = Instance.new('Frame')
	input_bg.Size = UDim2.new(1, -8, 0, INPUT_H)
	input_bg.Position = UDim2.new(0, 4, 1, -INPUT_H - 4)
	input_bg.BackgroundColor3 = Color3.fromRGB(24, 24, 30)
	input_bg.BorderSizePixel = 0
	input_bg.Parent = win
	do local c = Instance.new('UICorner') c.CornerRadius = UDim.new(0,5) c.Parent = input_bg end
	do local s = Instance.new('UIStroke') s.Color = Color3.fromRGB(60,60,80) s.Thickness=1 s.Parent=input_bg end

	local input = Instance.new('TextBox')
	input.Size = UDim2.new(1, -10, 1, 0)
	input.Position = UDim2.new(0, 5, 0, 0)
	input.BackgroundTransparency = 1
	input.PlaceholderText = '> run lua here...'
	input.PlaceholderColor3 = Color3.fromRGB(80, 80, 100)
	input.Text = ''
	input.Font = Enum.Font.Code
	input.TextSize = IS_MOB and 12 or 11
	input.TextColor3 = Color3.fromRGB(200, 220, 255)
	input.TextXAlignment = Enum.TextXAlignment.Left
	input.ClearTextOnFocus = false
	input.Parent = input_bg

	input.FocusLost:Connect(function(enter)
		if not enter or input.Text == '' then return end
		local code = input.Text
		input.Text = ''
		add_line('> ' .. code, 'info')
		local fn, err = loadstring(code)
		if not fn then
			add_line('Syntax: ' .. tostring(err), 'error')
			return
		end
		local ok, result = pcall(fn)
		if not ok then
			add_line('Error: ' .. tostring(result), 'error')
		elseif result ~= nil then
			add_line('=> ' .. tostring(result), 'output')
		else
			add_line('OK', 'output')
		end
	end)

	do
		local dragging, ds, sp = false, nil, nil
		hdr.InputBegan:Connect(function(inp)
			if inp.UserInputType == Enum.UserInputType.MouseButton1 or inp.UserInputType == Enum.UserInputType.Touch then
				dragging = true ds = inp.Position sp = win.Position
			end
		end)
		services.user_input_service.InputChanged:Connect(function(inp)
			if dragging and (inp.UserInputType == Enum.UserInputType.MouseMovement or inp.UserInputType == Enum.UserInputType.Touch) then
				local d = inp.Position - ds
				win.Position = UDim2.new(sp.X.Scale, sp.X.Offset+d.X, sp.Y.Scale, sp.Y.Offset+d.Y)
			end
		end)
		services.user_input_service.InputEnded:Connect(function(inp)
			if inp.UserInputType == Enum.UserInputType.MouseButton1 or inp.UserInputType == Enum.UserInputType.Touch then
				dragging = false
			end
		end)
	end

	notify('console', 'console opened — bottom right', 1)
end)

cmd_library.add({'printconsole', 'cprint', 'cp'}, 'prints a message to the console GUI', {
	{'message', 'string', '...'}
}, function(vstorage, ...)
	local msg = table.concat({...}, ' ')
	local vs = cmd_library.get_variable_storage('consolegui')
	if vs.add_line then
		vs.add_line(msg, 'output')
	end
	print('[cprint] ' .. msg)
	notify('console', msg:sub(1, 60), 1)
end)

cmd_library.add({'namechanger', 'fakename', 'setname'}, 'changes your display name locally', {
	{'name', 'string'}
}, function(vstorage, name)
	if not name then return notify('namechanger', 'provide a name', 2) end
	local player = services.players.LocalPlayer
	if hookmetamethod then
		if vstorage.hook_active then
			hook_lib.destroy_hook('namechanger')
		end
		hook_lib.create_hook('namechanger', {
			index = function(self, key)
				if self == player and key == 'DisplayName' then return name end
				if self == player and key == 'Name' then return name end
			end
		})
		vstorage.hook_active = true
	end
	local char = stuff.owner_char
	if char then
		local bb = char:FindFirstChildOfClass('BillboardGui')
			or char.Head and char.Head:FindFirstChildOfClass('BillboardGui')
		if bb then
			local lbl = bb:FindFirstChildOfClass('TextLabel')
			if lbl then lbl.Text = name end
		end
	end
	notify('namechanger', 'display name set to: ' .. name, 1)
end)

cmd_library.add({'resetname', 'clearfakename'}, 'clears fake name', {}, function()
	local vs = cmd_library.get_variable_storage('namechanger')
	if vs.hook_active then
		hook_lib.destroy_hook('namechanger')
		vs.hook_active = false
	end
	notify('namechanger', 'name reset', 1)
end)

cmd_library.add({'walkthrough', 'nowall', 'ghostwalk'}, 'toggle walkthrough — pass through all parts', {
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, et)
	if et and vstorage.enabled then cmd_library.execute('unwalkthrough') return end
	if vstorage.enabled then return notify('walkthrough', 'already enabled', 2) end
	vstorage.enabled = true
	vstorage.saved = {}
	local char = stuff.owner_char
	for _, part in char:GetDescendants() do
		if part:IsA('BasePart') then
			vstorage.saved[part] = {cc = part.CanCollide, mt = part.Material}
			pcall(function()
				stuff.rawrbxset(part, 'CanCollide', false)
			end)
		end
	end
	maid.add('walkthrough_added', char.DescendantAdded, function(part)
		if part:IsA('BasePart') then
			pcall(function() stuff.rawrbxset(part, 'CanCollide', false) end)
		end
	end, true)
	notify('walkthrough', 'walkthrough on', 1)
end)

cmd_library.add({'unwalkthrough', 'unnowall', 'unghostwalk'}, 'disables walkthrough', {}, function()
	local vs = cmd_library.get_variable_storage('walkthrough')
	if not vs.enabled then return notify('walkthrough', 'not active', 2) end
	vs.enabled = false
	maid.remove('walkthrough_added')
	local char = stuff.owner_char
	for part, data in pairs(vs.saved or {}) do
		pcall(function() stuff.rawrbxset(part, 'CanCollide', data.cc) end)
	end
	vs.saved = {}
	notify('walkthrough', 'walkthrough off', 1)
end)

