	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, et)
	if et and vstorage.enabled then cmd_library.execute('unantideath') return end
	if vstorage.enabled then return notify('antideath', 'already active', 2) end
	vstorage.enabled = true
	notify('antideath', 'anti-death on — you will respawn instantly', 1)
	maid.add('antideath', services.players.LocalPlayer.CharacterAdded, function(char)
		if not vstorage.enabled then return end
