cmd_library.add({'aimlock', 'lock', 'locktarget'}, 'locks camera aim to nearest player', {
	{'key',    'string'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, key, et)
	if et and vstorage.enabled then cmd_library.execute('unaimlock') return end
	if vstorage.enabled then return notify('aimlock', 'already active', 2) end
	vstorage.enabled = true
	vstorage.key_code = key and Enum.KeyCode[key:upper()] or Enum.KeyCode.Q
	notify('aimlock', 'aimlock on — hold ' .. (key or 'Q') .. ' to lock', 1)
	maid.add('aimlock', services.run_service.RenderStepped, function()
		if not vstorage.enabled then return end
		local uis = services.user_input_service
		if not uis:IsKeyDown(vstorage.key_code) then return end
		local cam = workspace.CurrentCamera
		local hrp = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
		if not hrp then return end
		local closest, closest_dist = nil, math.huge
		for _, plr in ipairs(services.players:GetPlayers()) do
			if plr ~= stuff.owner and plr.Character then
				local t_hrp = plr.Character:FindFirstChild('HumanoidRootPart')
				if t_hrp then
					local dist = (t_hrp.Position - hrp.Position).Magnitude
					if dist < closest_dist then
						closest = t_hrp
						closest_dist = dist
					end
				end
			end
		end
		if closest then
			cam.CFrame = CFrame.lookAt(cam.CFrame.Position, closest.Position)
		end
	end)
end)

