cmd_library.add({'wallhack', 'wh', 'seethru'}, 'makes all parts partially transparent so you can see through walls', {
	{'transparency', 'number'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, trans, et)
	if et and vstorage.enabled then cmd_library.execute('unwallhack') return end
	if vstorage.enabled then return notify('wallhack', 'already active', 2) end
	vstorage.enabled = true
	trans = math.clamp(trans or 0.7, 0, 0.98)
	vstorage.saved = {}
	for _, obj in workspace:GetDescendants() do
		if obj:IsA('BasePart') and obj.Transparency < trans then
			local plr = services.players:GetPlayerFromCharacter(obj.Parent)
				or services.players:GetPlayerFromCharacter(obj.Parent and obj.Parent.Parent)
			if not plr then
				vstorage.saved[obj] = obj.Transparency
				pcall(function() stuff.rawrbxset(obj, 'Transparency', trans) end)
			end
		end
	end
	maid.add('wallhack_add', workspace.DescendantAdded, function(obj)
		if not vstorage.enabled then return end
		if obj:IsA('BasePart') and obj.Transparency < trans then
			local plr = services.players:GetPlayerFromCharacter(obj.Parent)
			if not plr then
				vstorage.saved[obj] = obj.Transparency
				pcall(function() stuff.rawrbxset(obj, 'Transparency', trans) end)
			end
		end
	end, true)
	notify('wallhack', 'wallhack on at ' .. trans .. ' transparency', 1)
end)

