}, function(vstorage, text, color_name)
	if not text then return notify('nametag', 'provide tag text', 2) end
	local char = stuff.owner_char
	local head = char and char:FindFirstChild('Head')
	if not head then return notify('nametag', 'no head', 2) end
	if vstorage.bb then pcall(function() vstorage.bb:Destroy() end) end

	local col_map = {
		red=Color3.fromRGB(255,80,80), blue=Color3.fromRGB(80,150,255),
		green=Color3.fromRGB(80,220,120), yellow=Color3.fromRGB(255,220,60),
		white=Color3.fromRGB(255,255,255), purple=Color3.fromRGB(180,80,255),
		orange=Color3.fromRGB(255,150,60), cyan=Color3.fromRGB(60,220,220),
	}
	local col = (color_name and col_map[color_name:lower()]) or Color3.fromRGB(255,255,255)

	local bb = Instance.new('BillboardGui')
	bb.Size = UDim2.new(0, 160, 0, 40)
	bb.StudsOffset = Vector3.new(0, 3, 0)
	bb.AlwaysOnTop = true
	bb.Parent = head
	vstorage.bb = bb

	local lbl = Instance.new('TextLabel')
	lbl.Size = UDim2.new(1, 0, 1, 0)
	lbl.BackgroundTransparency = 1
	lbl.Text = text
	lbl.Font = Enum.Font.GothamBold
