cmd_library.add({'getscripts', 'listscripts', 'scripts'}, 'lists all LocalScripts and Scripts loaded in the game', {
	{'filter', 'string'}
}, function(vstorage, filter)
	local found = {}
	for _, obj in game:GetDescendants() do
		if (obj:IsA('LocalScript') or obj:IsA('Script') or obj:IsA('ModuleScript')) then
			local path = obj:GetFullName()
			if not filter or path:lower():find(filter:lower(), 1, true) then
				table.insert(found, obj.ClassName:sub(1,2) .. ':' .. path)
			end
		end
	end
	table.sort(found)
	if #found == 0 then return notify('scripts', 'no scripts found', 2) end
	notify('scripts', #found .. ' scripts — printed to F9', 4)
	for _, s in ipairs(found) do print('[scripts] ' .. s) end
end)

cmd_library.add({'decompile', 'decomp', 'getsource'}, 'attempts to decompile a script by name', {
	{'name', 'string'}
}, function(vstorage, name)
	if not name then return notify('decompile', 'provide a script name', 2) end
	local found = nil
	for _, obj in game:GetDescendants() do
		if (obj:IsA('LocalScript') or obj:IsA('Script') or obj:IsA('ModuleScript'))
			and obj.Name:lower() == name:lower() then
			found = obj
			break
		end
	end
	if not found then return notify('decompile', 'script "' .. name .. '" not found', 2) end
	local src = decompile and decompile(found) or found.Source
	if src and src ~= '' then
		pcall(setclipboard, src)
		notify('decompile', 'source copied for: ' .. found:GetFullName(), 1)
		print('[decompile] ' .. found:GetFullName())
		print(src:sub(1, 500))
	else
		notify('decompile', 'source empty or decompile unavailable', 2)
	end
end)

cmd_library.add({'getmodules', 'modules', 'listmodules'}, 'lists all loaded ModuleScripts', {}, function()
	local mods = getloadedmodules and getloadedmodules() or {}
	if #mods == 0 then
		notify('modules', 'no loaded modules / getloadedmodules unavailable', 2)
		return
	end
	notify('modules', #mods .. ' modules — printed to F9', 4)
	for _, m in ipairs(mods) do
		pcall(function() print('[module] ' .. m:GetFullName()) end)
	end
end)

cmd_library.add({'copyremote', 'copyrpath'}, 'copies the full path of a remote by name to clipboard', {
	{'name', 'string'}
}, function(vstorage, name)
	if not name then return notify('copyremote', 'provide a name', 2) end
	local paths = {}
	for _, obj in game:GetDescendants() do
		if (obj:IsA('RemoteEvent') or obj:IsA('RemoteFunction'))
			and obj.Name:lower():find(name:lower(), 1, true) then
			table.insert(paths, obj:GetFullName())
		end
	end
	if #paths == 0 then return notify('copyremote', 'no remote matching "' .. name .. '"', 2) end
	pcall(setclipboard, table.concat(paths, '\n'))
	notify('copyremote', 'copied ' .. #paths .. ' path(s)', 1)
end)

