cmd_library.add({'orbit', 'orbitplayer', 'circleround'}, 'orbits around a player', {
	{'player',   'player'},
	{'radius',   'number'},
	{'speed',    'number'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, targets, radius, speed, et)
	if et and vstorage.enabled then cmd_library.execute('unorbit') return end
	if vstorage.enabled then cmd_library.execute('unorbit') end
	if not targets or #targets == 0 then return notify('orbit', 'player not found', 2) end
	vstorage.enabled = true
	vstorage.target  = targets[1]
	radius = radius or 10
	speed  = speed  or 1
	vstorage.angle  = 0
	notify('orbit', 'orbiting ' .. targets[1].Name, 1)
	maid.add('orbit', services.run_service.Heartbeat, function(dt)
		if not vstorage.enabled then return end
		local t = vstorage.target
		if not t or not t.Character then return end
		local tc = t.Character:FindFirstChild('HumanoidRootPart')
		if not tc then return end
		vstorage.angle = (vstorage.angle + dt * speed) % (math.pi * 2)
		local offset = Vector3.new(
			math.cos(vstorage.angle) * radius,
			0,
			math.sin(vstorage.angle) * radius
		)
		stuff.owner_char:PivotTo(CFrame.new(tc.Position + offset, tc.Position))
	end)
end)

cmd_library.add({'unorbit', 'stoporbit'}, 'stops orbiting', {}, function()
	local vs = cmd_library.get_variable_storage('orbit')
	vs.enabled = false
	maid.remove('orbit')
	notify('orbit', 'orbit stopped', 1)
end)

cmd_library.add({'follow', 'followplayer', 'stalk'}, 'follows a player at a distance', {
	{'player',   'player'},
	{'distance', 'number'},
	{'enable_toggling', 'boolean', 'hidden'}
}, function(vstorage, targets, dist, et)
	if et and vstorage.enabled then cmd_library.execute('unfollow') return end
	if vstorage.enabled then cmd_library.execute('unfollow') end
	if not targets or #targets == 0 then return notify('follow', 'player not found', 2) end
	vstorage.enabled = true
	vstorage.target  = targets[1]
	dist = dist or 5
	notify('follow', 'following ' .. targets[1].Name, 1)
	maid.add('follow', services.run_service.Heartbeat, function()
		if not vstorage.enabled then return end
		local t = vstorage.target
		if not t or not t.Character then return end
		local tc = t.Character:FindFirstChild('HumanoidRootPart')
		local sc = stuff.owner_char and stuff.owner_char:FindFirstChild('HumanoidRootPart')
		if not (tc and sc) then return end
		local current_dist = (tc.Position - sc.Position).Magnitude
		if current_dist > dist + 2 then
			local dir = (tc.Position - sc.Position).Unit
			stuff.owner_char:PivotTo(CFrame.new(tc.Position - dir * dist))
		end
	end)
end)

