local function getPlayer(list,speaker)
	if list == nil then return {speaker.Name} end
	local found = {}
	for i,v in pairs(game:GetService("Players"):GetChildren()) do
		if string.sub(string.lower(v.Name),1,#name) == string.lower(name) then
