cmd_library.register_plugin('iy_legacy', {
    version = '9.5.3',
    author = 'Infinite Yield / Goosesploit',
    description = 'Legacy Infinite Yield commands ported to Goosesploit'
})

local function addcmd(name, desc, alias, func)

    local names = {name}
    if alias then
        for _, a in ipairs(alias) do
            if a ~= '' then table.insert(names, a) end
        end
    end

    cmd_library.add_plugin_command('iy_legacy', names, desc, {{'args','string','optional'}},
        function(vstorage, raw_args)
            local speaker = services.players.LocalPlayer

            local args = {}
            if raw_args then
                for part in tostring(raw_args):gmatch('%S+') do
                    table.insert(args, part)
                end
            end
            local ok, err = pcall(func, args, speaker)
            if not ok then
                notify('iy-legacy', 'Command error: ' .. tostring(err), 3)
            end
        end
    )
end


