-- =====================================================================
-- SIRIUS INFINITE YIELD COMMANDS BRIDGE
-- 377 additional commands ported from Sirius Infinite Yield
-- These commands use :commandname syntax just like all other commands
-- =====================================================================

do -- IY bridge scope
-- IY helper variables (local to this scope)
local iyflyspeed = 1
local vehicleflyspeed = 1
local floatName
local CFloop
local Floating
local Noclipping
local Clip = true
local QEfly = true
local FLYING = false
local flyKeyDown, flyKeyUp

-- IY helper functions
local function randomString()
    local length = math.random(10,20)
    local array = {}
    for i = 1, length do array[i] = string.char(math.random(32, 126)) end
    return table.concat(array)
end
floatName = randomString()

local function isNumber(str)
    return tonumber(str) ~= nil or str == 'inf'
end

local function getRoot(char)
    return char:FindFirstChild('HumanoidRootPart') or char:FindFirstChild('Torso') or char:FindFirstChild('UpperTorso')
end

local function FindInTable(tbl, val)
    for _,v in pairs(tbl or {}) do
        if tostring(v):lower() == tostring(val):lower() then return true end
    end
end

local function tools(plr)
    if plr:FindFirstChildOfClass("Backpack"):FindFirstChildOfClass('Tool') or plr.Character:FindFirstChildOfClass('Tool') then
        return true
    end
end

local function r15(plr)
    if plr.Character:FindFirstChildOfClass('Humanoid').RigType == Enum.HumanoidRigType.R15 then
        return true
    end
end

local IYMouse = services.players.LocalPlayer:GetMouse()

local function NOFLY()
    FLYING = false
    if flyKeyDown then flyKeyDown:Disconnect() end
    if flyKeyUp then flyKeyUp:Disconnect() end
    if services.players.LocalPlayer.Character then
        local hum = services.players.LocalPlayer.Character:FindFirstChildOfClass('Humanoid')
        if hum then hum.PlatformStand = false end
    end
    pcall(function() workspace.CurrentCamera.CameraType = Enum.CameraType.Custom end)
end

local function sFLY(vfly)
    repeat wait() until services.players.LocalPlayer and services.players.LocalPlayer.Character and getRoot(services.players.LocalPlayer.Character) and services.players.LocalPlayer.Character:FindFirstChildOfClass("Humanoid")
    repeat wait() until IYMouse
    local T = getRoot(services.players.LocalPlayer.Character)
    local CONTROL = {F=0,B=0,L=0,R=0,Q=0,E=0}
    local lCONTROL = {F=0,B=0,L=0,R=0,Q=0,E=0}
    local SPEED = 0
    local function FLY()
        FLYING = true
        local BG = Instance.new('BodyGyro', T)
        local BV = Instance.new('BodyVelocity', T)
        BG.P = 9e4
        BG.maxTorque = Vector3.new(9e9,9e9,9e9)
        BG.cframe = T.CFrame
        BV.velocity = Vector3.new(0,0,0)
        BV.maxForce = Vector3.new(9e9,9e9,9e9)
        task.spawn(function()
            repeat wait()
                if not vfly then
                    local hum = services.players.LocalPlayer.Character:FindFirstChildOfClass('Humanoid')
                    if hum then hum.PlatformStand = true end
                end
                if CONTROL.L+CONTROL.R ~= 0 or CONTROL.F+CONTROL.B ~= 0 or CONTROL.Q+CONTROL.E ~= 0 then
                    SPEED = 50
                elseif SPEED ~= 0 then
                    SPEED = 0
                end
                if (CONTROL.L+CONTROL.R)~=0 or (CONTROL.F+CONTROL.B)~=0 or (CONTROL.Q+CONTROL.E)~=0 then
                    BV.velocity = ((workspace.CurrentCamera.CoordinateFrame.lookVector*(CONTROL.F+CONTROL.B))+((workspace.CurrentCamera.CoordinateFrame*CFrame.new(CONTROL.L+CONTROL.R,(CONTROL.F+CONTROL.B+CONTROL.Q+CONTROL.E)*0.2,0).p)-workspace.CurrentCamera.CoordinateFrame.p))*SPEED
                    lCONTROL = {F=CONTROL.F,B=CONTROL.B,L=CONTROL.L,R=CONTROL.R,Q=CONTROL.Q,E=CONTROL.E}
                elseif (CONTROL.L+CONTROL.R)==0 and (CONTROL.F+CONTROL.B)==0 and (CONTROL.Q+CONTROL.E)==0 and SPEED~=0 then
                    BV.velocity = ((workspace.CurrentCamera.CoordinateFrame.lookVector*(lCONTROL.F+lCONTROL.B))+((workspace.CurrentCamera.CoordinateFrame*CFrame.new(lCONTROL.L+lCONTROL.R,(lCONTROL.F+lCONTROL.B+lCONTROL.Q+lCONTROL.E)*0.2,0).p)-workspace.CurrentCamera.CoordinateFrame.p))*SPEED
                else
                    BV.velocity = Vector3.new(0,0,0)
                end
                BG.cframe = workspace.CurrentCamera.CoordinateFrame
            until not FLYING
            CONTROL={F=0,B=0,L=0,R=0,Q=0,E=0}
            lCONTROL={F=0,B=0,L=0,R=0,Q=0,E=0}
            SPEED=0
            BG:Destroy()
            BV:Destroy()
            local hum = services.players.LocalPlayer.Character:FindFirstChildOfClass('Humanoid')
            if hum then hum.PlatformStand = false end
        end)
    end
    flyKeyDown = IYMouse.KeyDown:Connect(function(KEY)
        KEY = KEY:lower()
        if KEY=='w' then CONTROL.F=(vfly and vehicleflyspeed or iyflyspeed)
        elseif KEY=='s' then CONTROL.B=-(vfly and vehicleflyspeed or iyflyspeed)
        elseif KEY=='a' then CONTROL.L=-(vfly and vehicleflyspeed or iyflyspeed)
        elseif KEY=='d' then CONTROL.R=(vfly and vehicleflyspeed or iyflyspeed)
        elseif QEfly and KEY=='e' then CONTROL.Q=(vfly and vehicleflyspeed or iyflyspeed)*2
        elseif QEfly and KEY=='q' then CONTROL.E=-(vfly and vehicleflyspeed or iyflyspeed)*2
        end
    end)
    flyKeyUp = IYMouse.KeyUp:Connect(function(KEY)
        KEY = KEY:lower()
        if KEY=='w' then CONTROL.F=0
        elseif KEY=='s' then CONTROL.B=0
        elseif KEY=='a' then CONTROL.L=0
        elseif KEY=='d' then CONTROL.R=0
        elseif KEY=='e' then CONTROL.Q=0
        elseif KEY=='q' then CONTROL.E=0
        end
    end)
    FLY()
end

-- Bridge: map IY's addcmd to cmd_library.add
local function addcmd(name, aliases, func)
    local names = {name}
    for _, a in ipairs(aliases or {}) do
        table.insert(names, a)
    end
    cmd_library.add(names, '[IY] ' .. name, {{'args','string','...'}}, function(vstorage, ...)
        local args = {...}
        pcall(func, args, services.players.LocalPlayer)
    end)
end

